    def test_unreadable_blast_radius_refuses_never_reads_as_empty(self):
        broker, client, _ = make_broker()
        client.fail_linked = "HTTP 500: linked-with exploded"
        out = broker.dispatch("plan_cancel", {"name": "SI-9"})
