class TestJournalEntryInvoiceDiscountingReach(unittest.TestCase):
    """The Invoice Discounting reach RETROFIT (pre-verification fan, 2026-07-21): Journal Entry
    Account's ``reference_type`` is a Select whose options include "Invoice Discounting" — a
    cross-document channel invisible to Link-field scans, so the founding JE landing never
    disclosed it. ``update_invoice_discounting`` (journal_entry.py:459-501) THROWS on a stage
    mismatch and, when it proceeds, db_sets the Invoice Discounting's status AND recomputes/
    db_sets every linked Sales Invoice's status (invoice_discounting.py:101-108). Pinned here:
    fires on plan_submit + plan_cancel + per-node in plan_cascade_cancel, direction-specific
    wording, distinct reference_names counted, silent on ID-free drafts (the founding fixtures)."""

    def _reach_rows(self):
        return [{"account": "Short Term Loan", "debit": 0.0, "credit": 100.0,
                 "reference_type": "Invoice Discounting", "reference_name": "ID-0001"},
                {"account": "Bank", "debit": 100.0, "credit": 0.0,
                 "reference_type": "Invoice Discounting", "reference_name": "ID-0002"},
                {"account": "Bank", "debit": 50.0, "credit": 50.0,
                 "reference_type": "Invoice Discounting", "reference_name": "ID-0001"}]

    def test_submit_flag_fires_with_forward_walk_and_distinct_names(self):
        broker, client, _ = make_broker()
        client.docs["JE-1"]["accounts"] = self._reach_rows()
        out = broker.dispatch("plan_submit", {"name": "JE-1", "pacioli_doctype": "Journal Entry"})
        self.assertTrue(out["ok"], out)
        reach = [f for f in out["risk_flags"] if "reference_type Select" in f]
        self.assertEqual(len(reach), 1, out["risk_flags"])
        self.assertIn("2 Invoice Discounting document(s) (ID-0001, ID-0002)", reach[0])
        self.assertIn("Sanctioned->Disbursed", reach[0])
        self.assertIn("THROWS", reach[0])
        self.assertIn("EVERY linked Sales Invoice", reach[0])

    def test_cancel_flag_fires_with_reversed_walk(self):
        broker, client, _ = make_broker()
        client.docs["JE-9"]["accounts"] = self._reach_rows()
        out = broker.dispatch("plan_cancel", {"name": "JE-9", "pacioli_doctype": "Journal Entry"})
        self.assertTrue(out["ok"], out)
        reach = [f for f in out["risk_flags"] if "reference_type Select" in f]
        self.assertEqual(len(reach), 1, out["risk_flags"])
        self.assertIn("Disbursed->Sanctioned", reach[0])
        self.assertIn("Settled->Disbursed", reach[0])

    def test_cascade_per_node_flag_prefixed_with_docname(self):
        cc = CascadeClient({})
        cc.docs["T"]["accounts"] = self._reach_rows()
        broker, client, _ = make_broker(client=cc)
        plan = broker.dispatch("plan_cascade_cancel",
                               {"name": "T", "pacioli_doctype": "Journal Entry"})
        self.assertTrue(plan["ok"], plan)
        self.assertTrue(any(f.startswith("T: ") and "reference_type Select" in f
                            and "Disbursed->Sanctioned" in f for f in plan["risk_flags"]),
                        plan["risk_flags"])

    def test_silent_on_id_free_drafts_both_directions(self):
        broker, client, _ = make_broker()
        out = broker.dispatch("plan_submit", {"name": "JE-1", "pacioli_doctype": "Journal Entry"})
        self.assertTrue(out["ok"], out)
        self.assertFalse(any("Invoice Discounting" in f and "reference_type" in f
                             for f in out["risk_flags"]), out["risk_flags"])
        out = broker.dispatch("plan_cancel", {"name": "JE-9", "pacioli_doctype": "Journal Entry"})
        self.assertTrue(out["ok"], out)
        self.assertFalse(any("Invoice Discounting" in f and "reference_type" in f
                             for f in out["risk_flags"]), out["risk_flags"])

    def test_rows_missing_reference_name_do_not_crash_or_flag(self):
        broker, client, _ = make_broker()
        client.docs["JE-1"]["accounts"] = [
            {"account": "Cash", "debit": 100.0, "credit": 0.0,
             "reference_type": "Invoice Discounting"},  # no reference_name — malformed row
            {"account": "Sales", "debit": 0.0, "credit": 100.0}]
        out = broker.dispatch("plan_submit", {"name": "JE-1", "pacioli_doctype": "Journal Entry"})
        self.assertTrue(out["ok"], out)
        self.assertFalse(any("reference_type Select" in f for f in out["risk_flags"]),
                         out["risk_flags"])


