class TestSalesOrderDateField(unittest.TestCase):
    """The ONE genuinely new branch Sales Order forces (erpnext.py's SUPPORTED_DOCTYPES docstring
    has the full source-cited finding): Sales Order carries no `posting_date` field at all, only
    `transaction_date` — confirmed absent from sales_order.json. SO-1/SO-9 (FakeClient, above)
    deliberately carry NO "posting_date" key, so a regression to the old hardcoded
    doc.get("posting_date") read would silently resolve to "" rather than crash — these tests
    assert the ACTUAL date value threaded through to the closed-books check, which fails loudly on
    a regression."""

    def test_plan_submit_reads_transaction_date_not_posting_date(self):
        broker, client, _ = make_broker()
        out = broker.dispatch("plan_submit", {"name": "SO-1", "pacioli_doctype": "Sales Order"})
        self.assertTrue(out["ok"], out)
        self.assertEqual(out["posting_date"], "2026-07-01")  # SO-1's transaction_date value
        self.assertEqual(client.lock_calls[-1], ("Example Corp", SALES_ORDER, "2026-07-01"))

    def test_plan_cancel_reads_transaction_date_not_posting_date(self):
        broker, client, _ = make_broker()
        out = broker.dispatch("plan_cancel", {"name": "SO-9", "pacioli_doctype": "Sales Order"})
        self.assertTrue(out["ok"], out)
        self.assertEqual(out["posting_date"], "2026-06-15")  # SO-9's transaction_date value
        self.assertEqual(client.lock_calls[-1], ("Example Corp", SALES_ORDER, "2026-06-15"))

    def test_governed_submit_reads_transaction_date_at_execute_time(self):
        broker, client, stores = make_broker()
        plan = broker.dispatch("plan_submit", {"name": "SO-1", "pacioli_doctype": "Sales Order"})
        token = "so-date-field-token"
        stores("prod").mint_marker(token, plan["plan_id"], expires_at=2_000.0)
        calls_before = len(client.lock_calls)
        out = broker.dispatch("submit_sales_order",
                              {"name": "SO-1", "plan_id": plan["plan_id"], "marker": token})
        self.assertTrue(out["ok"], out)
        self.assertGreater(len(client.lock_calls), calls_before)
        self.assertEqual(client.lock_calls[-1], ("Example Corp", SALES_ORDER, "2026-07-01"))

    def test_cascade_node_meta_reads_transaction_date_for_a_sales_order_node(self):
        # _cascade_node_meta is the shared closure both plan_cascade_cancel and cascade_cancel's
        # re-discovery use — cascade.py itself is untouched (fully doctype-blind, see tools.py's
        # module docstring), so this closure is the whole fix for a Sales Order cascade node.
        broker, client, _ = make_broker()
        node_meta = broker._cascade_node_meta(client)
        meta = node_meta(SALES_ORDER, "SO-1")
        self.assertEqual(meta["posting_date"], "2026-07-01")

    def test_other_doctypes_still_read_posting_date_unaffected(self):
        # Back-compat pin: the date-field lookup must be a no-op for every doctype that already
        # had a real posting_date field.
        broker, client, _ = make_broker()
        out = broker.dispatch("plan_submit", {"name": "SI-1"})
        self.assertTrue(out["ok"], out)
        self.assertEqual(out["posting_date"], "2026-07-01")
        self.assertEqual(client.lock_calls[-1], ("Example Corp", SALES_INVOICE, "2026-07-01"))


