class TestDeliveryNoteLedgerDisclosure(unittest.TestCase):
    """Delivery Note is the first STOCK-PRIMARY supported doctype: unlike Sales Order/Purchase
    Order/Material Request (whose `make_gl_entries` is a conditional no-op because they carry no
    Stock Ledger Entry rows of their own), Delivery Note's own ERPNext preview RPC
    (`get_accounting_ledger_preview`, stock_controller.py:2109-2110) explicitly seeds an in-memory
    `update_stock_ledger()` for Delivery Note (named alongside Purchase Receipt/Stock Entry) BEFORE
    calling `make_gl_entries()` — so `projected_gl` is genuinely populated on a real bench, not
    near-always-empty like the three pre-accounting doctypes.

    The FakeClient's own `ledger_preview` stub is a FIXED, doctype-blind double (always one
    non-empty Debtors row, regardless of doctype — confirmed by reading FakeClient.ledger_preview
    above) — no test anywhere in this suite asserts an EMPTY projected_gl for Sales Order/Purchase
    Order/Material Request either, so this doctype breaks no prior assumption. What this class adds
    is the POSITIVE pin: a real test naming Delivery Note's plan_submit as surfacing non-empty
    projected_gl, on the record, so a future change that silently special-cased Delivery Note into
    an empty preview (mirroring the real no-GL doctypes) would fail loudly here."""

    def test_plan_submit_surfaces_non_empty_projected_gl(self):
        broker, client, _ = make_broker()
        out = broker.dispatch("plan_submit", {"name": "DN-1", "pacioli_doctype": "Delivery Note"})
        self.assertTrue(out["ok"], out)
        self.assertTrue(out["projected_gl"], "Delivery Note's projected_gl must not be empty — "
                                             "it is a stock-primary doctype whose own ledger "
                                             "preview seeds real Stock Ledger Entry rows before "
                                             "asking for GL (stock_controller.py:2109-2110)")
        self.assertEqual(out["projected_gl"][0]["account"], "Debtors")

    def test_plan_cancel_surfaces_the_live_gl_reversal(self):
        broker, client, _ = make_broker()
        out = broker.dispatch("plan_cancel", {"name": "DN-9", "pacioli_doctype": "Delivery Note"})
        self.assertTrue(out["ok"], out)
        self.assertTrue(out["projected_reversal"])
        self.assertIn((DELIVERY_NOTE, "DN-9"), client.gl_calls)


class TestDeliveryNoteReturnDisclosure(unittest.TestCase):
    """The real code fix landing alongside this doctype: `_return_risk_flags` previously assumed
    every `is_return` doctype also carries `update_outstanding_for_self` (true for Sales/Purchase
    Invoice, the only two doctypes with `is_return` before this landing). Delivery Note carries
    `is_return`/`return_against` but NO `update_outstanding_for_self` field at all (confirmed
    absent from delivery_note.json) and never posts to a receivable/payable account of its own —
    the fixture (DN-1/DN-9, above) deliberately carries no such key, modeling the real bench shape
    directly. Before the fix, a return Delivery Note with return_against set would have gotten the
    SI-shaped "the original's outstanding is reduced by this reversal" — a false claim for a
    doctype with no outstanding concept at all."""

    def test_return_against_gets_the_stock_only_sentence_not_the_ar_claim(self):
        broker, client, _ = make_broker()
        client.docs["DN-1"]["is_return"] = 1
        client.docs["DN-1"]["return_against"] = "DN-9"
        out = broker.dispatch("plan_submit", {"name": "DN-1", "pacioli_doctype": "Delivery Note"})
        self.assertTrue(out["ok"], out)
        flag = next(f for f in out["risk_flags"] if "DN-9" in f and "STOCK reversal" in f)
        self.assertIn("Delivery Note", flag)
        self.assertIn("no receivable/payable balance", flag)
        self.assertIn("SEPARATE Sales Invoice", flag)
        # The false claim must NEVER appear alongside the correct one.
        self.assertFalse(any("outstanding is reduced" in f for f in out["risk_flags"]))
        self.assertFalse(any("does NOT settle" in f for f in out["risk_flags"]))

    def test_free_standing_return_still_gets_the_shared_flags(self):
        # The parts of _return_risk_flags that DON'T depend on update_outstanding_for_self (the
        # top-line RETURN flag, the FREE-STANDING flag, the mixed-sign flag) are unchanged for
        # Delivery Note — only the return_against-conditional settlement branch was doctype-aware.
        broker, client, _ = make_broker()
        client.docs["DN-1"]["is_return"] = 1  # no return_against set
        out = broker.dispatch("plan_submit", {"name": "DN-1", "pacioli_doctype": "Delivery Note"})
        self.assertTrue(out["ok"], out)
        self.assertTrue(any("RETURN" in f and "credit note" in f for f in out["risk_flags"]))
        self.assertTrue(any(f.startswith("FREE-STANDING credit note") for f in out["risk_flags"]))

    def test_plan_cancel_carries_the_same_stock_only_sentence(self):
        broker, client, _ = make_broker()
        client.docs["DN-9"]["is_return"] = 1
        client.docs["DN-9"]["return_against"] = "DN-1"
        out = broker.dispatch("plan_cancel", {"name": "DN-9", "pacioli_doctype": "Delivery Note"})
        self.assertTrue(out["ok"], out)
        self.assertTrue(any("STOCK reversal" in f and "DN-1" in f for f in out["risk_flags"]))
        self.assertFalse(any("outstanding is reduced" in f for f in out["risk_flags"]))

    def test_sales_invoice_return_disclosure_is_unchanged_by_the_fix(self):
        # Regression pin: SI (which DOES carry update_outstanding_for_self) must still get its
        # original two-way wording — the fix only ADDS a third branch, it must not touch the other
        # two. Mirrors TestReturnDisclosure's own SI cases, re-asserted here because this class
        # exists specifically to touch _return_risk_flags's shared code.
        broker, client, _ = make_broker()
        client.docs["SI-1"]["is_return"] = 1
        client.docs["SI-1"]["return_against"] = "SI-9"
        client.docs["SI-1"]["update_outstanding_for_self"] = 0
        out = broker.dispatch("plan_submit", {"name": "SI-1"})
        self.assertTrue(out["ok"], out)
        self.assertTrue(any("posts against SI-9" in f and "outstanding is reduced" in f
                            for f in out["risk_flags"]))
        self.assertFalse(any("STOCK reversal" in f for f in out["risk_flags"]))


