class TestPurchaseReceiptReturnDisclosure(unittest.TestCase):
    """No further code change lands here — `_return_risk_flags`'s field-presence branch was already
    fixed by Delivery Note's landing (2026-07-21, same day). Purchase Receipt carries
    `is_return`/`return_against` but NO `update_outstanding_for_self` field at all (confirmed
    absent from purchase_receipt.json's full 148-field list) and never posts to a
    receivable/payable account of its own — the fixture (PR-1/PR-9, above) deliberately carries no
    such key, modeling the real bench shape directly. This class exercises the EXISTING branch
    live for a second doctype, proving the fix generalizes rather than merely happening to fit
    Delivery Note's own shape by coincidence."""

    def test_return_against_gets_the_stock_only_sentence_not_the_ar_claim(self):
        broker, client, _ = make_broker()
        client.docs["PR-1"]["is_return"] = 1
        client.docs["PR-1"]["return_against"] = "PR-9"
        out = broker.dispatch("plan_submit",
                              {"name": "PR-1", "pacioli_doctype": "Purchase Receipt"})
        self.assertTrue(out["ok"], out)
        flag = next(f for f in out["risk_flags"] if "PR-9" in f and "STOCK reversal" in f)
        self.assertIn("Purchase Receipt", flag)
        self.assertIn("no receivable/payable balance", flag)
        self.assertIn("SEPARATE Sales Invoice", flag)
        # The false claim must NEVER appear alongside the correct one.
        self.assertFalse(any("outstanding is reduced" in f for f in out["risk_flags"]))
        self.assertFalse(any("does NOT settle" in f for f in out["risk_flags"]))

    def test_free_standing_return_still_gets_the_shared_flags(self):
        # The parts of _return_risk_flags that DON'T depend on update_outstanding_for_self (the
        # top-line RETURN flag, the FREE-STANDING flag, the mixed-sign flag) are unchanged for
        # Purchase Receipt — only the return_against-conditional settlement branch is doctype-aware.
        broker, client, _ = make_broker()
        client.docs["PR-1"]["is_return"] = 1  # no return_against set
        out = broker.dispatch("plan_submit",
                              {"name": "PR-1", "pacioli_doctype": "Purchase Receipt"})
        self.assertTrue(out["ok"], out)
        self.assertTrue(any("RETURN" in f and "credit note" in f for f in out["risk_flags"]))
        self.assertTrue(any(f.startswith("FREE-STANDING credit note") for f in out["risk_flags"]))

    def test_plan_cancel_carries_the_same_stock_only_sentence(self):
        broker, client, _ = make_broker()
        client.docs["PR-9"]["is_return"] = 1
        client.docs["PR-9"]["return_against"] = "PR-1"
        out = broker.dispatch("plan_cancel",
                              {"name": "PR-9", "pacioli_doctype": "Purchase Receipt"})
        self.assertTrue(out["ok"], out)
        self.assertTrue(any("STOCK reversal" in f and "PR-1" in f for f in out["risk_flags"]))
        self.assertFalse(any("outstanding is reduced" in f for f in out["risk_flags"]))

    def test_purchase_invoice_return_disclosure_is_unchanged_by_the_fix(self):
        # Regression pin: PI (which DOES carry update_outstanding_for_self) must still get its
        # original two-way wording — the fix only ADDS a third branch, it must not touch the other
        # two. Mirrors TestDeliveryNoteReturnDisclosure's own SI regression case, re-asserted here
        # with PI (the natural sibling on the purchase side) because this class exists specifically
        # to touch _return_risk_flags's shared code a second time.
        broker, client, _ = make_broker()
        client.docs["PI-1"]["is_return"] = 1
        client.docs["PI-1"]["return_against"] = "PI-9"
        client.docs["PI-1"]["update_outstanding_for_self"] = 0
        out = broker.dispatch("plan_submit",
                              {"name": "PI-1", "pacioli_doctype": "Purchase Invoice"})
        self.assertTrue(out["ok"], out)
        self.assertTrue(any("posts against PI-9" in f and "outstanding is reduced" in f
                            for f in out["risk_flags"]))
        self.assertFalse(any("STOCK reversal" in f for f in out["risk_flags"]))


