class TestStockEntryGovernedRoundTrip(unittest.TestCase):
    """One full plan->submit, plan->cancel, and amend round trip, plus the cascade node_meta
    closure — the mechanical-wiring proof for the tenth doctype, matching the shape of
    TestPurchaseReceiptGovernedRoundTrip above. Per-branch coverage already pinned elsewhere (the
    list-tier branch: TestStockEntryListTier above) is not re-derived here."""

    def test_plan_submit_records_the_doctype_and_reads_posting_date(self):
        broker, client, stores = make_broker()
        out = broker.dispatch("plan_submit", {"name": "SE-1", "pacioli_doctype": "Stock Entry"})
        self.assertTrue(out["ok"], out)
        self.assertEqual(out["doctype"], "Stock Entry")
        self.assertEqual(out["posting_date"], "2026-07-01")  # SE-1's posting_date value
        self.assertEqual(client.lock_calls[-1], ("Example Corp", STOCK_ENTRY, "2026-07-01"))
        stored = stores("prod").get_plan(out["plan_id"])
        self.assertEqual(stored.doctype, "Stock Entry")
        self.assertEqual(stored.docname, "SE-1")

    def test_full_governed_submit_flow(self):
        broker, client, stores = make_broker()
        plan = broker.dispatch("plan_submit", {"name": "SE-1", "pacioli_doctype": "Stock Entry"})
        token = "se-raw-token"
        stores("prod").mint_marker(token, plan["plan_id"], expires_at=2_000.0)
        out = broker.dispatch("submit_stock_entry",
                              {"name": "SE-1", "plan_id": plan["plan_id"], "marker": token})
        self.assertTrue(out["ok"], out)
        self.assertEqual(out["result"]["docstatus"], 1)
        self.assertEqual(out["result"]["doctype"], "Stock Entry")
        self.assertEqual(client.submitted, ["SE-1"])
        store = stores("prod")
        self.assertEqual(store.marker_state(token), "consumed")
        self.assertEqual(store.orphans(), [])

    def test_plan_submit_refuses_non_draft(self):
        broker, client, _ = make_broker()
        client.docs["SE-1"]["docstatus"] = 1
        out = broker.dispatch("plan_submit", {"name": "SE-1", "pacioli_doctype": "Stock Entry"})
        self.assertFalse(out["ok"])
        self.assertIn("draft", out["reason"].lower())

    def test_full_governed_cancel_flow(self):
        broker, client, stores = make_broker()
        plan = broker.dispatch("plan_cancel", {"name": "SE-9", "pacioli_doctype": "Stock Entry"})
        self.assertTrue(plan["ok"], plan)
        self.assertEqual(plan["doctype"], "Stock Entry")
        self.assertIn((STOCK_ENTRY, "SE-9"), client.gl_calls)
        token = "se-cancel-token"
