        # Same shared closure every prior doctype's own cascade test pins — cascade.py itself is
        # untouched (fully doctype-blind), so this closure is the whole cascade proof for a Stock
        # Entry node too.
        broker, client, _ = make_broker()
        node_meta = broker._cascade_node_meta(client)
