class TestStockEntryReturnDisclosure(unittest.TestCase):
    """No code change lands here — Stock Entry carries `is_return` (a real field: Check, hidden,
    read_only, default 0) but CONFIRMED NO `return_against` field at all (absent from
    stock_entry.json's full field list, unlike DN/PR which carry the field but may leave it
    unset). Traced to its one real producer (`work_order.py`'s `make_stock_return_entry`):
    `is_return=1` marks excess raw material being returned from a Work Order back to store on an
    ordinary "Material Transfer for Manufacture" entry — a direction flag, not a credit-note
    concept. Because `return_against` can never be present on a real Stock Entry document,
    `_return_risk_flags`'s `if doc.get("return_against")` branch (the settlement wording, keyed on
    `update_outstanding_for_self` presence) structurally can never fire for this doctype — this
    class pins that only the top-line RETURN flag and the FREE-STANDING flag ever appear, proving
    the shared helper degrades safely for a doctype whose is_return shape it was never designed
    around, rather than merely assuming so."""

    def test_is_return_gets_only_the_top_line_and_free_standing_flags(self):
        broker, client, _ = make_broker()
        client.docs["SE-1"]["is_return"] = 1  # no return_against key at all — matches real schema
        out = broker.dispatch("plan_submit", {"name": "SE-1", "pacioli_doctype": "Stock Entry"})
        self.assertTrue(out["ok"], out)
        self.assertTrue(any("RETURN" in f and "credit note" in f for f in out["risk_flags"]))
        self.assertTrue(any(f.startswith("FREE-STANDING credit note") for f in out["risk_flags"]))
        # The settlement/STOCK-reversal wording is gated on return_against, which this doctype's
        # schema never carries — it must never appear for a Stock Entry.
        self.assertFalse(any("STOCK reversal" in f for f in out["risk_flags"]))
        self.assertFalse(any("outstanding is reduced" in f for f in out["risk_flags"]))
        self.assertFalse(any("does NOT settle" in f for f in out["risk_flags"]))

    def test_plan_cancel_carries_the_same_free_standing_shape(self):
        broker, client, _ = make_broker()
        client.docs["SE-9"]["is_return"] = 1
        out = broker.dispatch("plan_cancel", {"name": "SE-9", "pacioli_doctype": "Stock Entry"})
        self.assertTrue(out["ok"], out)
        self.assertTrue(any(f.startswith("FREE-STANDING credit note") for f in out["risk_flags"]))
        self.assertFalse(any("STOCK reversal" in f for f in out["risk_flags"]))

    def test_no_is_return_key_is_a_silent_no_op(self):
        # SE-9 (above) carries no "is_return" key at all by default — the ordinary case for the
        # vast majority of Stock Entry purposes. _return_risk_flags must return no flags at all.
        broker, client, _ = make_broker()
        out = broker.dispatch("plan_submit", {"name": "SE-1", "pacioli_doctype": "Stock Entry"})
        self.assertTrue(out["ok"], out)
        self.assertFalse(any("RETURN" in f and "credit note" in f for f in out["risk_flags"]))
        self.assertFalse(any(f.startswith("FREE-STANDING credit note") for f in out["risk_flags"]))


