        # The decision itself, asserted directly: party_field=None is a deliberate value for
        # Quotation (Material Request's shape, NOT a forced single Dynamic Link splice), not an
        # accident of a missing dict key or an empty-string placeholder that could silently splice
        # a literal "" into the field list.
        cfg = SUPPORTED_DOCTYPES[QUOTATION]
        self.assertIn("party_field", cfg)
        self.assertIsNone(cfg["party_field"])


