class TestPOSInvoiceLedgerDisclosure(unittest.TestCase):
    """THE central finding of this landing: unlike every other doctype landed so far (including
    the three stock-primary doctypes, whose own preview genuinely reflects what a real submit will
    post), POS Invoice's plan_submit projected_gl is a SIMULATION of a posting that will NEVER
    happen. ERPNext's own ledger-preview RPC calls doc.make_gl_entries() directly, bypassing
    on_submit entirely — POSInvoice never overrides that method (only on_submit), so the call
    resolves to the INHERITED SalesInvoice.make_gl_entries and genuinely computes real-shaped GL
    rows. But POSInvoice.on_submit() itself never calls make_gl_entries() (confirmed absent from
    the whole 1119-line pos_invoice.py) — a real submit posts nothing.

    The FakeClient's own ledger_preview stub is a FIXED, doctype-blind double (always one
    non-empty Debtors row) — so, mechanically, this doctype's plan_submit ALSO comes back with a
    non-empty projected_gl, matching what a real bench's preview RPC would also do (for the
    doctype-inheritance reason above, not by coincidence). What makes this class different from
    TestDeliveryNoteLedgerDisclosure's own shape: the positive pin here is NOT "non-empty
    projected_gl proves a real posting" (that claim would be FALSE for POS Invoice) — it is that
    the new deferral risk flag fires ALONGSIDE the non-empty preview, naming the divergence
    plainly rather than letting it pass silently."""

    def test_plan_submit_surfaces_non_empty_projected_gl_and_the_deferral_warning(self):
        broker, client, _ = make_broker()
        out = broker.dispatch("plan_submit", {"name": "POSI-1", "pacioli_doctype": "POS Invoice"})
        self.assertTrue(out["ok"], out)
        self.assertTrue(out["projected_gl"], "POS Invoice's projected_gl is non-empty because "
                                             "ERPNext's preview RPC calls make_gl_entries() "
                                             "directly, inherited unmodified from Sales Invoice")
        self.assertTrue(
            any("PROJECTED GL ABOVE WILL NOT POST" in f for f in out["risk_flags"]),
            "the non-empty preview above must NEVER go out without the deferral warning — a real "
            "POS Invoice submit posts no GL of its own at all")
        flag = next(f for f in out["risk_flags"] if "PROJECTED GL ABOVE WILL NOT POST" in f)
        self.assertIn("POS Closing Entry", flag)

    def test_plan_cancel_needs_no_deferral_flag_the_real_read_is_already_honest(self):
        # plan_cancel's projected_reversal comes from get_gl_entries — a REAL bench read, not a
        # simulation — which correctly comes back empty for POS Invoice (nothing was ever posted
        # to reverse); the pre-existing generic "no live GL rows found" flag already says so.
        broker, client, _ = make_broker()
        client.gl_rows = []
        out = broker.dispatch("plan_cancel", {"name": "POSI-9", "pacioli_doctype": "POS Invoice"})
        self.assertTrue(out["ok"], out)
        self.assertEqual(out["projected_reversal"], [])
        self.assertTrue(any("no live GL rows found" in f for f in out["risk_flags"]))
        self.assertFalse(any("PROJECTED GL ABOVE WILL NOT POST" in f for f in out["risk_flags"]))

    def test_update_stock_flag_names_the_deferral_not_a_false_posting_claim(self):
        # _update_stock_risk_flags gains a POS-Invoice-gated branch: the doctype-agnostic wording
        # ("the stock ledger is written alongside the GL on submit") would be FALSE for POS
        # Invoice — update_stock_ledger() is never called anywhere in pos_invoice.py either.
        broker, client, _ = make_broker()
        client.docs["POSI-1"]["update_stock"] = 1
        client.docs["POSI-1"]["items"] = [{"item_code": "Widget", "qty": 2, "uom": "Nos",
                                           "warehouse": "Stores - EC"}]
        out = broker.dispatch("plan_submit", {"name": "POSI-1", "pacioli_doctype": "POS Invoice"})
        self.assertTrue(out["ok"], out)
        flag = next(f for f in out["risk_flags"] if "update_stock is set" in f)
        self.assertIn("does not write a Stock Ledger Entry", flag)
        self.assertIn("POS Closing Entry", flag)
        self.assertFalse(any("stock ledger is written alongside the GL" in f
                             for f in out["risk_flags"]))

    def test_cancel_update_stock_flag_also_names_the_deferral(self):
        broker, client, _ = make_broker()
        client.docs["POSI-9"]["update_stock"] = 1
        client.docs["POSI-9"]["items"] = [{"item_code": "Widget", "qty": 2, "uom": "Nos",
                                           "warehouse": "Stores - EC"}]
        out = broker.dispatch("plan_cancel", {"name": "POSI-9", "pacioli_doctype": "POS Invoice"})
        self.assertTrue(out["ok"], out)
        flag = next(f for f in out["risk_flags"] if "update_stock was set" in f)
        self.assertIn("reverses no Stock Ledger Entry of its own", flag)


class TestPOSInvoiceReturnDisclosure(unittest.TestCase):
    """_return_risk_flags gains a FOURTH shape, keyed explicitly on doctype == POS_INVOICE (a
    VERIFIED behavioral fact, not inferred from field presence — POS Invoice DOES carry debit_to,
    so it would wrongly route into the Delivery-Note/Purchase-Receipt "stock-only" branch if keyed
    on field presence alone). update_outstanding_for_self is confirmed absent from
    pos_invoice.json's full 185-field list (the POSI-1/POSI-9 fixtures above carry no such key,
    modeling the real bench shape directly) — but unlike DN/PR, POS Invoice DOES carry debit_to,
    and (per the central finding) posts no GL of ANY kind on its own submit regardless — so neither
    the SI/PI wording (settles / does not settle) nor the DN/PR wording (STOCK reversal only) is
    accurate; a fourth sentence names the real behavior."""

    def test_return_against_gets_the_pos_invoice_sentence_not_the_stock_only_or_ar_claim(self):
        broker, client, _ = make_broker()
        client.docs["POSI-1"]["is_return"] = 1
        client.docs["POSI-1"]["return_against"] = "POSI-9"
        out = broker.dispatch("plan_submit", {"name": "POSI-1", "pacioli_doctype": "POS Invoice"})
        self.assertTrue(out["ok"], out)
        flag = next(f for f in out["risk_flags"] if "POSI-9" in f and "return_against" in f)
        self.assertIn("posts NO GL entries of its own on ANY submit", flag)
        self.assertIn("POS Closing Entry", flag)
        # Neither the DN/PR "STOCK reversal only" wording nor the SI/PI settlement wording may
        # appear alongside the POS-Invoice-specific sentence.
        self.assertFalse(any("STOCK reversal only" in f for f in out["risk_flags"]))
        self.assertFalse(any("does NOT settle" in f for f in out["risk_flags"]))
        self.assertFalse(any("outstanding is reduced" in f for f in out["risk_flags"]))

    def test_free_standing_return_still_gets_the_shared_flags(self):
        # The parts of _return_risk_flags that DON'T depend on update_outstanding_for_self (the
        # top-line RETURN flag, the FREE-STANDING flag, the mixed-sign flag) are unchanged for POS
        # Invoice — only the return_against-conditional settlement branch was doctype-aware.
        broker, client, _ = make_broker()
        client.docs["POSI-1"]["is_return"] = 1  # no return_against set
        out = broker.dispatch("plan_submit", {"name": "POSI-1", "pacioli_doctype": "POS Invoice"})
        self.assertTrue(out["ok"], out)
        self.assertTrue(any("RETURN" in f and "credit note" in f for f in out["risk_flags"]))
        self.assertTrue(any(f.startswith("FREE-STANDING credit note") for f in out["risk_flags"]))

    def test_plan_cancel_carries_the_same_pos_invoice_sentence(self):
        broker, client, _ = make_broker()
        client.docs["POSI-9"]["is_return"] = 1
        client.docs["POSI-9"]["return_against"] = "POSI-1"
        out = broker.dispatch("plan_cancel", {"name": "POSI-9", "pacioli_doctype": "POS Invoice"})
        self.assertTrue(out["ok"], out)
        self.assertTrue(any("posts NO GL entries of its own on ANY submit" in f and "POSI-1" in f
                            for f in out["risk_flags"]))
        self.assertFalse(any("STOCK reversal only" in f for f in out["risk_flags"]))

    def test_delivery_note_return_disclosure_is_unchanged_by_the_fourth_branch(self):
        # Regression pin: Delivery Note (which has NO debit_to at all) must still get its own
        # "STOCK reversal only" wording — the new POS-Invoice branch only fires for
        # doctype == POS_INVOICE, it must not swallow DN/PR's existing branch.
        broker, client, _ = make_broker()
        client.docs["DN-1"]["is_return"] = 1
        client.docs["DN-1"]["return_against"] = "DN-9"
        out = broker.dispatch("plan_submit", {"name": "DN-1", "pacioli_doctype": "Delivery Note"})
        self.assertTrue(out["ok"], out)
        self.assertTrue(any("STOCK reversal only" in f for f in out["risk_flags"]))
        self.assertFalse(any("posts NO GL entries of its own on ANY submit" in f
                             for f in out["risk_flags"]))


class TestPOSInvoiceConsolidationCancelDisclosure(unittest.TestCase):
    """The dossier's own §5-§7 claim that neither a submitted consolidated Sales Invoice nor a
    submitted POS Closing Entry/POS Invoice Merge Log is visible to this broker's
    get_submitted_linked_docs blast-radius disclosure — traced directly against frappe's own
    linked_with.py (version-16) in erpnext.py's module docstring, this is WRONG: both are
    discoverable (Sales Invoice Item.pos_invoice is a real Link; POS Invoice Reference.pos_invoice
    is a real, required Link on a child table frappe's own child-table-to-parent resolution walks
    up to its embedding submittable parent). This broker's PRE-EXISTING generic refusal (any
    non-empty get_submitted_linked_docs result denies the plan) already covers both — these tests
    pin that mechanical fact via the FakeClient's own scriptable client.linked, the same shape
    TestPlanCancel.test_plan_refuses_when_submitted_docs_link_to_it already uses for Sales
    Invoice. (The real-bench claim itself — that frappe's own mechanism resolves these edges — is
    a source-verification claim, not something a doctype-blind fake can independently prove; it is
    cited to source in erpnext.py's own module docstring.)"""

    def test_plan_cancel_refuses_when_the_consolidated_sales_invoice_is_submitted(self):
        broker, client, _ = make_broker()
        client.docs["POSI-9"]["consolidated_invoice"] = "SI-CONS-1"
        client.linked = [{"doctype": "Sales Invoice", "name": "SI-CONS-1"}]
        out = broker.dispatch("plan_cancel", {"name": "POSI-9", "pacioli_doctype": "POS Invoice"})
        self.assertFalse(out["ok"])
        self.assertIn("Sales Invoice SI-CONS-1", out["reason"])
        self.assertIn("cascade", out["reason"])

    def test_plan_cancel_refuses_when_a_submitted_pos_closing_entry_references_it(self):
        # The POS Invoice Reference child-table edge — resolved up to its embedding parent
        # (POS Closing Entry) by frappe's own get_referencing_documents parenttype-groupby logic,
        # not something this broker builds itself; the fake just plays the role of "what the real
        # bench's RPC would report" for this edge.
        broker, client, _ = make_broker()
        client.linked = [{"doctype": "POS Closing Entry", "name": "PCE-1"}]
        out = broker.dispatch("plan_cancel", {"name": "POSI-9", "pacioli_doctype": "POS Invoice"})
        self.assertFalse(out["ok"])
        self.assertIn("POS Closing Entry PCE-1", out["reason"])
        self.assertIn("cascade", out["reason"])

    def test_plan_cancel_refuses_when_a_submitted_pos_invoice_merge_log_references_it(self):
        broker, client, _ = make_broker()
        client.linked = [{"doctype": "POS Invoice Merge Log", "name": "PIML-1"}]
        out = broker.dispatch("plan_cancel", {"name": "POSI-9", "pacioli_doctype": "POS Invoice"})
        self.assertFalse(out["ok"])
        self.assertIn("POS Invoice Merge Log PIML-1", out["reason"])

    def test_plan_cancel_clean_when_no_linked_docs(self):
        # Control: a POS Invoice with no consolidated_invoice and nothing in the blast radius
        # cancels cleanly, the same generic shape every other supported doctype already gets.
        broker, client, _ = make_broker()
        out = broker.dispatch("plan_cancel", {"name": "POSI-9", "pacioli_doctype": "POS Invoice"})
        self.assertTrue(out["ok"], out)


