class TestDunningGovernedRoundTrip(unittest.TestCase):
    """One full plan->submit, plan->cancel, and amend round trip, plus the cascade node_meta
    closure — the mechanical-wiring proof for the fourteenth doctype, matching the shape of
    TestPOSInvoiceGovernedRoundTrip above. The semantic divergence (the native preview being
    uncallable, not merely non-posting) lives in TestDunningLedgerPreviewSkipped below, not here —
    this class proves the generated mechanical wiring holds end to end."""

    def test_plan_submit_records_the_doctype_and_reads_posting_date(self):
        broker, client, stores = make_broker()
        out = broker.dispatch("plan_submit", {"name": "DUNN-1", "pacioli_doctype": "Dunning"})
        self.assertTrue(out["ok"], out)
        self.assertEqual(out["doctype"], "Dunning")
        self.assertEqual(out["posting_date"], "2026-07-01")  # DUNN-1's posting_date value
        self.assertEqual(client.lock_calls[-1], ("Example Corp", DUNNING, "2026-07-01"))
        stored = stores("prod").get_plan(out["plan_id"])
        self.assertEqual(stored.doctype, "Dunning")
        self.assertEqual(stored.docname, "DUNN-1")

    def test_full_governed_submit_flow(self):
        broker, client, stores = make_broker()
        plan = broker.dispatch("plan_submit", {"name": "DUNN-1", "pacioli_doctype": "Dunning"})
        token = "dunn-raw-token"
        stores("prod").mint_marker(token, plan["plan_id"], expires_at=2_000.0)
        out = broker.dispatch("submit_dunning",
                              {"name": "DUNN-1", "plan_id": plan["plan_id"], "marker": token})
        self.assertTrue(out["ok"], out)
        self.assertEqual(out["result"]["docstatus"], 1)
        self.assertEqual(out["result"]["doctype"], "Dunning")
        self.assertEqual(client.submitted, ["DUNN-1"])
        store = stores("prod")
        self.assertEqual(store.marker_state(token), "consumed")
        self.assertEqual(store.orphans(), [])

    def test_plan_submit_refuses_non_draft(self):
        broker, client, _ = make_broker()
        client.docs["DUNN-1"]["docstatus"] = 1
        out = broker.dispatch("plan_submit", {"name": "DUNN-1", "pacioli_doctype": "Dunning"})
        self.assertFalse(out["ok"])
        self.assertIn("draft", out["reason"].lower())

    def test_full_governed_cancel_flow(self):
        broker, client, stores = make_broker()
        plan = broker.dispatch("plan_cancel", {"name": "DUNN-9", "pacioli_doctype": "Dunning"})
        self.assertTrue(plan["ok"], plan)
        self.assertEqual(plan["doctype"], "Dunning")
        self.assertIn((DUNNING, "DUNN-9"), client.gl_calls)
        token = "dunn-cancel-token"
        stores("prod").mint_marker(token, plan["plan_id"], expires_at=2_000.0)
        out = broker.dispatch("cancel_dunning",
                              {"name": "DUNN-9", "plan_id": plan["plan_id"], "marker": token})
        self.assertTrue(out["ok"], out)
        self.assertEqual(out["result"]["docstatus"], 2)
        self.assertEqual(client.cancelled, ["DUNN-9"])
        self.assertEqual(stores("prod").marker_state(token), "consumed")

    def test_amend_creates_the_draft_with_receipts_and_no_marker(self):
        broker, client, stores = make_broker()
        client.docs["DUNN-9"]["docstatus"] = 2
        out = broker.dispatch("amend_dunning", {"name": "DUNN-9"})
        self.assertTrue(out["ok"], out)
        self.assertEqual(out["result"]["name"], "DUNN-9-1")
        self.assertEqual(out["result"]["docstatus"], 0)
        self.assertEqual(out["result"]["doctype"], "Dunning")
        self.assertEqual(client.amended, ["DUNN-9"])
        store = stores("prod")
        receipts = store.receipts()
        self.assertEqual([r.kind for r in receipts], ["intent", "outcome"])
        self.assertEqual(receipts[0].body["doctype"], "Dunning")
        self.assertEqual(store.orphans(), [])

    def test_amend_refuses_an_uncancelled_source(self):
        broker, client, _ = make_broker()
        out = broker.dispatch("amend_dunning", {"name": "DUNN-1"})  # a draft
        self.assertFalse(out["ok"])
        self.assertIn("cancelled", out["reason"])

    def test_cascade_node_meta_reads_posting_date_for_a_dunning_node(self):
        # Same shared closure every prior doctype's own cascade test pins — cascade.py itself is
        # untouched (fully doctype-blind), and _cascade_node_meta uses get_gl_entries (a safe read,
        # never ledger_preview) for every doctype including Dunning, so no special-casing is needed
        # here even though plan_submit's own preview call IS special-cased below.
        broker, client, _ = make_broker()
        node_meta = broker._cascade_node_meta(client)
        meta = node_meta(DUNNING, "DUNN-1")
        self.assertEqual(meta["posting_date"], "2026-07-01")


class TestDunningLedgerPreviewSkipped(unittest.TestCase):
    """THE central finding of this landing, and a DIFFERENT shape from every prior "posts no GL"
    doctype: Dunning's own plan_submit does not merely disclose a misleading preview (POS Invoice's
    shape) — it never CALLS the native preview at all, because Dunning has no make_gl_entries
    method anywhere in its class hierarchy and the real RPC would raise AttributeError on a live
    bench if invoked. The FakeClient's own ledger_preview stub is a FIXED, doctype-blind double
    (always one non-empty Debtors row) — so the only way to prove the broker genuinely skips the
    call, rather than merely discarding its result, is to intercept the call itself, the same
    technique test_refused_before_the_native_preview_is_even_called
    (TestJournalEntryPlanSubmitAndSubmit) already uses for Journal Entry's reserved-voucher-type
    belt."""

    def test_plan_submit_never_calls_the_native_preview(self):
        broker, client, _ = make_broker()
        preview_calls = []
        real_preview = client.ledger_preview
        client.ledger_preview = lambda **kw: preview_calls.append(kw) or real_preview(**kw)
        out = broker.dispatch("plan_submit", {"name": "DUNN-1", "pacioli_doctype": "Dunning"})
        self.assertTrue(out["ok"], out)
        self.assertEqual(preview_calls, [])

    def test_plan_submit_projected_gl_is_empty_by_construction_with_the_disclosure_flag(self):
        broker, client, _ = make_broker()
        out = broker.dispatch("plan_submit", {"name": "DUNN-1", "pacioli_doctype": "Dunning"})
        self.assertTrue(out["ok"], out)
        self.assertEqual(out["projected_gl"], [])
        self.assertTrue(
            any("PROJECTED GL IS EMPTY BECAUSE THE PREVIEW COULD NOT RUN" in f
                for f in out["risk_flags"]),
            "an empty projected_gl for Dunning must carry the WHY — this is not a preview that "
            "ran and found nothing (SO/PO/MR's shape), it is a preview this broker never called")
        flag = next(f for f in out["risk_flags"]
                   if "PROJECTED GL IS EMPTY BECAUSE THE PREVIEW COULD NOT RUN" in f)
        self.assertIn("make_gl_entries", flag)
        self.assertIn("Payment Entry", flag)
        # The POS Invoice flag (a different shape — non-empty preview, misleading) must never
        # appear alongside Dunning's own flag.
        self.assertFalse(any("PROJECTED GL ABOVE WILL NOT POST" in f for f in out["risk_flags"]))

    def test_plan_cancel_needs_no_new_flag_the_real_read_is_already_honest(self):
        # plan_cancel's projected_reversal comes from get_gl_entries — a REAL, safe bench read
        # (never make_gl_entries), which correctly comes back empty for Dunning (no GL row was
        # ever written under this voucher_type); the pre-existing generic "no live GL rows found"
        # flag already says so, same shape as POS Invoice's own plan_cancel.
        broker, client, _ = make_broker()
        client.gl_rows = []
        out = broker.dispatch("plan_cancel", {"name": "DUNN-9", "pacioli_doctype": "Dunning"})
        self.assertTrue(out["ok"], out)
        self.assertEqual(out["projected_reversal"], [])
        self.assertTrue(any("no live GL rows found" in f for f in out["risk_flags"]))
        self.assertFalse(any("PROJECTED GL IS EMPTY BECAUSE THE PREVIEW COULD NOT RUN" in f
                             for f in out["risk_flags"]))

    def test_other_doctypes_plan_submit_is_unaffected_by_the_dunning_branch(self):
        # Regression pin: the doctype-gated skip in _tool_plan_submit must not swallow the native
        # preview call for any other doctype — Sales Invoice still gets a real (fake-client-stub)
        # non-empty projected_gl with no Dunning-shaped flag attached.
        broker, client, _ = make_broker()
        out = broker.dispatch("plan_submit", {"name": "SI-1"})
        self.assertTrue(out["ok"], out)
        self.assertTrue(out["projected_gl"])
        self.assertFalse(any("PREVIEW COULD NOT RUN" in f for f in out["risk_flags"]))


