class TestStockReconciliationLedgerPreviewIncomplete(unittest.TestCase):
    """THE central finding of this landing, and a shape distinct from every prior doctype: Stock
    Reconciliation's native preview is callable and raises nothing (it IS a StockController
    subclass, unlike Dunning), but its empty projected_gl is a FALSE NEGATIVE — a real submit
    ALWAYS writes Stock Ledger Entry rows and, when perpetual inventory is enabled, real GL Entry
    rows too, none of which the preview can show (it is absent from ERPNext's own SLE-seeding
    whitelist). Unlike Dunning's landing, the native preview call is NOT skipped — it is callable
    and harmless here — only its result is annotated."""

    def test_plan_submit_still_calls_the_native_preview(self):
        # Distinguishes this shape from Dunning's: the call is NOT skipped, since it never raises
        # for Stock Reconciliation (unlike Dunning's AttributeError risk).
        broker, client, _ = make_broker()
        preview_calls = []
        real_preview = client.ledger_preview
        client.ledger_preview = lambda **kw: preview_calls.append(kw) or real_preview(**kw)
        out = broker.dispatch("plan_submit",
                              {"name": "SR-1", "pacioli_doctype": "Stock Reconciliation"})
        self.assertTrue(out["ok"], out)
        self.assertEqual(len(preview_calls), 1)
        self.assertEqual(preview_calls[0]["doctype"], STOCK_RECONCILIATION)

    def test_plan_submit_carries_the_incomplete_disclosure_flag(self):
        broker, client, _ = make_broker()
        out = broker.dispatch("plan_submit",
                              {"name": "SR-1", "pacioli_doctype": "Stock Reconciliation"})
        self.assertTrue(out["ok"], out)
        self.assertTrue(
            any("PROJECTED GL ABOVE MAY BE INCOMPLETE" in f for f in out["risk_flags"]),
            "a Stock Reconciliation plan_submit must carry the WHY the preview may undersell a "
            "real submit's postings")
        flag = next(f for f in out["risk_flags"] if "PROJECTED GL ABOVE MAY BE INCOMPLETE" in f)
        self.assertIn("Stock Ledger Entry", flag)
        self.assertIn("perpetual inventory", flag)
        # The Dunning/POS Invoice flags (different shapes) must never appear alongside this one.
        self.assertFalse(any("PREVIEW COULD NOT RUN" in f for f in out["risk_flags"]))
        self.assertFalse(any("WILL NOT POST" in f for f in out["risk_flags"]))

    def test_plan_cancel_needs_no_new_flag_the_real_read_is_already_honest(self):
        # plan_cancel's projected_reversal comes from get_gl_entries — a REAL, actually-posted
        # bench read (never make_gl_entries), accurate for Stock Reconciliation exactly as for
        # every other doctype.
        broker, client, _ = make_broker()
        out = broker.dispatch("plan_cancel",
                              {"name": "SR-9", "pacioli_doctype": "Stock Reconciliation"})
        self.assertTrue(out["ok"], out)
        self.assertFalse(any("PROJECTED GL ABOVE MAY BE INCOMPLETE" in f
                             for f in out["risk_flags"]))

    def test_other_doctypes_plan_submit_is_unaffected_by_the_stock_reconciliation_branch(self):
        broker, client, _ = make_broker()
        out = broker.dispatch("plan_submit", {"name": "SI-1"})
        self.assertTrue(out["ok"], out)
        self.assertFalse(any("PROJECTED GL ABOVE MAY BE INCOMPLETE" in f
                             for f in out["risk_flags"]))


