class TestLandedCostVoucherGovernedRoundTrip(unittest.TestCase):
    """One full plan->submit, plan->cancel, and amend round trip, plus the cascade node_meta
    closure — the mechanical-wiring proof for the sixteenth doctype, matching the shape of
    TestDunningGovernedRoundTrip/TestStockReconciliationGovernedRoundTrip above. The semantic
    divergence (the native preview being uncallable AND describing the wrong document even if it
    weren't, plus the cancel-side revaluation disclosure) lives in
    TestLandedCostVoucherLedgerPreviewUnavailable/TestLandedCostVoucherCancelRevaluationDisclosure
    below, not here — this class proves the generated mechanical wiring holds end to end."""

    def test_plan_submit_records_the_doctype_and_reads_posting_date(self):
        broker, client, stores = make_broker()
        out = broker.dispatch("plan_submit",
                              {"name": "LCV-1", "pacioli_doctype": "Landed Cost Voucher"})
        self.assertTrue(out["ok"], out)
        self.assertEqual(out["doctype"], "Landed Cost Voucher")
        self.assertEqual(out["posting_date"], "2026-07-01")  # LCV-1's posting_date value
        self.assertEqual(client.lock_calls[-1],
                         ("Example Corp", LANDED_COST_VOUCHER, "2026-07-01"))
        stored = stores("prod").get_plan(out["plan_id"])
        self.assertEqual(stored.doctype, "Landed Cost Voucher")
        self.assertEqual(stored.docname, "LCV-1")

    def test_full_governed_submit_flow(self):
        broker, client, stores = make_broker()
        plan = broker.dispatch("plan_submit",
                               {"name": "LCV-1", "pacioli_doctype": "Landed Cost Voucher"})
        token = "lcv-raw-token"
        stores("prod").mint_marker(token, plan["plan_id"], expires_at=2_000.0)
        out = broker.dispatch("submit_landed_cost_voucher",
                              {"name": "LCV-1", "plan_id": plan["plan_id"], "marker": token})
        self.assertTrue(out["ok"], out)
        self.assertEqual(out["result"]["docstatus"], 1)
        self.assertEqual(out["result"]["doctype"], "Landed Cost Voucher")
        self.assertEqual(client.submitted, ["LCV-1"])
        store = stores("prod")
        self.assertEqual(store.marker_state(token), "consumed")
        self.assertEqual(store.orphans(), [])

    def test_plan_submit_refuses_non_draft(self):
        broker, client, _ = make_broker()
        client.docs["LCV-1"]["docstatus"] = 1
        out = broker.dispatch("plan_submit",
                              {"name": "LCV-1", "pacioli_doctype": "Landed Cost Voucher"})
        self.assertFalse(out["ok"])
        self.assertIn("draft", out["reason"].lower())

    def test_full_governed_cancel_flow(self):
        broker, client, stores = make_broker()
        plan = broker.dispatch("plan_cancel",
                               {"name": "LCV-9", "pacioli_doctype": "Landed Cost Voucher"})
        self.assertTrue(plan["ok"], plan)
        self.assertEqual(plan["doctype"], "Landed Cost Voucher")
        self.assertIn((LANDED_COST_VOUCHER, "LCV-9"), client.gl_calls)
        token = "lcv-cancel-token"
        stores("prod").mint_marker(token, plan["plan_id"], expires_at=2_000.0)
        out = broker.dispatch("cancel_landed_cost_voucher",
                              {"name": "LCV-9", "plan_id": plan["plan_id"], "marker": token})
        self.assertTrue(out["ok"], out)
        self.assertEqual(out["result"]["docstatus"], 2)
        self.assertEqual(client.cancelled, ["LCV-9"])
        self.assertEqual(stores("prod").marker_state(token), "consumed")

    def test_amend_creates_the_draft_with_receipts_and_no_marker(self):
        broker, client, stores = make_broker()
        client.docs["LCV-9"]["docstatus"] = 2
        out = broker.dispatch("amend_landed_cost_voucher", {"name": "LCV-9"})
        self.assertTrue(out["ok"], out)
        self.assertEqual(out["result"]["name"], "LCV-9-1")
        self.assertEqual(out["result"]["docstatus"], 0)
        self.assertEqual(out["result"]["doctype"], "Landed Cost Voucher")
        self.assertEqual(client.amended, ["LCV-9"])
        store = stores("prod")
        receipts = store.receipts()
        self.assertEqual([r.kind for r in receipts], ["intent", "outcome"])
        self.assertEqual(receipts[0].body["doctype"], "Landed Cost Voucher")
        self.assertEqual(store.orphans(), [])

    def test_amend_refuses_an_uncancelled_source(self):
        broker, client, _ = make_broker()
        out = broker.dispatch("amend_landed_cost_voucher", {"name": "LCV-1"})  # a draft
        self.assertFalse(out["ok"])
        self.assertIn("cancelled", out["reason"])

