# dossier's own hedge — TestRequestForQuotationLedgerPreviewHonestEmpty proves it rides the
# SO/PO/MR/SQ/Q "honest-empty" category (preview genuinely callable, never skipped), NOT the
# Dunning/Landed Cost Voucher "uncallable" one, despite request_for_quotation.md's own §4 reading
# ambiguously close to the latter on a surface pass.
# ============================================================================================

class TestRequestForQuotationLedgerPreviewHonestEmpty(unittest.TestCase):
    """THE central verification of this landing: RFQ's native ledger_preview RPC is genuinely
    CALLABLE (RequestforQuotation(BuyingController) shares BuyingController -> Subcontracting-
    Controller -> StockController with Purchase Order/Material Request/Supplier Quotation, so it
    inherits a real make_gl_entries — never AttributeErrors), so it is NOT added to tools.py's
    (DUNNING, LANDED_COST_VOUCHER) skip tuple. This distinguishes RFQ from Dunning/Landed Cost
    Voucher (preview skipped entirely) AND from Stock Reconciliation (preview called but flagged
    incomplete) — for RFQ the call happens and needs no annotation at all, the same "quiet, no
    new machinery" shape SO/PO/MR/SQ/Q's own landings already established."""

    def test_plan_submit_still_calls_the_native_preview(self):
        broker, client, _ = make_broker()
        preview_calls = []
        real_preview = client.ledger_preview
        client.ledger_preview = lambda **kw: preview_calls.append(kw) or real_preview(**kw)
        out = broker.dispatch("plan_submit",
                              {"name": "RFQ-1", "pacioli_doctype": "Request for Quotation"})
        self.assertTrue(out["ok"], out)
        self.assertEqual(len(preview_calls), 1)
        self.assertEqual(preview_calls[0]["doctype"], REQUEST_FOR_QUOTATION)

    def test_plan_submit_carries_none_of_the_other_doctypes_ledger_preview_flags(self):
        # None of the Dunning/POS Invoice/Stock Reconciliation/Landed Cost Voucher disclosure
        # flags belong on an RFQ plan — its own preview is genuinely, quietly honest.
        broker, client, _ = make_broker()
        out = broker.dispatch("plan_submit",
                              {"name": "RFQ-1", "pacioli_doctype": "Request for Quotation"})
        self.assertTrue(out["ok"], out)
        self.assertFalse(any("PREVIEW COULD NOT RUN" in f for f in out["risk_flags"]))
        self.assertFalse(any("WILL NOT POST" in f for f in out["risk_flags"]))
        self.assertFalse(any("PROJECTED GL ABOVE MAY BE INCOMPLETE" in f
                             for f in out["risk_flags"]))


class TestRequestForQuotationListTier(unittest.TestCase):
    """The ONE genuinely new branch RFQ forces (erpnext.py's SUPPORTED_DOCTYPES/_list_fields
    docstrings have the full source-cited finding): party_field=None combined with status present
    and grand_total absent is Material Request's own absence SHAPE, but not a reuse of that
    branch — Material Request's own substitute fields (material_request_type/per_ordered/
    per_received) do not exist on this doctype's schema, and RFQ has no natural analog to any of
    them, so this is the FIRST branch with no substitute/context column at all."""

