class TestJobCardLedgerPreviewSkipped(unittest.TestCase):
    """THE central finding of this landing, verified from the MRO rather than assumed: Job Card's
    own plan_submit does not merely disclose a misleading preview — it never CALLS the native
    preview at all, because JobCard(Document) has no make_gl_entries method anywhere in its class
    hierarchy and the real RPC would raise AttributeError on a live bench if invoked. The same
    "intercept the call itself" technique TestDunningLedgerPreviewSkipped/
    TestBlanketOrderLedgerPreviewSkipped already use, since the FakeClient's own ledger_preview stub
    is a fixed, doctype-blind double that would otherwise mask a regression."""

    def test_plan_submit_never_calls_the_native_preview(self):
        broker, client, _ = make_broker()
        preview_calls = []
        real_preview = client.ledger_preview
        client.ledger_preview = lambda **kw: preview_calls.append(kw) or real_preview(**kw)
        out = broker.dispatch("plan_submit", {"name": "JC-1", "pacioli_doctype": "Job Card"})
        self.assertTrue(out["ok"], out)
        self.assertEqual(preview_calls, [])

    def test_plan_submit_projected_gl_is_empty_by_construction_with_the_disclosure_flag(self):
        broker, client, _ = make_broker()
        out = broker.dispatch("plan_submit", {"name": "JC-1", "pacioli_doctype": "Job Card"})
        self.assertTrue(out["ok"], out)
        self.assertEqual(out["projected_gl"], [])
        self.assertTrue(
            any("PROJECTED GL IS EMPTY BECAUSE THE PREVIEW COULD NOT RUN" in f
                for f in out["risk_flags"]),
            "an empty projected_gl for Job Card must carry the WHY — this is not a preview that "
            "ran and found nothing (SO/PO/MR/SQ/Q/RFQ's shape), it is a preview this broker never "
            "called")
        flag = next(f for f in out["risk_flags"]
                   if "PROJECTED GL IS EMPTY BECAUSE THE PREVIEW COULD NOT RUN" in f)
        self.assertIn("make_gl_entries", flag)
        self.assertIn("Job Card", flag)
        # Neither the LCV dual-flag shape nor the Dunning/Blanket-Order-specific wording belongs
        # on a Job Card plan — its own flag names its own doctype, not a borrowed one.
        self.assertNotIn("Dunning", flag)
        self.assertNotIn("Blanket Order", flag)
        self.assertFalse(any("WRONG DOCUMENT" in f for f in out["risk_flags"]))

    def test_plan_cancel_needs_no_new_flag_the_real_read_is_already_honest(self):
        # plan_cancel's projected_reversal comes from get_gl_entries — a REAL, safe bench read
        # (never make_gl_entries), which correctly comes back empty for Job Card (no GL row was
        # ever written under this voucher_type, in either direction — its own on_cancel resets the
        # linked Work Order's operation quantities only, never a ledger row); the pre-existing
        # generic "no live GL rows found" flag already says so, the same shape Dunning's/Blanket
        # Order's own plan_cancel already established.
        broker, client, _ = make_broker()
        client.gl_rows = []
        out = broker.dispatch("plan_cancel", {"name": "JC-9", "pacioli_doctype": "Job Card"})
        self.assertTrue(out["ok"], out)
        self.assertEqual(out["projected_reversal"], [])
        self.assertTrue(any("no live GL rows found" in f for f in out["risk_flags"]))
        self.assertFalse(any("PROJECTED GL IS EMPTY BECAUSE THE PREVIEW COULD NOT RUN" in f
                             for f in out["risk_flags"]))

    def test_other_doctypes_plan_submit_is_unaffected_by_the_job_card_branch(self):
        # Regression pin: the doctype-gated skip in _tool_plan_submit must not swallow the native
        # preview call for any other doctype — Sales Invoice still gets a real (fake-client-stub)
        # non-empty projected_gl with no Job-Card-shaped flag attached.
        broker, client, _ = make_broker()
        out = broker.dispatch("plan_submit", {"name": "SI-1"})
        self.assertTrue(out["ok"], out)
        self.assertTrue(out["projected_gl"])
        self.assertFalse(any("PREVIEW COULD NOT RUN" in f for f in out["risk_flags"]))


