class TestStockRepostChannelFlag(unittest.TestCase):
    """The 2026-07-22 debt pass — THE CONFIRMED RETROACTIVE GAP the Asset Capitalization landing
    reported (commit 5f74f17): the four founding stock rows call the identical
    repost_future_sle_and_gle machinery and none disclosed it. Now they all do, both directions,
    with the source-verified directional asymmetry (cancel UNCONDITIONAL via the method's own
    docstatus==2 force; submit conditional on future SLEs)."""

    ROWS = ((STOCK_ENTRY, "SE-1", "SE-9", "stock_entry.py:566", "stock_entry.py:602"),
            (STOCK_RECONCILIATION, "SR-1", "SR-9",
             "stock_reconciliation.py:114", "stock_reconciliation.py:126"),
            (DELIVERY_NOTE, "DN-1", "DN-9", "delivery_note.py:479", "delivery_note.py:500"),
            (PURCHASE_RECEIPT, "PR-1", "PR-9", "purchase_receipt.py:396", "purchase_receipt.py:467"))

    def test_submit_plan_discloses_the_conditional_repost_channel(self):
        broker, client, _ = make_broker()
        for doctype, draft, _sub, submit_site, _csite in self.ROWS:
            with self.subTest(doctype=doctype):
                out = broker.dispatch("plan_submit",
                                      {"name": draft, "pacioli_doctype": doctype})
                self.assertTrue(out["ok"], out)
                flag = next((f for f in out["risk_flags"]
                             if "Repost Item Valuation" in f and submit_site in f), None)
                self.assertIsNotNone(flag, out["risk_flags"])
                self.assertIn("back-dated", flag)      # the conditional-arming clause
                self.assertNotIn("UNCONDITIONALLY", flag)

    def test_cancel_plan_discloses_the_unconditional_repost_channel(self):
        broker, client, _ = make_broker()
        for doctype, _draft, submitted, _ssite, cancel_site in self.ROWS:
            with self.subTest(doctype=doctype):
                out = broker.dispatch("plan_cancel",
                                      {"name": submitted, "pacioli_doctype": doctype})
                self.assertTrue(out["ok"], out)
                flag = next((f for f in out["risk_flags"]
                             if "Repost Item Valuation" in f and cancel_site in f), None)
                self.assertIsNotNone(flag, out["risk_flags"])
                self.assertIn("UNCONDITIONALLY", flag)
                self.assertIn("docstatus == 2", flag)  # the force clause, cited

    def test_no_op_for_a_non_stock_doctype(self):
        broker, client, _ = make_broker()
        out = broker.dispatch("plan_submit", {"name": "SO-1", "pacioli_doctype": SALES_ORDER})
        self.assertTrue(out["ok"], out)
        self.assertFalse(any("repost_future_sle_and_gle" in f for f in out["risk_flags"]),
                         out["risk_flags"])


class TestGraphNodeDatelessPin(unittest.TestCase):
    """The Asset-cascade live-prove find (lab CT 31340, 2026-07-22): Asset Depreciation Schedule
    — auto-created and auto-submitted by Asset's own submit, so it rides EVERY submitted
    depreciating Asset's cascade graph — is an unmodeled node with ZERO date fields in its own
    schema. Under the unmodeled "posting_date" default, node_meta read ``""`` and the deny-biased
    non-ISO refusal killed the whole cascade at preflight — the landed Asset row's ONLY
    documented cancel path (plan_cascade_cancel) could structurally never run. The fix is the
    BOM declared-dateless pin extended to graph participants (tools.GRAPH_NODE_DATE_FIELDS),
    source-verified the same three ways (not in period_closing_doctypes, no make_gl_entries in
    its hierarchy, no Date/Datetime field in its schema). Deny-bias is UNCHANGED for every
    other unmodeled node — the control test pins that."""

    ADS = "Asset Depreciation Schedule"

    def _client_with_dependent(self, dep_doctype):
        cc = CascadeClient({("Sales Invoice", "T"): [{"doctype": dep_doctype, "docname": "S"}],
                            (dep_doctype, "S"): []})
        # The dependent's doc deliberately carries NO posting_date key — the live ADS shape
        # (zero date fields in its schema; a frappe read returns nothing to read).
        cc.docs["S"] = {"name": "S", "docstatus": 1, "company": "Example Corp",
                        "modified": "vS"}
        return cc

    def test_cascade_node_meta_carries_the_sentinel_for_an_ads_node(self):
        # Mirrors the BOM sentinel test one class up: the pin routes through the SAME
        # _posting_date_of single reader, so _cascade_node_meta hands run_cascade the sentinel.
        cc = self._client_with_dependent(self.ADS)
        broker, client, _ = make_broker(client=cc)
        meta = broker._cascade_node_meta(client)(self.ADS, "S")
        self.assertEqual(meta["posting_date"], NO_DATE_FIELD)

    def test_cascade_with_an_ads_dependent_plans_and_executes(self):
        # End-to-end: plan (graph S then T, S generic), mint, execute — both cancel. Before the
        # pin this refused at run_cascade preflight with the non-ISO lock-read refusal.
        cc = self._client_with_dependent(self.ADS)
        broker, client, store_provider = make_broker(client=cc)
        plan = broker.dispatch("plan_cascade_cancel",
                               {"name": "T", "pacioli_doctype": "Sales Invoice"})
        self.assertTrue(plan["ok"], plan)
        self.assertEqual([n["docname"] for n in plan["graph"]], ["S", "T"])
        self.assertEqual(plan["graph"][0]["coverage"], "generic")
        self.assertEqual(plan["graph"][0]["posting_date"], NO_DATE_FIELD)
        store_provider("prod").mint_marker("casc-token", plan["plan_id"], expires_at=2_000.0)
        out = broker.dispatch("cascade_cancel",
                              {"name": "T", "plan_id": plan["plan_id"], "marker": "casc-token"})
        self.assertTrue(out["ok"], out)
        self.assertEqual([n["docname"] for n in out["cancelled"]], ["S", "T"])
        # The sentinel node's lock read was SKIPPED (only T's own real date was lock-checked).
        self.assertTrue(all(pd != NO_DATE_FIELD and pd for (_, _, pd) in client.lock_calls),
                        client.lock_calls)

    def test_cascade_with_an_unpinned_dateless_node_still_refuses(self):
        # CONTROL — deny-bias unchanged: an unmodeled, unpinned dependent with no readable date
        # (the pre-fix ADS shape, on a doctype with NO source-verified pin) still refuses the
        # whole cascade at preflight, exactly like the live bench did. Plan succeeds (the plan
        # loop flags dates but does not read locks for a blank one at plan time on this path);
        # execute's preflight is where the lock read refuses.
        cc = self._client_with_dependent("Transaction Deletion Record")
        broker, client, store_provider = make_broker(client=cc)
        plan = broker.dispatch("plan_cascade_cancel",
                               {"name": "T", "pacioli_doctype": "Sales Invoice"})
        if not plan.get("ok"):
            # Equally honest: the refusal may already fire at plan time — either way, refused.
            self.assertIn("not a valid ISO", plan["reason"])
            return
        store_provider("prod").mint_marker("casc-token", plan["plan_id"], expires_at=2_000.0)
        out = broker.dispatch("cascade_cancel",
                              {"name": "T", "plan_id": plan["plan_id"], "marker": "casc-token"})
        self.assertFalse(out["ok"], out)
        self.assertEqual(client.cancelled, [])  # nothing irreversible happened
        self.assertIn("not a valid ISO", repr(out))


class TestCompanylessClosedBooksGuard(unittest.TestCase):
    """The REAL shipped broker bug the 2026-07-21 live-prove batch caught against the assembled
    broker (never surfaced by the unit suite, because FakeClient.get_period_locks used to
    tolerate company=None where the real ErpnextClient refuses): ``_tool_plan_submit ->
    _plan_closed_books_risk -> client.get_period_locks(company=None, doctype, posting_date) ->
    get_period_locks -> self._doc_path("Company", None) -> ErpnextError("a document name is
    required")``. Every COMPANYLESS-BUT-DATED doctype crashed ``plan_submit``/``plan_cancel``/the
    real submit/cancel execute path on a live bench: Bank Guarantee, Project Update, Supplier
    Scorecard Period, Shipment, and Asset Maintenance Log (the fifth found from shape during this
    fix, not originally reported broken — the same companyless+dated combination). Packing Slip
    is companyless too but ALSO dateless, so its own sentinel branch already short-circuited
    before reaching this one — genuinely unaffected, pinned below.

    The fix is shape-driven off ``company`` presence alone (:func:`pacioli.tools._locks_for` /
    :meth:`PacioliBroker._plan_closed_books_risk`), never a doctype list — these tests exercise
    it generically (a loop over every live-broken doctype) plus the two edge conditions that
    prove the guard actually fires BEFORE any network call, not merely that the outcome happens
    to look right."""

    COMPANYLESS_DATED = (
        ("Bank Guarantee", "BG-1", BANK_GUARANTEE, "BG-9"),
        ("Project Update", "PU-1", PROJECT_UPDATE, "PU-9"),
        ("Supplier Scorecard Period", "SSP-1", SUPPLIER_SCORECARD_PERIOD, "SSP-9"),
        ("Shipment", "SHIP-1", SHIPMENT, "SHIP-9"),
        ("Asset Maintenance Log", "AML-1", ASSET_MAINTENANCE_LOG, "AML-9"),
    )

    def test_fake_client_itself_refuses_a_companyless_lock_read(self):
        # The honesty fix, pinned directly: the test double must refuse company=None exactly like
        # the real ErpnextClient (erpnext.py's _doc_path("Company", None)) — never tolerate what
        # the real client refuses, or a missing production guard could ship green again.
        broker, client, _ = make_broker()
        from pacioli.erpnext import ErpnextError
        with self.assertRaises(ErpnextError) as ctx:
            client.get_period_locks(None, "Bank Guarantee", "2026-07-01")
        self.assertIn("a document name is required", str(ctx.exception))
        with self.assertRaises(ErpnextError):
            client.get_period_locks("", "Bank Guarantee", "2026-07-01")

    def test_plan_submit_never_crashes_and_discloses_for_every_companyless_dated_doctype(self):
        for doctype, docname, _const, _submitted in self.COMPANYLESS_DATED:
            with self.subTest(doctype=doctype):
                broker, client, _ = make_broker(reg=REG_UNPINNED)
                out = broker.dispatch("plan_submit",
                                      {"name": docname, "pacioli_doctype": doctype})
                self.assertTrue(out["ok"], out)
                self.assertEqual(client.lock_calls, [],
                                 f"{doctype}: get_period_locks must never be called with "
                                 "company=None")
                self.assertTrue(
                    any("closed-books: not applicable" in f and "no company" in f
                       for f in out["risk_flags"]),
                    (doctype, out["risk_flags"]))

    def test_plan_cancel_never_crashes_and_discloses_for_every_companyless_dated_doctype(self):
        for doctype, _draft, _const, submitted_name in self.COMPANYLESS_DATED:
            with self.subTest(doctype=doctype):
                broker, client, _ = make_broker(reg=REG_UNPINNED)
                out = broker.dispatch("plan_cancel",
                                      {"name": submitted_name, "pacioli_doctype": doctype})
                self.assertTrue(out["ok"], out)
                self.assertEqual(client.lock_calls, [],
                                 f"{doctype}: get_period_locks must never be called with "
                                 "company=None")
                self.assertTrue(
                    any("closed-books: not applicable" in f and "no company" in f
                       for f in out["risk_flags"]),
                    (doctype, out["risk_flags"]))

    def test_execute_time_submit_and_cancel_never_call_locks_even_with_an_unreadable_source(self):
        # The strongest form of the claim, mirroring TestBomDatelessClosedBooks's own
        # test_full_governed_submit_flow_with_live_locks_and_an_unreadable_lock_source: arm
        # fail_locks so the fake WOULD raise if the guard ever let a call through, then prove a
        # real submit AND a real cancel both still succeed end to end — the guard in
        # _locks_for/_plan_closed_books_risk short-circuits before _governed_write's own
        # execute-time lock read too, not just the plan-time disclosure.
        broker, client, stores = make_broker(reg=REG_UNPINNED)
        client.fail_locks = "lock source down"
        plan = broker.dispatch("plan_submit",
                               {"name": "SSP-1", "pacioli_doctype": "Supplier Scorecard Period"})
        self.assertTrue(plan["ok"], plan)
        token = "ssp-companyless-guard-token"
        stores("prod").mint_marker(token, plan["plan_id"], expires_at=2_000.0)
        out = broker.dispatch("submit_supplier_scorecard_period",
                              {"name": "SSP-1", "plan_id": plan["plan_id"], "marker": token})
        self.assertTrue(out["ok"], out)
        self.assertEqual(client.lock_calls, [])  # never read, plan OR execute

        cancel_plan = broker.dispatch("plan_cancel",
                                      {"name": "SSP-9",
                                       "pacioli_doctype": "Supplier Scorecard Period"})
        self.assertTrue(cancel_plan["ok"], cancel_plan)
        cancel_token = "ssp-companyless-guard-cancel-token"
        stores("prod").mint_marker(cancel_token, cancel_plan["plan_id"], expires_at=2_000.0)
        cancel_out = broker.dispatch("cancel_supplier_scorecard_period",
                                     {"name": "SSP-9", "plan_id": cancel_plan["plan_id"],
                                      "marker": cancel_token})
        self.assertTrue(cancel_out["ok"], cancel_out)
        self.assertEqual(client.lock_calls, [])  # still never read

    def test_flag_absent_for_a_company_bearing_doctype(self):
        # The control case: a company-PINNED, company-bearing doctype (Sales Invoice) reads a
        # real lock and never carries the "no company" disclosure — the guard is shape-driven off
        # an ACTUALLY missing/blank company, never a blanket suppression of the real check.
        broker, client, _ = make_broker()
        out = broker.dispatch("plan_submit", {"name": "SI-1"})
        self.assertTrue(out["ok"], out)
        self.assertEqual(client.lock_calls, [("Example Corp", SALES_INVOICE, "2026-07-01")])
        self.assertFalse(any("no company" in f for f in out["risk_flags"]), out["risk_flags"])

    def test_dateless_and_companyless_packing_slip_still_takes_the_sentinel_path(self):
        # Packing Slip is companyless too, but ALSO dateless — the dateless branch in
        # _plan_closed_books_risk returns FIRST, before the company check is ever reached, so its
        # disclosure text must still be the "no date field" one, never the newer "no company" one
        # this fix adds. Unchanged by this fix, pinned explicitly.
        broker, client, _ = make_broker(reg=REG_UNPINNED)
        out = broker.dispatch("plan_submit", {"name": "PS-1", "pacioli_doctype": "Packing Slip"})
        self.assertTrue(out["ok"], out)
        self.assertEqual(client.lock_calls, [])
        self.assertTrue(any("no date field" in f for f in out["risk_flags"]), out["risk_flags"])
        self.assertFalse(any("no company" in f for f in out["risk_flags"]), out["risk_flags"])


class TestBomLedgerPreviewSkipped(unittest.TestCase):
    """The second finding, same shape as Dunning/LCV/Blanket Order/Job Card: BOM's plan_submit
    never CALLS the native preview at all — BOM(WebsiteGenerator) has no make_gl_entries anywhere
    in its MRO (WebsiteGenerator is a bare Document subclass, frappe-wide grep confirms frappe
    defines no such method), so the real RPC would raise AttributeError on a live bench. Same
    intercept technique as every prior skip-category test, since the FakeClient's doctype-blind
    preview stub would otherwise mask a regression."""

    def test_plan_submit_never_calls_the_native_preview(self):
        broker, client, _ = make_broker()
        preview_calls = []
        real_preview = client.ledger_preview
        client.ledger_preview = lambda **kw: preview_calls.append(kw) or real_preview(**kw)
        out = broker.dispatch("plan_submit", {"name": "BOM-1", "pacioli_doctype": "BOM"})
        self.assertTrue(out["ok"], out)
        self.assertEqual(preview_calls, [])

    def test_plan_submit_projected_gl_is_empty_by_construction_with_the_disclosure_flag(self):
        broker, client, _ = make_broker()
        out = broker.dispatch("plan_submit", {"name": "BOM-1", "pacioli_doctype": "BOM"})
        self.assertTrue(out["ok"], out)
        self.assertEqual(out["projected_gl"], [])
        self.assertTrue(
            any("PROJECTED GL IS EMPTY BECAUSE THE PREVIEW COULD NOT RUN" in f
                for f in out["risk_flags"]),
            "an empty projected_gl for BOM must carry the WHY — this is not a preview that ran "
            "and found nothing, it is a preview this broker never called")
        flag = next(f for f in out["risk_flags"]
                   if "PROJECTED GL IS EMPTY BECAUSE THE PREVIEW COULD NOT RUN" in f)
        self.assertIn("make_gl_entries", flag)
        self.assertIn("BOM", flag)
        self.assertIn("WebsiteGenerator", flag)
        # Its own flag names its own doctype, never a borrowed one.
        self.assertNotIn("Dunning", flag)
        self.assertNotIn("Job Card", flag)
        self.assertFalse(any("WRONG DOCUMENT" in f for f in out["risk_flags"]))

    def test_plan_cancel_needs_no_new_flag_the_real_read_is_already_honest(self):
        # plan_cancel's projected_reversal comes from get_gl_entries — a REAL, safe bench read
        # that correctly comes back empty for a BOM (no GL row was ever written under a BOM's
        # name, in either direction; its on_cancel deactivates the recipe and reassigns the
        # Item's default, never a ledger row); the pre-existing generic "no live GL rows found"
        # flag already says so.
        broker, client, _ = make_broker()
        client.gl_rows = []
        out = broker.dispatch("plan_cancel", {"name": "BOM-9", "pacioli_doctype": "BOM"})
        self.assertTrue(out["ok"], out)
        self.assertEqual(out["projected_reversal"], [])
        self.assertTrue(any("no live GL rows found" in f for f in out["risk_flags"]))
        self.assertFalse(any("PROJECTED GL IS EMPTY BECAUSE THE PREVIEW COULD NOT RUN" in f
                             for f in out["risk_flags"]))

    def test_other_doctypes_plan_submit_is_unaffected_by_the_bom_branch(self):
        # Regression pin: the skip tuple must not swallow the native preview call for any other
        # doctype — Sales Invoice still gets a real (fake-client-stub) non-empty projected_gl
        # with no skip-category flag attached, and its closed-books disclosure still READS locks.
        broker, client, _ = make_broker()
        out = broker.dispatch("plan_submit", {"name": "SI-1"})
        self.assertTrue(out["ok"], out)
        self.assertTrue(out["projected_gl"])
        self.assertFalse(any("PREVIEW COULD NOT RUN" in f for f in out["risk_flags"]))
        self.assertEqual(client.lock_calls, [("Example Corp", SALES_INVOICE, "2026-07-01")])


class TestBomCancelBlastRadiusForParentBom(unittest.TestCase):
    """BOM's cancel fan-in is the widest landed so far — 29 Link→BOM fields across 25 doctypes
    (erpnext.py's SUPPORTED_DOCTYPES comment block has the full enumeration; the dossier's own §7
    named Supplier Quotation among them, corrected: it carries no BOM link at all). The sharpest
    edge is the SELF-REFERENCING one: BOM Item.bom_no makes a parent BOM's child row a submitted
    link to this BOM, so the broker's leaf-node gate refuses the cancel BEFORE ERPNext's own
    narrower validate_bom_links throw (which only checks ACTIVE parents) would even be reached —
    equal-or-stricter, and the same generic get_submitted_linked_docs walk every prior doctype's
    edges ride, zero cascade.py changes."""

    def test_cancelling_a_bom_used_as_a_sub_assembly_is_refused(self):
        broker, client, _ = make_broker()
        client.linked = [{"doctype": "BOM", "name": "BOM-PARENT-7", "docstatus": 1}]
        out = broker.dispatch("plan_cancel", {"name": "BOM-9", "pacioli_doctype": "BOM"})
        self.assertFalse(out["ok"])
        self.assertIn("BOM-PARENT-7", out["reason"])

    def test_cancelling_a_bom_under_a_submitted_work_order_is_refused(self):
        broker, client, _ = make_broker()
        client.linked = [{"doctype": "Work Order", "name": "WO-3", "docstatus": 1}]
        out = broker.dispatch("plan_cancel", {"name": "BOM-9", "pacioli_doctype": "BOM"})
        self.assertFalse(out["ok"])
        self.assertIn("Work Order", out["reason"])
        self.assertIn("WO-3", out["reason"])


