class TestWorkOrderDatetimeDateProjection(unittest.TestCase):
    """THE central finding of this landing: planned_start_date is a DATETIME — the raw REST read
    ("2026-07-01 08:30:00") fails the strict ISO-date shape every closed-books consumer
    validates, so _posting_date_of projects it to its date part. Without the projection every
    Work Order write would hard-deny at plan (the E6 lock read raises on non-ISO) AND at execute
    (get_period_locks' own gate). Each test pins one consumer of the projected value."""

    def test_plan_submit_stores_the_date_part_and_queries_locks_with_it(self):
        broker, client, stores = make_broker()
        out = broker.dispatch("plan_submit", {"name": "WO-1", "pacioli_doctype": "Work Order"})
        self.assertTrue(out["ok"], out)
        self.assertEqual(out["posting_date"], "2026-07-01")  # date part, never the raw datetime
        self.assertEqual(client.lock_calls[-1], ("Example Corp", WORK_ORDER, "2026-07-01"))
        stored = stores("prod").get_plan(out["plan_id"])
        self.assertEqual(stored.posting_date, "2026-07-01")

    def test_microsecond_datetime_projects_too(self):
        # WO-9 carries the ".ffffff" REST variant — the projection keys on the separator at
        # index 10, indifferent to what follows it.
        broker, client, _ = make_broker()
        out = broker.dispatch("plan_cancel", {"name": "WO-9", "pacioli_doctype": "Work Order"})
        self.assertTrue(out["ok"], out)
        self.assertEqual(out["posting_date"], "2026-06-15")
        self.assertEqual(client.lock_calls[-1], ("Example Corp", WORK_ORDER, "2026-06-15"))

    def test_malformed_datetime_stays_refused_projection_is_never_repair(self):
        # A non-zero-padded date under the time part must NOT truncate into a plausible-looking
        # wrong date — the raw shape flows through untouched (the projection's separator rule
        # refuses to fire on a non-ISO prefix) and the plan REFUSES at the period-lock read
        # (get_period_locks' own ISO gate — the raw value lands verbatim in the refusal).
        # LIVE-TRUE RESHAPE (2026-07-22 Asset-cascade live-prove): this test used to assert
        # "plan ok with a disclosure, execute refuses at red_line" — a shape only the formerly
        # tolerant fake produced. The real client refuses a non-ISO date at the lock read on
        # BOTH plan and execute (its first line, before any network call), so a live bench
        # never reaches check_red_line for this shape; the fake now refuses identically (see
        # FakeClient.get_period_locks' HONESTY FIX 2). check_red_line's own date branches stay
        # covered by the companyless tests (locks={} short-circuits the read) and test_plan.
        broker, client, stores = make_broker()
        client.docs["WO-1"]["planned_start_date"] = "2026-7-1 08:30:00"
        plan = broker.dispatch("plan_submit", {"name": "WO-1", "pacioli_doctype": "Work Order"})
        self.assertFalse(plan["ok"])
        self.assertIn("not a valid ISO", plan["reason"])
        self.assertIn("2026-7-1 08:30:00", plan["reason"])  # raw shape, never a "repair"
        self.assertEqual(client.submitted, [])  # nothing went to the bench

    def test_empty_date_on_this_dated_doctype_refuses_at_the_plan_lock_read(self):
        # Work Order DECLARES a date field — an empty read stays the unverifiable path, never a
        # drift into BOM's declared-dateless pass: refused at the plan-time lock read (live-true
        # reshape, see test_malformed_datetime_stays_refused_projection_is_never_repair above).
        broker, client, stores = make_broker()
        client.docs["WO-1"]["planned_start_date"] = ""
        plan = broker.dispatch("plan_submit", {"name": "WO-1", "pacioli_doctype": "Work Order"})
        self.assertFalse(plan["ok"])
        self.assertIn("not a valid ISO", plan["reason"])
        self.assertEqual(client.submitted, [])

    def test_full_governed_submit_flow(self):
        broker, client, stores = make_broker()
        plan = broker.dispatch("plan_submit", {"name": "WO-1", "pacioli_doctype": "Work Order"})
        token = "wo-raw-token"
        stores("prod").mint_marker(token, plan["plan_id"], expires_at=2_000.0)
        out = broker.dispatch("submit_work_order",
                              {"name": "WO-1", "plan_id": plan["plan_id"], "marker": token})
        self.assertTrue(out["ok"], out)
        self.assertEqual(out["result"]["docstatus"], 1)
        self.assertEqual(out["result"]["doctype"], "Work Order")
        self.assertEqual(client.submitted, ["WO-1"])
        # The execute-time lock read got the PROJECTED date too — the last call is
        # _governed_write's own, same triple as plan time.
        self.assertEqual(client.lock_calls[-1], ("Example Corp", WORK_ORDER, "2026-07-01"))
        store = stores("prod")
        self.assertEqual(store.marker_state(token), "consumed")
        self.assertEqual(store.orphans(), [])

    def test_full_governed_cancel_flow(self):
        broker, client, stores = make_broker()
        plan = broker.dispatch("plan_cancel", {"name": "WO-9", "pacioli_doctype": "Work Order"})
        self.assertTrue(plan["ok"], plan)
        self.assertIn((WORK_ORDER, "WO-9"), client.gl_calls)
        token = "wo-cancel-token"
        stores("prod").mint_marker(token, plan["plan_id"], expires_at=2_000.0)
        out = broker.dispatch("cancel_work_order",
                              {"name": "WO-9", "plan_id": plan["plan_id"], "marker": token})
        self.assertTrue(out["ok"], out)
