class TestWorkOrderLedgerPreviewSkipped(unittest.TestCase):
    """Same shape as Dunning/LCV/Blanket Order/Job Card/BOM: WorkOrder(Document) has no
    make_gl_entries anywhere in its 3114 lines (the dossier's own §5 hedged "empty OR
    AttributeError" — the MRO settles it as AttributeError), so plan_submit never calls the
    native preview at all. Same intercept technique as every prior skip-category test."""

    def test_plan_submit_never_calls_the_native_preview(self):
        broker, client, _ = make_broker()
        preview_calls = []
        real_preview = client.ledger_preview
        client.ledger_preview = lambda **kw: preview_calls.append(kw) or real_preview(**kw)
        out = broker.dispatch("plan_submit", {"name": "WO-1", "pacioli_doctype": "Work Order"})
        self.assertTrue(out["ok"], out)
        self.assertEqual(preview_calls, [])

    def test_plan_submit_projected_gl_is_empty_by_construction_with_the_disclosure_flag(self):
        broker, client, _ = make_broker()
        out = broker.dispatch("plan_submit", {"name": "WO-1", "pacioli_doctype": "Work Order"})
        self.assertTrue(out["ok"], out)
        self.assertEqual(out["projected_gl"], [])
        flag = next((f for f in out["risk_flags"]
                    if "PROJECTED GL IS EMPTY BECAUSE THE PREVIEW COULD NOT RUN" in f), None)
        self.assertIsNotNone(flag, out["risk_flags"])
        self.assertIn("make_gl_entries", flag)
        self.assertIn("Work Order", flag)
        self.assertNotIn("Dunning", flag)
        self.assertNotIn("BOM has", flag)  # its own flag, never a borrowed one

