class TestAssetSubmitRiskFlags(unittest.TestCase):
    """The submit-direction disclosure layer for the first async-GL doctype. ASSET-1's fixture
    is deliberately the QUIET configuration (purchase doc linked, depreciation off, date in the
    past, regular asset_type) so each test below mutates exactly one field and asserts exactly
    one flag lights — and the quiet baseline asserts the conditional flags stay dark."""

    def _flags(self, broker):
        out = broker.dispatch("plan_submit", {"name": "ASSET-1", "pacioli_doctype": "Asset"})
        self.assertTrue(out["ok"], out)
        return out["risk_flags"]

    def test_sibling_asset_movement_flag_is_unconditional(self):
        broker, _, _ = make_broker()
        flags = self._flags(broker)
        self.assertTrue(any("auto-creates AND submits an Asset Movement" in f for f in flags))

    def test_quiet_baseline_has_no_conditional_flags(self):
        broker, _, _ = make_broker()
        flags = self._flags(broker)
        self.assertFalse(any("calculate_depreciation is set" in f for f in flags))
        self.assertFalse(any("available_for_use_date is in the future" in f for f in flags))
        self.assertFalse(any("no purchase document" in f for f in flags))
        self.assertFalse(any("Composite Component" in f for f in flags))

    def test_depreciation_channel_flag(self):
        broker, client, _ = make_broker()
        client.docs["ASSET-1"]["calculate_depreciation"] = 1
        flags = self._flags(broker)
        flag = next(f for f in flags if "calculate_depreciation is set" in f)
        self.assertIn("post_depreciation_entries", flag)
        self.assertIn("outside this broker's consent", flag)

    def test_deferred_cwip_channel_flag_for_a_future_date(self):
        broker, client, _ = make_broker()
        client.docs["ASSET-1"]["available_for_use_date"] = "2027-01-01"
        flags = self._flags(broker)
        flag = next(f for f in flags if "available_for_use_date is in the future" in f)
        self.assertIn("make_post_gl_entry", flag)
        # The generic future-date flag fires alongside from the same comparison — both belong.
        self.assertTrue(any(f == "posting_date is in the future" for f in flags))

    def test_no_purchase_document_flag(self):
        broker, client, _ = make_broker()
        client.docs["ASSET-1"]["purchase_receipt"] = ""
        client.docs["ASSET-1"]["purchase_invoice"] = ""
        flags = self._flags(broker)
        flag = next(f for f in flags if "no purchase document" in f)
        self.assertIn("validate_make_gl_entry", flag)

    def test_composite_component_flag_and_no_purchase_doc_exemption(self):
        # A Composite Component never posts directly — its own flag fires, and the
        # no-purchase-document flag must NOT (validate_make_gl_entry's purchase-doc requirement
        # exempts the composite family).
        broker, client, _ = make_broker()
        client.docs["ASSET-1"]["asset_type"] = "Composite Component"
        client.docs["ASSET-1"]["purchase_receipt"] = ""
        flags = self._flags(broker)
        self.assertTrue(any("Composite Component" in f for f in flags))
        self.assertFalse(any("no purchase document" in f for f in flags))

    def test_other_doctypes_are_unaffected(self):
        broker, client, _ = make_broker()
        out = broker.dispatch("plan_submit", {"name": "SI-1"})
        self.assertTrue(out["ok"], out)
        self.assertFalse(any("Asset Movement" in f for f in out["risk_flags"]))


class TestAssetStructuralCancel(unittest.TestCase):
    """THE structural finding: every submitted Asset carries a submitted Asset Movement from
    birth (on_submit creates and submits it), so leaf-node plan_cancel refuses for every real
    Asset and plan_cascade_cancel is the governed cancel path — equal in effect to ERPNext's own
    silent multi-document unwind (frappe runs on_cancel BEFORE check_no_back_links_exist),
    stricter in consent (the human sees the whole graph first)."""

    def test_plan_cancel_refuses_on_the_birth_movement(self):
        broker, client, _ = make_broker()
        client.linked = [{"doctype": "Asset Movement", "name": "AM-1", "docstatus": 1}]
        out = broker.dispatch("plan_cancel", {"name": "ASSET-9", "pacioli_doctype": "Asset"})
        self.assertFalse(out["ok"])
        self.assertIn("Asset Movement", out["reason"])
        self.assertIn("plan_cascade_cancel", out["reason"])

    def test_cascade_plan_carries_the_asset_disclosures_per_node(self):
        # The REAL cancel path: a graph containing the asset (its movement already cancelled out
        # from under it here, single-node graph for harness simplicity) still names the
        # multi-document unwind against the right docname.
        broker, client, stores = make_broker()
        out = broker.dispatch("plan_cascade_cancel",
                              {"name": "ASSET-9", "pacioli_doctype": "Asset"})
        self.assertTrue(out["ok"], out)
        self.assertTrue(any("ASSET-9: " in f and "multi-document unwind" in f
                            for f in out["risk_flags"]), out["risk_flags"])
        stored = stores("prod").get_plan(out["plan_id"])
        self.assertEqual(stored.posting_date, "2026-06-15")

    def test_leaf_cancel_when_reachable_carries_the_unwind_flag(self):
        # Reaching plan_cancel means the movement graph was already cancelled — the disclosure
        # still rides so the consent names what ERPNext's own on_cancel will do regardless.
        broker, client, _ = make_broker()
        out = broker.dispatch("plan_cancel", {"name": "ASSET-9", "pacioli_doctype": "Asset"})
        self.assertTrue(out["ok"], out)
        self.assertTrue(any("multi-document unwind" in f for f in out["risk_flags"]))
        self.assertTrue(any("plan_cascade_cancel is the governed path" in f
                            for f in out["risk_flags"]))

    def test_doomed_cancel_disclosed_for_maintenance_status(self):
        broker, client, _ = make_broker()
        client.docs["ASSET-9"]["status"] = "In Maintenance"
        out = broker.dispatch("plan_cancel", {"name": "ASSET-9", "pacioli_doctype": "Asset"})
        self.assertTrue(out["ok"], out)  # disclosure, not a broker gate — TOCTOU-honest
        self.assertTrue(any("'In Maintenance'" in f and "REFUSE" in f
                            for f in out["risk_flags"]), out["risk_flags"])

    def test_doomed_cancel_disclosed_for_terminal_status(self):
        broker, client, _ = make_broker()
        client.docs["ASSET-9"]["status"] = "Scrapped"
        out = broker.dispatch("plan_cancel", {"name": "ASSET-9", "pacioli_doctype": "Asset"})
        self.assertTrue(out["ok"], out)
        self.assertTrue(any("'Scrapped'" in f for f in out["risk_flags"]))

    def test_cancellable_status_carries_no_doom_flag(self):
        broker, client, _ = make_broker()  # ASSET-9 is Partially Depreciated — cancellable
        out = broker.dispatch("plan_cancel", {"name": "ASSET-9", "pacioli_doctype": "Asset"})
        self.assertTrue(out["ok"], out)
        self.assertFalse(any("validate_cancellation" in f for f in out["risk_flags"]))


# ============================================================================================
# BREADTH (Packing Slip) — Wave 4, the twenty-third doctype and first row (dossier at
# docs/plans/dossiers/packing_slip.md — correct on every axis it checked). party_field=None: a
# shipment-packing record, zero party fields anywhere. status AND grand_total both confirmed
# absent — forces a FIFTEENTH _list_fields branch (delivery_note/from_case_no/to_case_no stand
# in) that is ALSO the first to omit "company" entirely. date_field=None — THE SECOND DATELESS
# doctype, reusing BOM's own NO_DATE_FIELD machinery unchanged (see TestPackingSlipDateless
# below — folded into the governed round trip class since the pinned-target case can never even
# reach the dateless checks, see below). THE ledger_preview finding: PackingSlip(StatusUpdater)
# has no make_gl_entries anywhere in its MRO — the Dunning/LCV/Blanket Order/Job Card/BOM/Work
# Order "uncallable" category (see TestPackingSlipLedgerPreviewSkipped). A GENUINELY NEW finding
# that is NOT new machinery: Packing Slip also carries no "company" field at all — every
# governed verb's existing "wrong books" belt (unchanged code, nine call sites in tools.py)
# therefore refuses under a company-PINNED target (None never matches a real pin) and passes
# cleanly under the documented UNPINNED posture (see TestPackingSlipCompanylessBooks and the
# REG_UNPINNED-based TestPackingSlipGovernedRoundTrip below). Cascade: a CASCADE LEAF — the only
# Link -> Packing Slip field anywhere in the v16 tree is its own self-referencing amended_from
# (full-tree scan), so no external-doctype blast-radius test is built (there is no real edge to
# exercise one against).
# ============================================================================================

class TestPackingSlipListTier(unittest.TestCase):
    """The list half of Packing Slip's fifteenth _list_fields branch (erpnext.py's own
    docstrings carry the full source-cited finding; the requested-column assertions live in
    test_erpnext.py). What THIS class pins is the threading: party_field=None AND date_field=None
    both travel to list_documents as deliberate Nones — the same "both slots None at once" shape
    BOM's own TestBomListTier already established, now shared by a second doctype."""

