class TestPackingSlipCompanylessBooks(unittest.TestCase):
    """THE genuinely new finding of this landing: Packing Slip carries no "company" field at
    all, so `doc.get("company")` always reads back None. This is NOT a bug and NOT new
    machinery — the nine existing "wrong books" call sites in tools.py already handle it
    correctly, unchanged: a company-PINNED target (the default REG in this test module) refuses
    every governed write on this doctype (None never matches a real pin — the same
    deny-on-unverifiable posture this codebase already applies to a locked period or an
    unreadable clock), while the documented UNPINNED posture (registry.py; REG_UNPINNED,
    previously built for exactly this scenario) governs it cleanly. Reads are unaffected either
    way — only submit/cancel/amend carry the belt."""

    def test_plan_submit_refuses_wrong_books_under_a_pinned_target(self):
        broker, client, _ = make_broker()  # default REG: company = "Example Corp"
        out = broker.dispatch("plan_submit", {"name": "PS-1", "pacioli_doctype": "Packing Slip"})
        self.assertFalse(out["ok"])
        self.assertIn("wrong books", out["reason"].lower())
        self.assertIn("None", out["reason"])
        self.assertIn("Example Corp", out["reason"])

    def test_plan_cancel_refuses_wrong_books_under_a_pinned_target(self):
        broker, client, _ = make_broker()
        out = broker.dispatch("plan_cancel", {"name": "PS-9", "pacioli_doctype": "Packing Slip"})
        self.assertFalse(out["ok"])
        self.assertIn("wrong books", out["reason"].lower())

    def test_amend_refuses_wrong_books_under_a_pinned_target(self):
        broker, client, _ = make_broker()
        client.docs["PS-9"]["docstatus"] = 2
        out = broker.dispatch("amend_packing_slip", {"name": "PS-9"})
        self.assertFalse(out["ok"])
        self.assertIn("wrong books", out["reason"].lower())

    def test_get_and_list_are_unaffected_by_the_company_pin(self):
        # Reads carry no company check at all — the belt only ever sits on the governed verbs.
        broker, client, _ = make_broker()
        out = broker.dispatch("get_packing_slip", {"name": "PS-1"})
        self.assertTrue(out["ok"], out)
        out = broker.dispatch("list_packing_slips", {})
        self.assertTrue(out["ok"], out)

    def test_plan_submit_succeeds_under_the_documented_unpinned_posture(self):
        # The escape hatch this landing invents no new code for: REG_UNPINNED is the SAME idiom
        # Sales Invoice's own F-C2 wrong-books tests already built for a target with no company
        # pin — Packing Slip is simply the first doctype that can NEVER pass the pinned check.
        broker, client, _ = make_broker(reg=REG_UNPINNED)
        out = broker.dispatch("plan_submit", {"name": "PS-1", "pacioli_doctype": "Packing Slip"})
        self.assertTrue(out["ok"], out)


class TestPackingSlipGovernedRoundTrip(unittest.TestCase):
    """One full plan->submit, plan->cancel, and amend round trip, plus the cascade node_meta
    closure and the dateless closed-books chain — all exercised under REG_UNPINNED (the ONLY
    registry shape a companyless doctype can ever govern through, per
    TestPackingSlipCompanylessBooks above). The semantic divergences (uncallable preview,
    dateless sentinel, companyless wrong-books) live in their own dedicated test classes; this
    class proves the generated mechanical wiring holds end to end for the twenty-third
    doctype."""

