# BREADTH (Cost Center Allocation) — Wave 4, the twenty-fourth doctype and second row (dossier at
# docs/plans/dossiers/cost_center_allocation.md). A DOSSIER CORRECTION this landing settles from
# source: the dossier's own §3/§12 claimed BOTH a real, required valid_from Date field AND
# "DATELESS in the broker sense" — an internally contradictory pair. Verified from
# cost_center_allocation.json:27-34: valid_from IS a real Date field (reqd, default "Today") — a
# NORMAL dated doctype (the SO/PO/Blanket-Order-style equal-or-stricter closed-books shape),
# never the NO_DATE_FIELD sentinel; date_field="valid_from" is the SIXTH distinct date-fieldname
# pattern, riding the existing generic date machinery unchanged. party_field=None: a
# recurring-allocation rule, zero party fields anywhere. status AND grand_total: both confirmed
# absent — forces a SIXTEENTH _list_fields branch with no substitute/context column at all (the
# smallest schema this campaign has found, 7 fields total). "company" IS present (fetch_from
# main_cost_center.company, reqd) — UNLIKE Packing Slip, the standing "wrong books" belt applies
# in its ordinary form, so this class uses the DEFAULT (company-pinned) REG throughout, never
# REG_UNPINNED. THE ledger_preview finding: CostCenterAllocation(Document) has no make_gl_entries
# anywhere in its MRO — the Dunning/LCV/Blanket Order/Job Card/BOM/Work Order/Packing Slip
# "uncallable" category (see TestCostCenterAllocationLedgerPreviewSkipped). NO on_submit/
# on_cancel hook of any kind is defined — the simplest submit/cancel lifecycle this campaign has
# found, never even a counter rewrite. Cascade: a CASCADE LEAF — the only Link -> Cost Center
# Allocation field anywhere in the v16 tree is its own self-referencing amended_from (full-tree
# scan), so no external-doctype blast-radius test is built (there is no real edge to exercise
# one against). Side surface: ZERO whitelist callables — nothing to caveat, nothing to withhold.
# ============================================================================================

class TestCostCenterAllocationListTier(unittest.TestCase):
    """The ONE genuinely new branch Cost Center Allocation forces (erpnext.py's
    SUPPORTED_DOCTYPES/_list_fields docstrings have the full source-cited finding): party_field=
    None combined with status AND grand_total both absent is the Stock Entry/Stock
    Reconciliation/LCV/Blanket Order/BOM absence SHAPE, but not a reuse of any of them — this
    doctype carries no substitute/context column at all, the barest branch this campaign has
    built. date_field="valid_from" is a REAL Date column (the dossier correction), spliced via
    the parameter exactly like every other dated branch — never the dateless slot."""

    def test_list_uses_no_party_field_and_the_valid_from_field(self):
        broker, client, _ = make_broker()
        out = broker.dispatch("list_cost_center_allocations", {})
        self.assertTrue(out["ok"])
        self.assertEqual(client.list_calls, [(COST_CENTER_ALLOCATION, None, "valid_from")])

    def test_config_is_party_field_none_dated_and_run_method(self):
        # The decision itself, asserted directly: party_field=None is deliberate here too, and
        # date_field is a REAL fieldname (never None, despite the dossier's own contradictory
        # "dateless" claim) — neither is an accident of a missing key or blank-string placeholder.
        cfg = SUPPORTED_DOCTYPES[COST_CENTER_ALLOCATION]
        self.assertEqual(cfg, {"party_field": None, "submit_via": "run_method",
                               "date_field": "valid_from"})
        self.assertIn("party_field", cfg)
        self.assertIsNone(cfg["party_field"])
        self.assertIn("date_field", cfg)
        self.assertEqual(cfg["date_field"], "valid_from")


