class TestSupplierScorecardPeriodCompanylessBooks(unittest.TestCase):
    """THE genuinely new finding of this landing (shared shape with Packing Slip, a dossier
    omission both times): Supplier Scorecard Period carries no "company" field at all, so
    `doc.get("company")` always reads back None. This is NOT a bug and NOT new machinery — the
    nine existing "wrong books" call sites in tools.py already handle it correctly, unchanged: a
    company-PINNED target (the default REG in this test module) refuses every governed write on
    this doctype (None never matches a real pin), while the documented UNPINNED posture
    (registry.py; REG_UNPINNED) governs it cleanly. Reads are unaffected either way. UNLIKE
    Packing Slip, this doctype also carries a real party_field ("supplier") — proving the two
    axes are independent: a real party field changes nothing about the company check, which
    reads only doc.get("company")."""

    def test_plan_submit_refuses_wrong_books_under_a_pinned_target(self):
        broker, client, _ = make_broker()  # default REG: company = "Example Corp"
        out = broker.dispatch("plan_submit",
                              {"name": "SSP-1", "pacioli_doctype": "Supplier Scorecard Period"})
        self.assertFalse(out["ok"])
        self.assertIn("wrong books", out["reason"].lower())
        self.assertIn("None", out["reason"])
        self.assertIn("Example Corp", out["reason"])

    def test_plan_cancel_refuses_wrong_books_under_a_pinned_target(self):
        broker, client, _ = make_broker()
        out = broker.dispatch("plan_cancel",
                              {"name": "SSP-9", "pacioli_doctype": "Supplier Scorecard Period"})
        self.assertFalse(out["ok"])
        self.assertIn("wrong books", out["reason"].lower())

    def test_amend_refuses_wrong_books_under_a_pinned_target(self):
        broker, client, _ = make_broker()
        client.docs["SSP-9"]["docstatus"] = 2
        out = broker.dispatch("amend_supplier_scorecard_period", {"name": "SSP-9"})
        self.assertFalse(out["ok"])
        self.assertIn("wrong books", out["reason"].lower())

    def test_get_and_list_are_unaffected_by_the_company_pin(self):
        # Reads carry no company check at all — the belt only ever sits on the governed verbs.
        broker, client, _ = make_broker()
        out = broker.dispatch("get_supplier_scorecard_period", {"name": "SSP-1"})
        self.assertTrue(out["ok"], out)
        out = broker.dispatch("list_supplier_scorecard_periods", {})
        self.assertTrue(out["ok"], out)

    def test_plan_submit_succeeds_under_the_documented_unpinned_posture(self):
        # The escape hatch this landing invents no new code for: REG_UNPINNED is the SAME idiom
        # Packing Slip's own landing already used for a doctype that can never pass the pinned
        # check.
        broker, client, _ = make_broker(reg=REG_UNPINNED)
        out = broker.dispatch("plan_submit",
                              {"name": "SSP-1", "pacioli_doctype": "Supplier Scorecard Period"})
        self.assertTrue(out["ok"], out)


class TestSupplierScorecardPeriodGovernedRoundTrip(unittest.TestCase):
    """One full plan->submit, plan->cancel, and amend round trip, plus the cascade node_meta
    closure — all exercised under REG_UNPINNED (the ONLY registry shape a companyless doctype can
    ever govern through, per TestSupplierScorecardPeriodCompanylessBooks above). UNLIKE Packing
    Slip (also companyless, but dateless), this doctype IS genuinely dated.

    CORRECTED (2026-07-21 live-prove batch): this class used to claim the closed-books chain
    "DOES read a real (companyless) period-lock call: client.get_period_locks(None, ...)" — that
    was never true; it CRASHED on a live bench (get_period_locks's own _doc_path("Company", None)
    raises), masked here only because FakeClient.get_period_locks used to tolerate company=None.
    The fake is now honest (raises exactly like the real client); the fix
    (tools.py's _plan_closed_books_risk/_locks_for) short-circuits BEFORE any lock read the same
    way Packing Slip's own dateless sentinel already does — proven below by an EMPTY
    ``client.lock_calls`` and the "not applicable — no company" disclosure flag, never a
    ``(None, ...)`` call. The semantic divergences (uncallable preview, companyless wrong-books)
    live in their own dedicated test classes; this class proves the generated mechanical wiring
    holds end to end for the twenty-fifth doctype."""

    def test_plan_submit_records_the_doctype_and_reads_start_date(self):
        broker, client, stores = make_broker(reg=REG_UNPINNED)
        out = broker.dispatch("plan_submit",
                              {"name": "SSP-1",
                               "pacioli_doctype": "Supplier Scorecard Period"})
        self.assertTrue(out["ok"], out)
        self.assertEqual(out["doctype"], "Supplier Scorecard Period")
        self.assertEqual(out["posting_date"], "2026-07-01")  # SSP-1's start_date value
        # CORRECTED (2026-07-21 live-prove batch): a REAL date_field on a COMPANYLESS doctype
        # does NOT read a real period-lock call — company is None (never a real name), and
        # get_period_locks would crash on that (_doc_path("Company", None)). The plan-time
        # disclosure short-circuits BEFORE any lock read, the same shape the dateless sentinel
        # already uses — never a (None, ...) call.
        self.assertEqual(client.lock_calls, [])
        self.assertTrue(any("closed-books: not applicable" in f for f in out["risk_flags"]),
                        out["risk_flags"])
        self.assertTrue(any("no company" in f for f in out["risk_flags"]), out["risk_flags"])
        stored = stores("prod").get_plan(out["plan_id"])
        self.assertEqual(stored.doctype, "Supplier Scorecard Period")
        self.assertEqual(stored.docname, "SSP-1")

    def test_full_governed_submit_flow(self):
        broker, client, stores = make_broker(reg=REG_UNPINNED)
        plan = broker.dispatch("plan_submit",
                               {"name": "SSP-1",
                                "pacioli_doctype": "Supplier Scorecard Period"})
        self.assertTrue(plan["ok"], plan)
        token = "ssp-raw-token"
        stores("prod").mint_marker(token, plan["plan_id"], expires_at=2_000.0)
        out = broker.dispatch("submit_supplier_scorecard_period",
                              {"name": "SSP-1", "plan_id": plan["plan_id"], "marker": token})
        self.assertTrue(out["ok"], out)
        self.assertEqual(out["result"]["docstatus"], 1)
        self.assertEqual(out["result"]["doctype"], "Supplier Scorecard Period")
        self.assertEqual(client.submitted, ["SSP-1"])
        store = stores("prod")
        self.assertEqual(store.marker_state(token), "consumed")
        self.assertEqual(store.orphans(), [])

    def test_plan_submit_refuses_non_draft(self):
        broker, client, _ = make_broker(reg=REG_UNPINNED)
        client.docs["SSP-1"]["docstatus"] = 1
        out = broker.dispatch("plan_submit",
                              {"name": "SSP-1",
                               "pacioli_doctype": "Supplier Scorecard Period"})
        self.assertFalse(out["ok"])
        self.assertIn("draft", out["reason"].lower())

    def test_full_governed_cancel_flow(self):
        broker, client, stores = make_broker(reg=REG_UNPINNED)
        plan = broker.dispatch("plan_cancel",
                               {"name": "SSP-9",
                                "pacioli_doctype": "Supplier Scorecard Period"})
        self.assertTrue(plan["ok"], plan)
        self.assertEqual(plan["doctype"], "Supplier Scorecard Period")
        self.assertIn((SUPPLIER_SCORECARD_PERIOD, "SSP-9"), client.gl_calls)
        token = "ssp-cancel-token"
        stores("prod").mint_marker(token, plan["plan_id"], expires_at=2_000.0)
        out = broker.dispatch("cancel_supplier_scorecard_period",
                              {"name": "SSP-9", "plan_id": plan["plan_id"], "marker": token})
        self.assertTrue(out["ok"], out)
        self.assertEqual(out["result"]["docstatus"], 2)
        self.assertEqual(client.cancelled, ["SSP-9"])
        self.assertEqual(stores("prod").marker_state(token), "consumed")

    def test_amend_creates_the_draft_with_receipts_and_no_marker(self):
        broker, client, stores = make_broker(reg=REG_UNPINNED)
        client.docs["SSP-9"]["docstatus"] = 2
        out = broker.dispatch("amend_supplier_scorecard_period", {"name": "SSP-9"})
        self.assertTrue(out["ok"], out)
        self.assertEqual(out["result"]["name"], "SSP-9-1")
        self.assertEqual(out["result"]["docstatus"], 0)
        self.assertEqual(out["result"]["doctype"], "Supplier Scorecard Period")
        self.assertEqual(client.amended, ["SSP-9"])
        store = stores("prod")
        receipts = store.receipts()
        self.assertEqual([r.kind for r in receipts], ["intent", "outcome"])
        self.assertEqual(receipts[0].body["doctype"], "Supplier Scorecard Period")
        self.assertEqual(store.orphans(), [])

    def test_amend_refuses_an_uncancelled_source(self):
        broker, client, _ = make_broker(reg=REG_UNPINNED)
        out = broker.dispatch("amend_supplier_scorecard_period", {"name": "SSP-1"})  # a draft
        self.assertFalse(out["ok"])
        self.assertIn("cancelled", out["reason"])

    def test_cascade_node_meta_reads_start_date_and_no_company_for_an_ssp_node(self):
        # Same shared closure every prior doctype's own cascade test pins — cascade.py itself is
        # untouched (fully doctype-blind), and _cascade_node_meta uses get_gl_entries (a safe
        # read, never ledger_preview) for every doctype including Supplier Scorecard Period, so
        # no special-casing is needed here even though plan_submit's own preview call IS
        # special-cased in TestSupplierScorecardPeriodLedgerPreviewSkipped below.
        broker, client, _ = make_broker(reg=REG_UNPINNED)
        node_meta = broker._cascade_node_meta(client)
        meta = node_meta(SUPPLIER_SCORECARD_PERIOD, "SSP-1")
        self.assertEqual(meta["posting_date"], "2026-07-01")
        self.assertIsNone(meta["company"])  # confirmed absent from the real schema too


class TestSupplierScorecardPeriodLedgerPreviewSkipped(unittest.TestCase):
    """The second finding, same shape as Dunning/LCV/Blanket Order/Job Card/BOM/Work
    Order/Packing Slip/Cost Center Allocation: Supplier Scorecard Period's own plan_submit never
    CALLS the native preview at all — SupplierScorecardPeriod(Document) has no make_gl_entries
    anywhere in its MRO (a direct Document subclass), so the real RPC would raise AttributeError
    on a live bench. Same intercept technique as every prior skip-category test."""

    def test_plan_submit_never_calls_the_native_preview(self):
        broker, client, _ = make_broker(reg=REG_UNPINNED)
        preview_calls = []
        real_preview = client.ledger_preview
        client.ledger_preview = lambda **kw: preview_calls.append(kw) or real_preview(**kw)
        out = broker.dispatch("plan_submit",
                              {"name": "SSP-1",
                               "pacioli_doctype": "Supplier Scorecard Period"})
        self.assertTrue(out["ok"], out)
        self.assertEqual(preview_calls, [])

    def test_plan_submit_projected_gl_is_empty_by_construction_with_the_disclosure_flag(self):
        broker, client, _ = make_broker(reg=REG_UNPINNED)
        out = broker.dispatch("plan_submit",
                              {"name": "SSP-1",
                               "pacioli_doctype": "Supplier Scorecard Period"})
        self.assertTrue(out["ok"], out)
        self.assertEqual(out["projected_gl"], [])
        self.assertTrue(
            any("PROJECTED GL IS EMPTY BECAUSE THE PREVIEW COULD NOT RUN" in f
                for f in out["risk_flags"]),
            "an empty projected_gl for Supplier Scorecard Period must carry the WHY — this is "
            "not a preview that ran and found nothing, it is a preview this broker never called")
        flag = next(f for f in out["risk_flags"]
                   if "PROJECTED GL IS EMPTY BECAUSE THE PREVIEW COULD NOT RUN" in f)
        self.assertIn("make_gl_entries", flag)
        self.assertIn("Supplier Scorecard Period", flag)
        # Its own flag names its own doctype, never a borrowed one.
        self.assertNotIn("Packing Slip", flag)
        self.assertNotIn("Cost Center Allocation", flag)
        self.assertFalse(any("WRONG DOCUMENT" in f for f in out["risk_flags"]))

    def test_plan_cancel_needs_no_new_flag_the_real_read_is_already_honest(self):
        broker, client, _ = make_broker(reg=REG_UNPINNED)
        client.gl_rows = []
        out = broker.dispatch("plan_cancel",
                              {"name": "SSP-9",
                               "pacioli_doctype": "Supplier Scorecard Period"})
        self.assertTrue(out["ok"], out)
        self.assertEqual(out["projected_reversal"], [])
        self.assertTrue(any("no live GL rows found" in f for f in out["risk_flags"]))
        self.assertFalse(any("PROJECTED GL IS EMPTY BECAUSE THE PREVIEW COULD NOT RUN" in f
                             for f in out["risk_flags"]))

    def test_other_doctypes_plan_submit_is_unaffected_by_the_supplier_scorecard_period_branch(self):
        # Regression pin: the skip tuple must not swallow the native preview call for any other
        # doctype — Sales Invoice still gets a real (fake-client-stub) non-empty projected_gl
        # with no Supplier-Scorecard-Period-shaped flag attached, and its closed-books disclosure
        # still READS locks (the default pinned REG governs SI cleanly — company matches).
        broker, client, _ = make_broker()
        out = broker.dispatch("plan_submit", {"name": "SI-1"})
        self.assertTrue(out["ok"], out)
        self.assertTrue(out["projected_gl"])
        self.assertFalse(any("PREVIEW COULD NOT RUN" in f for f in out["risk_flags"]))
        self.assertEqual(client.lock_calls, [("Example Corp", SALES_INVOICE, "2026-07-01")])


