class TestSalesForecastLedgerPreviewSkipped(unittest.TestCase):
    """THE central finding of this landing, verified from the MRO rather than assumed, and the
    CLEANEST case in this campaign's "uncallable" category: SalesForecast(Document) imports ZERO
    accounting/stock-controller-related names at all (not even a bare exception class, unlike Job
    Card's/Shipment's own bare-Document shape) — the real RPC would raise AttributeError on a live
    bench if invoked. Same intercept technique as every prior skip-category test."""

    def test_plan_submit_never_calls_the_native_preview(self):
        broker, client, _ = make_broker()
        preview_calls = []
        real_preview = client.ledger_preview
        client.ledger_preview = lambda **kw: preview_calls.append(kw) or real_preview(**kw)
        out = broker.dispatch("plan_submit",
                              {"name": "SF-1", "pacioli_doctype": "Sales Forecast"})
        self.assertTrue(out["ok"], out)
        self.assertEqual(preview_calls, [])

