class TestProjectUpdateBlankDate(unittest.TestCase):
    """THE genuinely new finding on the date axis this landing carries: date_field="date" is a
    REAL, declared field (confirmed present in project_update.json, never the date_field=None
    dateless pin BOM/Packing Slip carry) that ALSO carries reqd=0 and no schema default —
    confirmed by reading all 29 lines of project_update.py: nothing server-side ever sets it
    (only project_update.js's own client-side validate() event, and a DIFFERENT doctype's
    scheduler machinery — see erpnext.py's own module docstring). An independently-authored
    Project Update, inserted directly via the REST API, can therefore carry a genuinely blank
    date. This class proves the EXISTING generic machinery already governs that case correctly,
    with zero new plan.py/tools.py code: deny-biased at both the plan-time disclosure and the
    real execute-time gate, never a crash, never a silent bypass."""

    def test_plan_submit_discloses_but_does_not_hard_refuse_a_blank_date(self):
        # Envelope E6 is a DISCLOSURE, never a gate: plan_submit still returns ok=True even
        # though the doc's own date is blank, exactly the way a locked period still plans with a
        # risk flag rather than refusing outright.
        broker, client, _ = make_broker(reg=REG_UNPINNED)
        client.docs["PU-1"]["date"] = None
        out = broker.dispatch("plan_submit",
                              {"name": "PU-1", "pacioli_doctype": "Project Update"})
        self.assertTrue(out["ok"], out)
        self.assertEqual(out["posting_date"], "")
        self.assertTrue(any("no posting_date" in f for f in out["risk_flags"]), out["risk_flags"])

    def test_submit_is_hard_refused_at_execute_for_a_blank_date(self):
        # The real gate: pacioli.spine.governed_submit calls check_red_line against the PLAN's
        # own stored posting_date (captured at plan time from the blank-dated doc), so a marker
        # minted against this plan is refused at submit_project_update too — deny-biased end to
        # end, never a silent bypass of the closed-books check just because this doctype's own
        # date field happens to be optional.
        broker, client, stores = make_broker(reg=REG_UNPINNED)
        client.docs["PU-1"]["date"] = None
