class TestMaintenanceVisitGovernedRoundTrip(unittest.TestCase):
    """One full plan->submit, plan->cancel, and amend round trip, plus the cascade node_meta
    closure — the mechanical-wiring proof for the thirty-first doctype, matching the shape of
    TestInstallationNoteGovernedRoundTrip above. The semantic divergences (the uncallable preview,
    the Warranty Claim db_update disclosures, the temporal-ordering cancel gate) live in their own
    dedicated test classes below, not here."""

    def test_plan_submit_records_the_doctype_and_reads_mntc_date(self):
        broker, client, stores = make_broker()
        out = broker.dispatch("plan_submit",
                              {"name": "MV-1", "pacioli_doctype": "Maintenance Visit"})
        self.assertTrue(out["ok"], out)
        self.assertEqual(out["doctype"], "Maintenance Visit")
        self.assertEqual(out["posting_date"], "2026-07-01")  # MV-1's own mntc_date value
        self.assertEqual(client.lock_calls[-1],
                         ("Example Corp", MAINTENANCE_VISIT, "2026-07-01"))
        stored = stores("prod").get_plan(out["plan_id"])
        self.assertEqual(stored.doctype, "Maintenance Visit")
        self.assertEqual(stored.docname, "MV-1")

    def test_full_governed_submit_flow(self):
        broker, client, stores = make_broker()
        plan = broker.dispatch("plan_submit",
                               {"name": "MV-1", "pacioli_doctype": "Maintenance Visit"})
        self.assertTrue(plan["ok"], plan)
        token = "mv-raw-token"
        stores("prod").mint_marker(token, plan["plan_id"], expires_at=2_000.0)
        out = broker.dispatch("submit_maintenance_visit",
                              {"name": "MV-1", "plan_id": plan["plan_id"], "marker": token})
        self.assertTrue(out["ok"], out)
        self.assertEqual(out["result"]["docstatus"], 1)
        self.assertEqual(out["result"]["doctype"], "Maintenance Visit")
        self.assertEqual(client.submitted, ["MV-1"])
        store = stores("prod")
        self.assertEqual(store.marker_state(token), "consumed")
        self.assertEqual(store.orphans(), [])

    def test_plan_submit_refuses_non_draft(self):
        broker, client, _ = make_broker()
        client.docs["MV-1"]["docstatus"] = 1
        out = broker.dispatch("plan_submit",
                              {"name": "MV-1", "pacioli_doctype": "Maintenance Visit"})
        self.assertFalse(out["ok"])
        self.assertIn("draft", out["reason"].lower())

    def test_full_governed_cancel_flow(self):
        broker, client, stores = make_broker()
        plan = broker.dispatch("plan_cancel",
                               {"name": "MV-9", "pacioli_doctype": "Maintenance Visit"})
        self.assertTrue(plan["ok"], plan)
        self.assertEqual(plan["doctype"], "Maintenance Visit")
        self.assertIn((MAINTENANCE_VISIT, "MV-9"), client.gl_calls)
        token = "mv-cancel-token"
        stores("prod").mint_marker(token, plan["plan_id"], expires_at=2_000.0)
        out = broker.dispatch("cancel_maintenance_visit",
                              {"name": "MV-9", "plan_id": plan["plan_id"], "marker": token})
        self.assertTrue(out["ok"], out)
        self.assertEqual(out["result"]["docstatus"], 2)
        self.assertEqual(client.cancelled, ["MV-9"])
        self.assertEqual(stores("prod").marker_state(token), "consumed")

    def test_amend_creates_the_draft_with_receipts_and_no_marker(self):
        broker, client, stores = make_broker()
        client.docs["MV-9"]["docstatus"] = 2
        out = broker.dispatch("amend_maintenance_visit", {"name": "MV-9"})
        self.assertTrue(out["ok"], out)
        self.assertEqual(out["result"]["name"], "MV-9-1")
        self.assertEqual(out["result"]["docstatus"], 0)
        self.assertEqual(out["result"]["doctype"], "Maintenance Visit")
        self.assertEqual(client.amended, ["MV-9"])
