class TestMaintenanceVisitWarrantyClaimDisclosure(unittest.TestCase):
    """THE two genuine data-driven risk-flag findings of this landing (the Asset-precedent
    shape), both computed entirely from the draft's own maintenance_schedule/purposes fields — no
    second-document read for either the gating condition or the affected Warranty Claim
    docname(s). See _maintenance_visit_submit_risk_flags/_maintenance_visit_cancel_risk_flags's
    own docstrings (tools.py) for the full source-cited finding, including the docstatus-guard
    question source settles outright (Warranty Claim carries no is_submittable key at all)."""

    def test_submit_discloses_the_warranty_claim_db_update_bypass_when_a_purpose_row_names_one(self):
        broker, client, _ = make_broker()
        client.docs["MV-1"]["purposes"] = [
            {"prevdoc_doctype": "Warranty Claim", "prevdoc_docname": "WC-1"}]
        out = broker.dispatch("plan_submit",
                              {"name": "MV-1", "pacioli_doctype": "Maintenance Visit"})
        self.assertTrue(out["ok"], out)
        flag = next((f for f in out["risk_flags"] if "update_customer_issue(1)" in f), None)
        self.assertIsNotNone(flag, out["risk_flags"])
        self.assertIn("WC-1", flag)
        self.assertIn("db_update", flag)
        self.assertIn("not a submittable doctype", flag)

    def test_submit_names_every_linked_warranty_claim_not_just_the_first(self):
        # A single submit can touch MORE THAN ONE Warranty Claim — one independent write per
        # matching purposes row (maintenance_visit.py:132-172's own loop, not a break-after-first).
        broker, client, _ = make_broker()
        client.docs["MV-1"]["purposes"] = [
            {"prevdoc_doctype": "Warranty Claim", "prevdoc_docname": "WC-1"},
            {"prevdoc_doctype": "Warranty Claim", "prevdoc_docname": "WC-2"}]
        out = broker.dispatch("plan_submit",
                              {"name": "MV-1", "pacioli_doctype": "Maintenance Visit"})
        self.assertTrue(out["ok"], out)
        flag = next((f for f in out["risk_flags"] if "update_customer_issue(1)" in f), None)
        self.assertIsNotNone(flag, out["risk_flags"])
        self.assertIn("WC-1", flag)
        self.assertIn("WC-2", flag)

    def test_submit_flag_absent_when_maintenance_schedule_is_set(self):
        # update_customer_issue's own body is gated on "if not self.maintenance_schedule:" — a
        # schedule-driven visit never runs it at all, regardless of the purposes rows.
        broker, client, _ = make_broker()
        client.docs["MV-1"]["maintenance_schedule"] = "MS-1"
        client.docs["MV-1"]["purposes"] = [
            {"prevdoc_doctype": "Warranty Claim", "prevdoc_docname": "WC-1"}]
        out = broker.dispatch("plan_submit",
                              {"name": "MV-1", "pacioli_doctype": "Maintenance Visit"})
        self.assertTrue(out["ok"], out)
        self.assertFalse(any("update_customer_issue(1)" in f for f in out["risk_flags"]))

    def test_submit_flag_absent_when_no_purpose_row_names_a_warranty_claim(self):
        broker, client, _ = make_broker()
        client.docs["MV-1"]["purposes"] = [
            {"prevdoc_doctype": "Sales Order", "prevdoc_docname": "SO-1"}]
        out = broker.dispatch("plan_submit",
                              {"name": "MV-1", "pacioli_doctype": "Maintenance Visit"})
        self.assertTrue(out["ok"], out)
        self.assertFalse(any("update_customer_issue(1)" in f for f in out["risk_flags"]))

    def test_submit_flag_absent_on_the_baseline_fixture(self):
        # MV-1's own baseline fixture carries no "purposes" key at all — the control case.
        broker, client, _ = make_broker()
        out = broker.dispatch("plan_submit",
                              {"name": "MV-1", "pacioli_doctype": "Maintenance Visit"})
        self.assertTrue(out["ok"], out)
        self.assertFalse(any("update_customer_issue(1)" in f for f in out["risk_flags"]))

    def test_cancel_always_discloses_the_temporal_ordering_gate_in_prose(self):
        # Unconditional: check_if_last_visit()'s own throw condition cannot be predicted without a
        # sibling read this plan cannot perform, so it is always named regardless of the draft's
        # own fields — the Installation Note validate_serial_no precedent.
        broker, client, _ = make_broker()
        out = broker.dispatch("plan_cancel",
                              {"name": "MV-9", "pacioli_doctype": "Maintenance Visit"})
        self.assertTrue(out["ok"], out)
        flag = next((f for f in out["risk_flags"] if "check_if_last_visit" in f), None)
        self.assertIsNotNone(flag, out["risk_flags"])
        self.assertIn("Cancel Material Visits", flag)
        self.assertIn("same-doctype PEER constraint", flag)

    def test_cancel_discloses_the_conditional_warranty_claim_touch_when_a_candidate_exists(self):
        broker, client, _ = make_broker()
        client.docs["MV-9"]["purposes"] = [
            {"prevdoc_doctype": "Warranty Claim", "prevdoc_docname": "WC-9"}]
        out = broker.dispatch("plan_cancel",
                              {"name": "MV-9", "pacioli_doctype": "Maintenance Visit"})
        self.assertTrue(out["ok"], out)
        flag = next((f for f in out["risk_flags"] if "update_customer_issue(0)" in f), None)
        self.assertIsNotNone(flag, out["risk_flags"])
        self.assertIn("WC-9", flag)

    def test_cancel_omits_the_conditional_flag_when_no_candidate_exists(self):
        broker, client, _ = make_broker()
        out = broker.dispatch("plan_cancel",
                              {"name": "MV-9", "pacioli_doctype": "Maintenance Visit"})
        self.assertTrue(out["ok"], out)
        self.assertFalse(any("update_customer_issue(0)" in f for f in out["risk_flags"]))
        # The ordering-gate flag is still present — the two are independent.
        self.assertTrue(any("check_if_last_visit" in f for f in out["risk_flags"]))

    def test_other_doctypes_are_unaffected_by_either_flag_function(self):
        broker, client, _ = make_broker()
        out = broker.dispatch("plan_submit", {"name": "SI-1"})
        self.assertTrue(out["ok"], out)
        self.assertFalse(any("update_customer_issue" in f for f in out["risk_flags"]))
        out = broker.dispatch("plan_cancel", {"name": "SI-9", "pacioli_doctype": "Sales Invoice"})
        self.assertTrue(out["ok"], out)
        self.assertFalse(any("update_customer_issue" in f for f in out["risk_flags"]))
        self.assertFalse(any("check_if_last_visit" in f for f in out["risk_flags"]))


