class TestMaintenanceScheduleLedgerPreviewSkipped(unittest.TestCase):
    """The ledger-preview finding, verified from the MRO rather than assumed, the SAME MRO depth
    Installation Note/Maintenance Visit established: MaintenanceSchedule(TransactionBase), and
    TransactionBase(StatusUpdater) — no make_gl_entries anywhere in maintenance_schedule.py,
    transaction_base.py, or status_updater.py, so the real RPC would raise AttributeError on a
    live bench. Same intercept technique as every prior skip-category test."""

    def test_plan_submit_never_calls_the_native_preview(self):
        broker, client, _ = make_broker()
        preview_calls = []
        real_preview = client.ledger_preview
        client.ledger_preview = lambda **kw: preview_calls.append(kw) or real_preview(**kw)
        out = broker.dispatch("plan_submit",
                              {"name": "MS-1", "pacioli_doctype": "Maintenance Schedule"})
        self.assertTrue(out["ok"], out)
        self.assertEqual(preview_calls, [])

