        self.assertIsNotNone(flag, out["risk_flags"])
        self.assertIn("permanently DELETES", flag)
        gate_flag = next((f for f in out["risk_flags"] if "NO gate against" in f), None)
        self.assertIsNotNone(gate_flag, out["risk_flags"])

