class TestBankGuaranteeSubmitRiskFlags(unittest.TestCase):
    """THE genuine finding of this landing: a fully deterministic doomed-submit gate off
    bank_guarantee_number/name_of_beneficiary/bank (three distinct ERPNext throws, each readable
    off the draft before a marker is ever minted, each stopping the check at the first failure),
    and — unlike every other doctype in this campaign carrying a submit risk-flag function — NO
    further side effect at all when submit is not doomed. See
    _bank_guarantee_submit_risk_flags's own docstring (tools.py) for the full source-cited
    finding."""

    def test_submit_is_doomed_when_bank_guarantee_number_is_blank(self):
        broker, client, _ = make_broker(reg=REG_UNPINNED)
        client.docs["BG-1"]["bank_guarantee_number"] = None
        out = broker.dispatch("plan_submit",
                              {"name": "BG-1", "pacioli_doctype": "Bank Guarantee"})
        self.assertTrue(out["ok"], out)  # the plan still records; only submit itself is doomed
        flag = next((f for f in out["risk_flags"] if "submit will be REFUSED" in f), None)
        self.assertIsNotNone(flag, out["risk_flags"])
        self.assertIn("Enter the Bank Guarantee Number", flag)

