class TestAssetMovementGovernedRoundTrip(unittest.TestCase):
    """One full plan->submit, plan->cancel, and amend round trip, plus the cascade node_meta
    closure — the mechanical-wiring proof for the thirty-fifth doctype. The semantic divergences
    (the uncallable preview, the write-mechanism disclosure, the Datetime projection) live in
    their own dedicated test classes below, not here. Company IS pinned normally (unlike Bank
    Guarantee/Asset Maintenance Log — Asset Movement is not companyless), so the default REG
    (company="Example Corp") governs it directly, no REG_UNPINNED needed."""

    def test_plan_submit_records_the_doctype_and_projects_transaction_date(self):
        broker, client, stores = make_broker()
        out = broker.dispatch("plan_submit",
                              {"name": "AM-1", "pacioli_doctype": "Asset Movement"})
        self.assertTrue(out["ok"], out)
        self.assertEqual(out["doctype"], "Asset Movement")
        self.assertEqual(out["posting_date"], "2026-07-01")  # projected from the Datetime value
        self.assertEqual(client.lock_calls[-1], ("Example Corp", ASSET_MOVEMENT, "2026-07-01"))
        stored = stores("prod").get_plan(out["plan_id"])
        self.assertEqual(stored.doctype, "Asset Movement")
        self.assertEqual(stored.docname, "AM-1")

    def test_full_governed_submit_flow(self):
        broker, client, stores = make_broker()
        plan = broker.dispatch("plan_submit",
                               {"name": "AM-1", "pacioli_doctype": "Asset Movement"})
        self.assertTrue(plan["ok"], plan)
        token = "am-raw-token"
        stores("prod").mint_marker(token, plan["plan_id"], expires_at=2_000.0)
        out = broker.dispatch("submit_asset_movement",
                              {"name": "AM-1", "plan_id": plan["plan_id"], "marker": token})
        self.assertTrue(out["ok"], out)
        self.assertEqual(out["result"]["docstatus"], 1)
        self.assertEqual(out["result"]["doctype"], "Asset Movement")
        self.assertEqual(client.submitted, ["AM-1"])
        store = stores("prod")
        self.assertEqual(store.marker_state(token), "consumed")
        self.assertEqual(store.orphans(), [])

    def test_plan_submit_refuses_non_draft(self):
        broker, client, _ = make_broker()
        client.docs["AM-1"]["docstatus"] = 1
        out = broker.dispatch("plan_submit",
                              {"name": "AM-1", "pacioli_doctype": "Asset Movement"})
        self.assertFalse(out["ok"])
        self.assertIn("draft", out["reason"].lower())

    def test_full_governed_cancel_flow(self):
        broker, client, stores = make_broker()
        plan = broker.dispatch("plan_cancel",
                               {"name": "AM-9", "pacioli_doctype": "Asset Movement"})
        self.assertTrue(plan["ok"], plan)
        self.assertEqual(plan["doctype"], "Asset Movement")
        self.assertIn((ASSET_MOVEMENT, "AM-9"), client.gl_calls)
        token = "am-cancel-token"
        stores("prod").mint_marker(token, plan["plan_id"], expires_at=2_000.0)
        out = broker.dispatch("cancel_asset_movement",
                              {"name": "AM-9", "plan_id": plan["plan_id"], "marker": token})
        self.assertTrue(out["ok"], out)
        self.assertEqual(out["result"]["docstatus"], 2)
        self.assertEqual(client.cancelled, ["AM-9"])
        self.assertEqual(stores("prod").marker_state(token), "consumed")

    def test_amend_creates_the_draft_with_receipts_and_no_marker(self):
        broker, client, stores = make_broker()
        client.docs["AM-9"]["docstatus"] = 2
        out = broker.dispatch("amend_asset_movement", {"name": "AM-9"})
        self.assertTrue(out["ok"], out)
        self.assertEqual(out["result"]["name"], "AM-9-1")
        self.assertEqual(out["result"]["docstatus"], 0)
        self.assertEqual(out["result"]["doctype"], "Asset Movement")
        self.assertEqual(client.amended, ["AM-9"])
        store = stores("prod")
        receipts = store.receipts()
        self.assertEqual([r.kind for r in receipts], ["intent", "outcome"])
        self.assertEqual(receipts[0].body["doctype"], "Asset Movement")
        self.assertEqual(store.orphans(), [])

    def test_amend_refuses_an_uncancelled_source(self):
        broker, client, _ = make_broker()
        out = broker.dispatch("amend_asset_movement", {"name": "AM-1"})  # a draft
        self.assertFalse(out["ok"])
        self.assertIn("cancelled", out["reason"])

    def test_cascade_node_meta_projects_transaction_date_and_reads_company_for_an_am_node(self):
        # Same shared closure every prior doctype's own cascade test pins — cascade.py itself is
        # untouched (fully doctype-blind), and _cascade_node_meta uses get_gl_entries (a safe
        # read, never ledger_preview) for every doctype including Asset Movement, so no
        # special-casing is needed here even though plan_submit's own preview call IS
        # special-cased in TestAssetMovementLedgerPreviewSkipped below. posting_date is the
        # PROJECTED date part (the same Datetime handling plan_submit itself uses).
        broker, client, _ = make_broker()
        node_meta = broker._cascade_node_meta(client)
        meta = node_meta(ASSET_MOVEMENT, "AM-1")
        self.assertEqual(meta["posting_date"], "2026-07-01")
        self.assertEqual(meta["company"], "Example Corp")


