class TestAssetMovementWriteRiskFlags(unittest.TestCase):
    """THE central finding of this landing: on_submit and on_cancel call the EXACT SAME method
    (set_latest_location_and_custodian_in_asset) — disclosed by ONE function shared across both
    directions (_asset_movement_write_risk_flags, the _pos_risk_flags "op" shape). See that
    function's own docstring (tools.py) for the full source-cited finding, including the
    frappe.db.set_value bypass grade and the cancel-direction asymmetric-clear disclosure."""

    def test_submit_names_the_single_referenced_asset_and_the_write_mechanism(self):
        broker, client, _ = make_broker()
        out = broker.dispatch("plan_submit",
                              {"name": "AM-1", "pacioli_doctype": "Asset Movement"})
        self.assertTrue(out["ok"], out)
        flag = next((f for f in out["risk_flags"] if "submitting this Asset Movement" in f), None)
        self.assertIsNotNone(flag, out["risk_flags"])
        self.assertIn("AST-0001", flag)
        self.assertIn("frappe.db.set_value", flag)
        self.assertIn("1 referenced Asset", flag)
        # Submit direction carries no asymmetric-clear prose — that is cancel-only.
        self.assertFalse(any("is NOT cleared" in f for f in out["risk_flags"]))

    def test_submit_names_every_referenced_asset_not_just_the_first(self):
        # A single Asset Movement can reference more than one asset — one write per row
        # (asset_movement.py's own loop over self.assets, not a break-after-first).
        broker, client, _ = make_broker()
        client.docs["AM-1"]["assets"] = [
            {"asset": "AST-0001", "target_location": "Warehouse B"},
            {"asset": "AST-0002", "target_location": "Warehouse B"}]
        out = broker.dispatch("plan_submit",
                              {"name": "AM-1", "pacioli_doctype": "Asset Movement"})
        self.assertTrue(out["ok"], out)
        flag = next((f for f in out["risk_flags"] if "submitting this Asset Movement" in f), None)
        self.assertIsNotNone(flag, out["risk_flags"])
        self.assertIn("AST-0001", flag)
        self.assertIn("AST-0002", flag)
        self.assertIn("2 referenced Asset", flag)

    def test_flag_absent_when_the_assets_child_table_is_empty(self):
        # Defensive: the real schema declares "assets" reqd=1 so this never happens on a genuine
        # bench document, but the flag function degrades gracefully rather than crashing.
        broker, client, _ = make_broker()
        client.docs["AM-1"]["assets"] = []
        out = broker.dispatch("plan_submit",
                              {"name": "AM-1", "pacioli_doctype": "Asset Movement"})
        self.assertTrue(out["ok"], out)
        self.assertFalse(any("submitting this Asset Movement" in f for f in out["risk_flags"]))

    def test_cancel_names_both_referenced_assets_and_the_write_mechanism(self):
        broker, client, _ = make_broker()
        out = broker.dispatch("plan_cancel",
                              {"name": "AM-9", "pacioli_doctype": "Asset Movement"})
        self.assertTrue(out["ok"], out)
        flag = next((f for f in out["risk_flags"] if "cancelling this Asset Movement" in f), None)
        self.assertIsNotNone(flag, out["risk_flags"])
        self.assertIn("AST-0001", flag)
        self.assertIn("AST-0002", flag)
        self.assertIn("frappe.db.set_value", flag)
        self.assertIn("2 referenced Asset", flag)

    def test_cancel_always_discloses_the_asymmetric_clear_in_prose(self):
        # Unconditional: no sibling read this plan can perform would let it predict which case a
        # REAL cancel resolves to, only that the asymmetry exists (the Maintenance Visit
        # check_if_last_visit precedent) — this is the dossier's own §7 correction, made loud.
        broker, client, _ = make_broker()
        out = broker.dispatch("plan_cancel",
                              {"name": "AM-9", "pacioli_doctype": "Asset Movement"})
        self.assertTrue(out["ok"], out)
        flag = next((f for f in out["risk_flags"] if "is NOT cleared" in f), None)
