class TestDeliveryTripGovernedRoundTrip(unittest.TestCase):
    """One full plan->submit, plan->cancel, and amend round trip, plus the cascade node_meta
    closure — the mechanical-wiring proof for the thirty-sixth doctype. The semantic divergences
    (the uncallable preview, the risk-flag findings, the Datetime projection, the cascade
    collision) live in their own dedicated test classes below, not here. Company IS pinned
    normally (Delivery Trip is not companyless), so the default REG (company="Example Corp")
    governs it directly. DT-1's own delivery_stops name DN-1 (a draft) and DT-9's name DN-9/DN-8
    — both real fixtures — but client.linked stays the honest empty default here (the SUBMITTED-
    blast-radius/cascade-collision tests live in their own classes below, not this one)."""

    def test_plan_submit_records_the_doctype_and_projects_departure_time(self):
        broker, client, stores = make_broker()
        out = broker.dispatch("plan_submit",
                              {"name": "DT-1", "pacioli_doctype": "Delivery Trip"})
        self.assertTrue(out["ok"], out)
        self.assertEqual(out["doctype"], "Delivery Trip")
        self.assertEqual(out["posting_date"], "2026-07-01")  # projected from the Datetime value
        self.assertEqual(client.lock_calls[-1], ("Example Corp", DELIVERY_TRIP, "2026-07-01"))
        stored = stores("prod").get_plan(out["plan_id"])
        self.assertEqual(stored.doctype, "Delivery Trip")
        self.assertEqual(stored.docname, "DT-1")

    def test_full_governed_submit_flow(self):
        broker, client, stores = make_broker()
        plan = broker.dispatch("plan_submit",
                               {"name": "DT-1", "pacioli_doctype": "Delivery Trip"})
        self.assertTrue(plan["ok"], plan)
        token = "dt-raw-token"
        stores("prod").mint_marker(token, plan["plan_id"], expires_at=2_000.0)
        out = broker.dispatch("submit_delivery_trip",
                              {"name": "DT-1", "plan_id": plan["plan_id"], "marker": token})
        self.assertTrue(out["ok"], out)
        self.assertEqual(out["result"]["docstatus"], 1)
        self.assertEqual(out["result"]["doctype"], "Delivery Trip")
        self.assertEqual(client.submitted, ["DT-1"])
        store = stores("prod")
        self.assertEqual(store.marker_state(token), "consumed")
        self.assertEqual(store.orphans(), [])

    def test_plan_submit_refuses_non_draft(self):
        broker, client, _ = make_broker()
        client.docs["DT-1"]["docstatus"] = 1
        out = broker.dispatch("plan_submit",
                              {"name": "DT-1", "pacioli_doctype": "Delivery Trip"})
        self.assertFalse(out["ok"])
        self.assertIn("draft", out["reason"].lower())

    def test_full_governed_cancel_flow(self):
        broker, client, stores = make_broker()
        plan = broker.dispatch("plan_cancel",
                               {"name": "DT-9", "pacioli_doctype": "Delivery Trip"})
        self.assertTrue(plan["ok"], plan)
        self.assertEqual(plan["doctype"], "Delivery Trip")
        self.assertIn((DELIVERY_TRIP, "DT-9"), client.gl_calls)
        token = "dt-cancel-token"
        stores("prod").mint_marker(token, plan["plan_id"], expires_at=2_000.0)
        out = broker.dispatch("cancel_delivery_trip",
                              {"name": "DT-9", "plan_id": plan["plan_id"], "marker": token})
        self.assertTrue(out["ok"], out)
        self.assertEqual(out["result"]["docstatus"], 2)
        self.assertEqual(client.cancelled, ["DT-9"])
        self.assertEqual(stores("prod").marker_state(token), "consumed")

    def test_amend_creates_the_draft_with_receipts_and_no_marker(self):
        broker, client, stores = make_broker()
        client.docs["DT-9"]["docstatus"] = 2
        out = broker.dispatch("amend_delivery_trip", {"name": "DT-9"})
        self.assertTrue(out["ok"], out)
        self.assertEqual(out["result"]["name"], "DT-9-1")
        self.assertEqual(out["result"]["docstatus"], 0)
        self.assertEqual(out["result"]["doctype"], "Delivery Trip")
        self.assertEqual(client.amended, ["DT-9"])
        store = stores("prod")
        receipts = store.receipts()
        self.assertEqual([r.kind for r in receipts], ["intent", "outcome"])
        self.assertEqual(receipts[0].body["doctype"], "Delivery Trip")
        self.assertEqual(store.orphans(), [])

    def test_amend_refuses_an_uncancelled_source(self):
        broker, client, _ = make_broker()
        out = broker.dispatch("amend_delivery_trip", {"name": "DT-1"})  # a draft
        self.assertFalse(out["ok"])
        self.assertIn("cancelled", out["reason"])

    def test_cascade_node_meta_projects_departure_time_and_reads_company_for_a_dt_node(self):
        # Same shared closure every prior doctype's own cascade test pins — cascade.py itself is
        # untouched (fully doctype-blind), and _cascade_node_meta uses get_gl_entries (a safe
        # read, never ledger_preview) for every doctype including Delivery Trip.
        broker, client, _ = make_broker()
        node_meta = broker._cascade_node_meta(client)
        meta = node_meta(DELIVERY_TRIP, "DT-1")
        self.assertEqual(meta["posting_date"], "2026-07-01")
        self.assertEqual(meta["company"], "Example Corp")


