class TestDeliveryTripSubmitCancelRiskFlags(unittest.TestCase):
    """THE genuine risk-flag findings of this landing, both fully data-driven off the draft's own
    delivery_stops rows. See _delivery_trip_submit_risk_flags/_delivery_trip_cancel_risk_flags's
    own docstrings (tools.py) for the full source-cited finding, including the honesty-grade
    placement (the SANCTIONED update_after_submit save path, not a bypass) and the CORRECTED
    (2026-07-21, supervisor-verified) structural finding: the cascade collision lands on the
    dependent Delivery Note's own cascade step (frappe's LinkExistsError), never on this Delivery
    Trip's own cancel step (which natively self-unlinks and succeeds as a leaf) — proven end to
    end in TestDeliveryTripCascadeCollision below."""

    def test_submit_is_doomed_when_no_driver_is_set(self):
        broker, client, _ = make_broker()
        client.docs["DT-1"]["driver"] = None
        out = broker.dispatch("plan_submit",
                              {"name": "DT-1", "pacioli_doctype": "Delivery Trip"})
        self.assertTrue(out["ok"], out)  # the plan still records; only submit itself is doomed
        flag = next((f for f in out["risk_flags"] if "submit will be REFUSED" in f), None)
        self.assertIsNotNone(flag, out["risk_flags"])
        self.assertIn("driver", flag)

    def test_submit_not_doomed_when_driver_is_set_but_names_the_linked_draft_note(self):
        broker, client, _ = make_broker()
        out = broker.dispatch("plan_submit",
                              {"name": "DT-1", "pacioli_doctype": "Delivery Trip"})
        self.assertTrue(out["ok"], out)
        self.assertFalse(any("submit will be REFUSED" in f for f in out["risk_flags"]))
        flag = next((f for f in out["risk_flags"] if "submit will ALSO be refused" in f), None)
        self.assertIsNotNone(flag, out["risk_flags"])
        self.assertIn("DN-1", flag)
        self.assertIn("validate_delivery_note_not_draft", flag)

    def test_submit_flag_absent_when_delivery_stops_names_no_notes(self):
        broker, client, _ = make_broker()
        client.docs["DT-1"]["delivery_stops"] = [{"delivery_note": None, "address": "ADDR-1"}]
        out = broker.dispatch("plan_submit",
                              {"name": "DT-1", "pacioli_doctype": "Delivery Trip"})
        self.assertTrue(out["ok"], out)
        self.assertFalse(any("submit will ALSO be refused" in f for f in out["risk_flags"]))

    def test_cancel_names_both_linked_delivery_notes_and_the_sanctioned_save_mechanism(self):
        broker, client, _ = make_broker()
        out = broker.dispatch("plan_cancel",
                              {"name": "DT-9", "pacioli_doctype": "Delivery Trip"})
        self.assertTrue(out["ok"], out)
        flag = next((f for f in out["risk_flags"] if "force-clear" in f), None)
        self.assertIsNotNone(flag, out["risk_flags"])
        self.assertIn("DN-9", flag)
        self.assertIn("DN-8", flag)
        self.assertIn("ignore_validate_update_after_submit", flag)
        self.assertIn("SANCTIONED", flag)
        self.assertIn("never a db_update/db_set/raw-SQL bypass", flag)

    def test_cancel_discloses_the_first_lock_the_cascade_fails_at_the_note_step(self):
        # THE CORRECTED sharpest finding (supervisor-verified 2026-07-21): unconditional whenever
        # delivery_stops names a note, the same "no sibling read this plan can perform would let
        # it predict the outcome" shape Asset Movement's own asymmetric-clear disclosure carries.
        # The collision is real but lands on the DEPENDENT Delivery Note's own cascade step —
        # frappe's own check_if_doc_is_linked(method="Cancel") walks child-table Link fields too
        # (Delivery Stop.delivery_note, istable=1), and Delivery Note's own on_cancel exemption
        # tuple (delivery_note.py:500-505) does not cover Delivery Trip — never on this Delivery
        # Trip's own cancel step, which natively self-unlinks and succeeds as a leaf.
        broker, client, _ = make_broker()
        out = broker.dispatch("plan_cancel",
                              {"name": "DT-9", "pacioli_doctype": "Delivery Trip"})
        self.assertTrue(out["ok"], out)
        flag = next((f for f in out["risk_flags"]
                    if "STRUCTURAL RISK" in f and "NOTE STEP" in f), None)
        self.assertIsNotNone(flag, out["risk_flags"])
        self.assertIn("LinkExistsError", flag)
        self.assertIn("plan_cascade_cancel", flag)
        self.assertIn("DN-9", flag)

    def test_cancel_discloses_the_second_lock_the_hypothetical_trip_step_raise(self):
        # Relabeled from the original landing's claim (now proven unreachable — the note step
        # above fails first, always, per the correction) to what it actually is: a second, weaker
        # lock that would ALSO fire if the note step were somehow already past.
        broker, client, _ = make_broker()
        out = broker.dispatch("plan_cancel",
                              {"name": "DT-9", "pacioli_doctype": "Delivery Trip"})
        self.assertTrue(out["ok"], out)
        flag = next((f for f in out["risk_flags"] if "SECOND LOCK" in f), None)
        self.assertIsNotNone(flag, out["risk_flags"])
        self.assertIn("ValidationError", flag)
        self.assertIn("Cannot edit cancelled document", flag)

    def test_cancel_discloses_the_ruled_leaf_exception_and_the_unchanged_cascade_death(self):
        # RULED 2026-07-21 (John's ruling 1): the leaf plan_cancel is now ALLOWED (option (a),
        # belted) — pinned here — while plan_cascade_cancel stays the ONE structurally dead path
        # for this pair (option (b) was NOT taken) — pinned on the cascade graph below.
        broker, client, _ = make_broker()
        leaf = broker.dispatch("plan_cancel",
                               {"name": "DT-9", "pacioli_doctype": "Delivery Trip"})
        self.assertTrue(leaf["ok"], leaf)
        leaf_flag = next((f for f in leaf["risk_flags"] if "LEAF CANCEL ALLOWED" in f), None)
        self.assertIsNotNone(leaf_flag, leaf["risk_flags"])
        self.assertIn("John's ruling 1", leaf_flag)
        self.assertIn("self_unlink_readback", leaf_flag)
        self.assertFalse(any("open design decision for John" in f for f in leaf["risk_flags"]))
        self.assertFalse(any("NO WORKING CANCEL PATH" in f for f in leaf["risk_flags"]))

        cc = CascadeClient({("Delivery Trip", "DT-9"):
                                [{"doctype": "Delivery Note", "docname": "DN-9"}],
                            ("Delivery Note", "DN-9"): []})
        broker2, _, _ = make_broker(client=cc)
        plan = broker2.dispatch("plan_cascade_cancel",
                                {"name": "DT-9", "pacioli_doctype": "Delivery Trip"})
        self.assertTrue(plan["ok"], plan)
        cascade_flag = next((f for f in plan["risk_flags"]
                             if f.startswith("DT-9: ") and "LEAF CANCEL ALLOWED" in f), None)
        self.assertIsNotNone(cascade_flag, plan["risk_flags"])
        self.assertIn("structurally dead", cascade_flag)
        # The cascade's own structural-death disclosure (the note-step LinkExistsError) is
        # unchanged — still present, still keyed to the target docname.
        structural_flag = next((f for f in plan["risk_flags"]
                                if f.startswith("DT-9: ") and "STRUCTURAL RISK" in f
                                and "NOTE STEP" in f), None)
        self.assertIsNotNone(structural_flag, plan["risk_flags"])

