class TestDeliveryTripSelfUnlinkReadback(unittest.TestCase):
    """THE SUSPENDERS (John's ruling 1, 2026-07-21,
    docs/plans/2026-07-21-cancel-truth-rulings.md): a post-execute readback
    (_delivery_trip_self_unlink_readback, wired into PacioliBroker._governed_write) that re-reads
    every Delivery Note the pre-cancel draft's own delivery_stops named and attests the
    self-unlink actually happened. Three outcome cases, each pinned on its own: clean (every
    note's own delivery_trip field no longer names the cancelled trip), still-linked (a note is
    REPORTED, never silently passed — the cancel already happened, so this is truth-telling,
    never a retro-refusal), and readback_error (a bench read failure is caught and named, never
    swallowed, never flipping the cancel's own already-landed success). Uses the FULL governed
    cancel round trip (plan -> mint -> cancel_delivery_trip), the same shape
    TestDeliveryTripGovernedRoundTrip's own test_full_governed_cancel_flow uses, because the
    readback is wired into the execute path, not the plan path."""

    def _mint_and_cancel(self, broker, stores, name="DT-9", token="dt-readback-token"):
        plan = broker.dispatch("plan_cancel", {"name": name, "pacioli_doctype": "Delivery Trip"})
        self.assertTrue(plan["ok"], plan)
        stores("prod").mint_marker(token, plan["plan_id"], expires_at=2_000.0)
        return broker.dispatch("cancel_delivery_trip",
                               {"name": name, "plan_id": plan["plan_id"], "marker": token})

    def test_clean_case_the_note_reports_unlinked(self):
        broker, client, stores = make_broker()
        client.docs["DT-9"]["delivery_stops"] = [{"delivery_note": "DN-9", "address": "ADDR-2"}]
        client.docs["DN-9"]["delivery_trip"] = None  # simulates ERPNext's own post-cancel state
        out = self._mint_and_cancel(broker, stores)
        self.assertTrue(out["ok"], out)
        self.assertEqual(out["result"]["docstatus"], 2)
        self.assertEqual(out["result"]["self_unlink_readback"],
                         {"checked": 1, "clean": 1, "still_linked": []})

    def test_still_linked_case_is_reported_never_silently_passed(self):
        broker, client, stores = make_broker()
        client.docs["DT-9"]["delivery_stops"] = [{"delivery_note": "DN-9", "address": "ADDR-2"},
                                                  {"delivery_note": "DN-8", "address": "ADDR-3"}]
        client.docs["DN-8"] = {"name": "DN-8", "docstatus": 1, "company": "Example Corp",
                               "customer": "Cust A", "status": "To Bill",
                               "posting_date": "2026-06-15", "grand_total": 250.0,
                               "delivery_trip": "DT-9",  # still linked — NOT cleared
                               "modified": "2026-06-15 09:00:00.000001"}
        client.docs["DN-9"]["delivery_trip"] = None  # this one WAS cleared correctly
        out = self._mint_and_cancel(broker, stores)
        self.assertTrue(out["ok"], out)  # the cancel already landed — never a retro-refusal
        readback = out["result"]["self_unlink_readback"]
        self.assertEqual(readback["checked"], 2)
        self.assertEqual(readback["clean"], 1)
        self.assertEqual(readback["still_linked"], ["DN-8"])
        self.assertNotIn("readback_error", readback)

    def test_bench_read_failure_is_readback_error_never_swallowed_never_flips_success(self):
        broker, client, stores = make_broker()
        client.docs["DT-9"]["delivery_stops"] = [{"delivery_note": "DN-9", "address": "ADDR-2"}]
        client.readback_fails = "DN-9"
        out = self._mint_and_cancel(broker, stores)
        self.assertTrue(out["ok"], out)  # a readback-side failure never flips the cancel success
        self.assertEqual(out["result"]["docstatus"], 2)
        self.assertEqual(client.cancelled, ["DT-9"])  # the cancel itself genuinely landed
        readback = out["result"]["self_unlink_readback"]
        self.assertEqual(readback["checked"], 0)
        self.assertEqual(readback["clean"], 0)
        self.assertEqual(readback["still_linked"], [])
        self.assertEqual(len(readback["readback_error"]), 1)
        self.assertEqual(readback["readback_error"][0]["delivery_note"], "DN-9")
        self.assertIn("bench hiccup", readback["readback_error"][0]["error"])

    def test_no_notes_named_reads_back_an_honest_zero_checklist(self):
        broker, client, stores = make_broker()
        client.docs["DT-9"]["delivery_stops"] = []
        out = self._mint_and_cancel(broker, stores)
        self.assertTrue(out["ok"], out)
        self.assertEqual(out["result"]["self_unlink_readback"],
                         {"checked": 0, "clean": 0, "still_linked": []})

    def test_readback_absent_for_unregistered_doctypes(self):
        broker, client, stores = make_broker()
        plan = broker.dispatch("plan_cancel", {"name": "SI-9", "pacioli_doctype": "Sales Invoice"})
        self.assertTrue(plan["ok"], plan)
        token = "si-cancel-readback-token"
        stores("prod").mint_marker(token, plan["plan_id"], expires_at=2_000.0)
        out = broker.dispatch("cancel_sales_invoice",
                              {"name": "SI-9", "plan_id": plan["plan_id"], "marker": token})
        self.assertTrue(out["ok"], out)
        self.assertNotIn("self_unlink_readback", out["result"])

    def test_readback_absent_on_submit(self):
        broker, client, stores = make_broker()
        plan = broker.dispatch("plan_submit",
                               {"name": "DT-1", "pacioli_doctype": "Delivery Trip"})
        self.assertTrue(plan["ok"], plan)
        token = "dt-submit-readback-token"
        stores("prod").mint_marker(token, plan["plan_id"], expires_at=2_000.0)
        out = broker.dispatch("submit_delivery_trip",
                              {"name": "DT-1", "plan_id": plan["plan_id"], "marker": token})
        self.assertTrue(out["ok"], out)
        self.assertNotIn("self_unlink_readback", out["result"])


class TestDeliveryTripCascadeCollision(unittest.TestCase):
    """THE sharpest finding of this landing, CORRECTED 2026-07-21 by supervisor verification and
    proven end to end with a REAL two-node cascade graph (CascadeClient, the same machinery
    TestCascadeCancel uses) rather than approximated: Delivery Note DN-9 is a genuine dependent of
    Delivery Trip DT-9 (both real fixtures), so plan_cascade_cancel orders DN-9 before DT-9 —
    exactly the order that guarantees the cascade fails AT THE NOTE STEP with frappe's own
    LinkExistsError (check_if_doc_is_linked walking Delivery Stop's own child-table delivery_note
    Link), never reaching this Delivery Trip's own cancel step at all — see
    _delivery_trip_cancel_risk_flags's own docstring for the full receipts.

    RULED 2026-07-21 — John's ruling 1: this cascade-path finding is UNCHANGED by the ruling
    (option (b), a cascade-order reorder, was NOT taken) — plan_cascade_cancel remains the ONE
    structurally dead path for this pair; the leaf plan_cancel is the ruled, working path
    (TestDeliveryTripBlastRadiusForDeliveryNote/TestDeliveryTripSubmitCancelRiskFlags above)."""

    def test_cascade_graph_orders_the_note_before_the_trip_and_discloses_the_note_step_collision(
            self):
        cc = CascadeClient({("Delivery Trip", "DT-9"):
                                [{"doctype": "Delivery Note", "docname": "DN-9"}],
                            ("Delivery Note", "DN-9"): []})
        broker, client, store_provider = make_broker(client=cc)
        plan = broker.dispatch("plan_cascade_cancel",
                               {"name": "DT-9", "pacioli_doctype": "Delivery Trip"})
        self.assertTrue(plan["ok"], plan)
        self.assertEqual([n["docname"] for n in plan["graph"]], ["DN-9", "DT-9"])
        self.assertEqual(plan["graph"][0]["coverage"], "modeled")  # Delivery Note IS modeled
        self.assertEqual(plan["graph"][1]["coverage"], "modeled")  # Delivery Trip IS modeled
        flag = next((f for f in plan["risk_flags"]
                    if f.startswith("DT-9: ") and "STRUCTURAL RISK" in f
                    and "NOTE STEP" in f), None)
        self.assertIsNotNone(flag, plan["risk_flags"])
        self.assertIn("DN-9", flag)
        self.assertIn("LinkExistsError", flag)
        # The disclosure is keyed to the TARGET's own docname, never the dependent's.
        self.assertFalse(any(f.startswith("DN-9: ") and "STRUCTURAL RISK" in f
                             for f in plan["risk_flags"]))
        # The ruled-state disclosure still names the cascade path as structurally dead (option
        # (b) not taken), even though the leaf path now works (option (a), belted).
        ruled_flag = next((f for f in plan["risk_flags"]
                           if f.startswith("DT-9: ") and "LEAF CANCEL ALLOWED" in f), None)
        self.assertIsNotNone(ruled_flag, plan["risk_flags"])
        self.assertIn("structurally dead", ruled_flag)


class TestDeliveryTripDatetimeDateProjection(unittest.TestCase):
    """THE third Datetime-dated doctype this campaign has found (after Work Order and Asset
    Movement): departure_time carries a real time component ("2026-07-01 08:30:00") — the SAME
    _posting_date_of projection Work Order's own landing built (reused unchanged, never
    reinvented). Each test pins one consumer of the projected value, mirroring
    TestWorkOrderDatetimeDateProjection/TestAssetMovementDatetimeDateProjection's own shape
    exactly."""

    def test_plan_submit_stores_the_date_part_and_queries_locks_with_it(self):
        broker, client, stores = make_broker()
        out = broker.dispatch("plan_submit",
                              {"name": "DT-1", "pacioli_doctype": "Delivery Trip"})
        self.assertTrue(out["ok"], out)
        self.assertEqual(out["posting_date"], "2026-07-01")  # date part, never the raw datetime
        self.assertEqual(client.lock_calls[-1], ("Example Corp", DELIVERY_TRIP, "2026-07-01"))
        stored = stores("prod").get_plan(out["plan_id"])
        self.assertEqual(stored.posting_date, "2026-07-01")

    def test_plan_cancel_projects_a_different_dts_datetime_too(self):
        broker, client, _ = make_broker()
        out = broker.dispatch("plan_cancel",
                              {"name": "DT-9", "pacioli_doctype": "Delivery Trip"})
        self.assertTrue(out["ok"], out)
        self.assertEqual(out["posting_date"], "2026-06-15")
        self.assertEqual(client.lock_calls[-1], ("Example Corp", DELIVERY_TRIP, "2026-06-15"))

    def test_microsecond_datetime_projects_too(self):
        # The projection keys on the separator at index 10, indifferent to what follows it.
        broker, client, _ = make_broker()
        client.docs["DT-1"]["departure_time"] = "2026-07-01 08:30:00.123456"
        out = broker.dispatch("plan_submit",
                              {"name": "DT-1", "pacioli_doctype": "Delivery Trip"})
        self.assertTrue(out["ok"], out)
        self.assertEqual(out["posting_date"], "2026-07-01")

    def test_malformed_datetime_stays_refused_projection_is_never_repair(self):
        # A non-zero-padded date under the time part must NOT truncate into a plausible-looking
        # wrong date — the raw shape flows through untouched and the plan REFUSES at the
        # period-lock read (live-true reshape, 2026-07-22 — see the Work Order class's own
        # reshaped test; the fake now refuses non-ISO like the real client).
        broker, client, stores = make_broker()
        client.docs["DT-1"]["departure_time"] = "2026-7-1 08:30:00"
        plan = broker.dispatch("plan_submit",
                               {"name": "DT-1", "pacioli_doctype": "Delivery Trip"})
        self.assertFalse(plan["ok"])
        self.assertIn("not a valid ISO", plan["reason"])
        self.assertIn("2026-7-1 08:30:00", plan["reason"])  # raw shape, never a "repair"
        self.assertEqual(client.submitted, [])  # nothing went to the bench

    def test_empty_departure_time_refuses_at_the_plan_lock_read(self):
        # Delivery Trip DECLARES a date field — an empty read stays the unverifiable path, never
        # a drift into a dateless pass (live-true reshape, 2026-07-22).
        broker, client, stores = make_broker()
        client.docs["DT-1"]["departure_time"] = ""
        plan = broker.dispatch("plan_submit",
                               {"name": "DT-1", "pacioli_doctype": "Delivery Trip"})
        self.assertFalse(plan["ok"])
        self.assertIn("not a valid ISO", plan["reason"])
        self.assertEqual(client.submitted, [])  # nothing went to the bench


