class TestAssetValueAdjustmentGovernedRoundTrip(unittest.TestCase):
    """One full plan->submit, plan->cancel, and amend round trip — the mechanical-wiring proof
    for the thirty-seventh doctype. The semantic divergences (the uncallable preview, the sibling
    JE / permission-only-bypass findings, the cascade dependent-node relationship) live in their
    own dedicated test classes below, not here. AVA-2 carries a real company (not companyless);
    AVA-9/AVA-10 are the submitted fixtures for the cancel-direction tests."""

