class TestPaymentOrderGovernedRoundTrip(unittest.TestCase):
    """One full plan->submit, plan->cancel, and amend round trip — the mechanical-wiring proof
    for the thirty-eighth doctype. The semantic divergences (the uncallable preview, the raw
    write-mechanism findings, the non-leaf cascade shape) live in their own dedicated test
    classes below, not here. PMO-1/PMO-2 are drafts (Payment-Request-typed and Payment-Entry-typed
    respectively); PMO-9/PMO-10 are the submitted fixtures for the cancel-direction tests."""

    def test_plan_submit_records_the_doctype_and_the_date(self):
        broker, client, stores = make_broker()
        out = broker.dispatch("plan_submit",
                              {"name": "PMO-1", "pacioli_doctype": "Payment Order"})
        self.assertTrue(out["ok"], out)
        self.assertEqual(out["doctype"], "Payment Order")
        self.assertEqual(out["posting_date"], "2026-07-01")
        self.assertEqual(client.lock_calls[-1],
                         ("Example Corp", PAYMENT_ORDER, "2026-07-01"))
        stored = stores("prod").get_plan(out["plan_id"])
        self.assertEqual(stored.doctype, "Payment Order")
        self.assertEqual(stored.docname, "PMO-1")

    def test_full_governed_submit_flow(self):
        broker, client, stores = make_broker()
        plan = broker.dispatch("plan_submit",
                               {"name": "PMO-1", "pacioli_doctype": "Payment Order"})
        self.assertTrue(plan["ok"], plan)
        token = "po-raw-token"
        stores("prod").mint_marker(token, plan["plan_id"], expires_at=2_000.0)
        out = broker.dispatch("submit_payment_order",
                              {"name": "PMO-1", "plan_id": plan["plan_id"], "marker": token})
        self.assertTrue(out["ok"], out)
        self.assertEqual(out["result"]["docstatus"], 1)
        self.assertEqual(out["result"]["doctype"], "Payment Order")
        self.assertEqual(client.submitted, ["PMO-1"])
        store = stores("prod")
        self.assertEqual(store.marker_state(token), "consumed")
        self.assertEqual(store.orphans(), [])

    def test_plan_submit_refuses_non_draft(self):
        broker, client, _ = make_broker()
        client.docs["PMO-1"]["docstatus"] = 1
        out = broker.dispatch("plan_submit",
                              {"name": "PMO-1", "pacioli_doctype": "Payment Order"})
        self.assertFalse(out["ok"])
        self.assertIn("draft", out["reason"].lower())

    def test_full_governed_cancel_flow(self):
        broker, client, stores = make_broker()
        plan = broker.dispatch("plan_cancel",
                               {"name": "PMO-10", "pacioli_doctype": "Payment Order"})
        self.assertTrue(plan["ok"], plan)
        self.assertEqual(plan["doctype"], "Payment Order")
        self.assertIn((PAYMENT_ORDER, "PMO-10"), client.gl_calls)
        token = "po-cancel-token"
        stores("prod").mint_marker(token, plan["plan_id"], expires_at=2_000.0)
        out = broker.dispatch("cancel_payment_order",
                              {"name": "PMO-10", "plan_id": plan["plan_id"], "marker": token})
        self.assertTrue(out["ok"], out)
        self.assertEqual(out["result"]["docstatus"], 2)
        self.assertEqual(client.cancelled, ["PMO-10"])
        self.assertEqual(stores("prod").marker_state(token), "consumed")

    def test_amend_creates_the_draft_with_receipts_and_no_marker(self):
        broker, client, stores = make_broker()
        client.docs["PMO-9"]["docstatus"] = 2
        out = broker.dispatch("amend_payment_order", {"name": "PMO-9"})
        self.assertTrue(out["ok"], out)
        self.assertEqual(out["result"]["name"], "PMO-9-1")
        self.assertEqual(out["result"]["docstatus"], 0)
        self.assertEqual(out["result"]["doctype"], "Payment Order")
        self.assertEqual(client.amended, ["PMO-9"])
        store = stores("prod")
        receipts = store.receipts()
        self.assertEqual([r.kind for r in receipts], ["intent", "outcome"])
        self.assertEqual(receipts[0].body["doctype"], "Payment Order")
        self.assertEqual(store.orphans(), [])

    def test_amend_refuses_an_uncancelled_source(self):
        broker, client, _ = make_broker()
        out = broker.dispatch("amend_payment_order", {"name": "PMO-1"})  # a draft
        self.assertFalse(out["ok"])
        self.assertIn("cancelled", out["reason"])

    def test_cascade_node_meta_projects_the_date_and_reads_company_for_a_po_node(self):
        broker, client, _ = make_broker()
        node_meta = broker._cascade_node_meta(client)
        meta = node_meta(PAYMENT_ORDER, "PMO-2")
        self.assertEqual(meta["posting_date"], "2026-07-01")
        self.assertEqual(meta["company"], "Example Corp")


