class TestPaymentOrderIsNotALeaf(unittest.TestCase):
    """THE cascade finding, genuinely NOT a leaf — JOINING Delivery Trip (not the first Wave-5
    row on this side: Asset Movement/Asset Value Adjustment are the OTHER shape, leaves for their
    own target scans that appear as dependents inside someone ELSE's graph; Payment Order is a
    real TARGET with real dependents, the same side of the relationship Delivery Trip's own
    landing already established — here with THREE incoming edges rather than Delivery Trip's
    one). A full-tree grep of the entire v16 checkout for '"options": "Payment Order"'
    returns FOUR hits — this doctype's own self-referencing amended_from, plus Journal Entry's/
    Payment Entry's/Payment Request's own real, static, submittable payment_order Link.
    ERPNext's own get_submitted_linked_docs already walks this generically — zero
    doctype-specific cascade.py code needed — so a submitted Payment Entry (or JE, or Payment
    Request) referencing this Payment Order blocks its leaf cancel."""

    def test_cancelling_a_payment_order_with_a_linked_payment_entry_is_refused(self):
        broker, client, _ = make_broker()
        client.linked = [{"doctype": "Payment Entry", "name": "PE-9", "docstatus": 1}]
        out = broker.dispatch("plan_cancel",
                              {"name": "PMO-10", "pacioli_doctype": "Payment Order"})
        self.assertFalse(out["ok"])
        self.assertIn("Payment Entry", out["reason"])
        self.assertIn("PE-9", out["reason"])

    def test_plan_cancel_of_a_submitted_po_with_no_linked_document_is_never_blocked(self):
        broker, client, _ = make_broker()
        self.assertEqual(client.linked, [])  # the honest default — no fixture pretends otherwise
        out = broker.dispatch("plan_cancel",
                              {"name": "PMO-10", "pacioli_doctype": "Payment Order"})
        self.assertTrue(out["ok"], out)

    def test_cascade_plan_on_a_po_with_a_submitted_je_dependent_walks_it_first(self):
        # Uses CascadeClient (defined later in this module — a module-level name, resolved at
        # call time, so the forward reference is safe) rather than the plain FakeClient: its own
        # get_submitted_linked_docs is doctype/docname-KEYED, avoiding the flat client.linked
        # list's self-referential-recursion trap (a bare client.linked would answer the SAME
        # dependents for every node queried, including the JE's own recursive lookup).
        cc = CascadeClient({("Payment Order", "PMO-9"):
                                [{"doctype": "Journal Entry", "docname": "JE-PMO-9"}],
                            ("Journal Entry", "JE-PMO-9"): []})
        cc.docs["PMO-9"] = dict(FakeClient().docs["PMO-9"])
        cc.docs["JE-PMO-9"] = {"name": "JE-PMO-9", "docstatus": 1, "company": "Example Corp",
                              "voucher_type": "Journal Entry", "posting_date": "2026-06-15",
                              "total_debit": 100.0, "total_credit": 100.0, "accounts": [],
                              "payment_order": "PMO-9", "modified": "2026-06-15 09:00:00.000001"}
        broker, client, stores = make_broker(client=cc)
        out = broker.dispatch("plan_cascade_cancel",
                              {"name": "PMO-9", "pacioli_doctype": "Payment Order"})
        self.assertTrue(out["ok"], out)
        self.assertEqual(out["total"], 2)  # the JE dependent, then PMO-9 itself, last
        self.assertEqual(out["graph"][-1]["doctype"], "Payment Order")
        self.assertEqual(out["graph"][-1]["docname"], "PMO-9")
        write_flag = next((f for f in out["risk_flags"]
                           if f.startswith("PMO-9: ") and "frappe.db.set_value" in f), None)
        self.assertIsNotNone(write_flag, out["risk_flags"])  # per-node disclosure on the TARGET
        stored = stores("prod").get_plan(out["plan_id"])
        self.assertEqual(stored.docname, "PMO-9")


