class TestShareTransferGovernedRoundTrip(unittest.TestCase):
    """One full plan->submit, plan->cancel, and amend round trip — the mechanical-wiring proof
    for the thirty-ninth doctype. The semantic divergences (the uncallable preview, the doomed-
    submit finding, the isolated-leaf cascade shape) live in their own dedicated test classes
    below, not here. ST-4 is a clean Transfer-type draft (both shareholders/folio numbers
    populated — no doomed-submit branch fires); ST-9 is the submitted fixture for the
    cancel-direction/amend tests."""

    def test_plan_submit_records_the_doctype_and_the_date(self):
        broker, client, stores = make_broker()
        out = broker.dispatch("plan_submit",
                              {"name": "ST-4", "pacioli_doctype": "Share Transfer"})
        self.assertTrue(out["ok"], out)
        self.assertEqual(out["doctype"], "Share Transfer")
        self.assertEqual(out["posting_date"], "2026-07-01")
        self.assertEqual(client.lock_calls[-1],
                         ("Example Corp", SHARE_TRANSFER, "2026-07-01"))
        stored = stores("prod").get_plan(out["plan_id"])
        self.assertEqual(stored.doctype, "Share Transfer")
        self.assertEqual(stored.docname, "ST-4")

    def test_full_governed_submit_flow(self):
        broker, client, stores = make_broker()
        plan = broker.dispatch("plan_submit",
                               {"name": "ST-4", "pacioli_doctype": "Share Transfer"})
        self.assertTrue(plan["ok"], plan)
        token = "st-raw-token"
        stores("prod").mint_marker(token, plan["plan_id"], expires_at=2_000.0)
        out = broker.dispatch("submit_share_transfer",
                              {"name": "ST-4", "plan_id": plan["plan_id"], "marker": token})
        self.assertTrue(out["ok"], out)
        self.assertEqual(out["result"]["docstatus"], 1)
        self.assertEqual(out["result"]["doctype"], "Share Transfer")
        self.assertEqual(client.submitted, ["ST-4"])
        store = stores("prod")
        self.assertEqual(store.marker_state(token), "consumed")
        self.assertEqual(store.orphans(), [])

    def test_plan_submit_refuses_non_draft(self):
        broker, client, _ = make_broker()
        client.docs["ST-4"]["docstatus"] = 1
        out = broker.dispatch("plan_submit",
                              {"name": "ST-4", "pacioli_doctype": "Share Transfer"})
        self.assertFalse(out["ok"])
        self.assertIn("draft", out["reason"].lower())

    def test_full_governed_cancel_flow(self):
        broker, client, stores = make_broker()
        plan = broker.dispatch("plan_cancel",
                               {"name": "ST-9", "pacioli_doctype": "Share Transfer"})
        self.assertTrue(plan["ok"], plan)
        self.assertEqual(plan["doctype"], "Share Transfer")
        self.assertIn((SHARE_TRANSFER, "ST-9"), client.gl_calls)
        token = "st-cancel-token"
        stores("prod").mint_marker(token, plan["plan_id"], expires_at=2_000.0)
        out = broker.dispatch("cancel_share_transfer",
                              {"name": "ST-9", "plan_id": plan["plan_id"], "marker": token})
        self.assertTrue(out["ok"], out)
        self.assertEqual(out["result"]["docstatus"], 2)
        self.assertEqual(client.cancelled, ["ST-9"])
        self.assertEqual(stores("prod").marker_state(token), "consumed")

    def test_amend_creates_the_draft_with_receipts_and_no_marker(self):
        broker, client, stores = make_broker()
        client.docs["ST-9"]["docstatus"] = 2
        out = broker.dispatch("amend_share_transfer", {"name": "ST-9"})
        self.assertTrue(out["ok"], out)
        self.assertEqual(out["result"]["name"], "ST-9-1")
        self.assertEqual(out["result"]["docstatus"], 0)
        self.assertEqual(out["result"]["doctype"], "Share Transfer")
        self.assertEqual(client.amended, ["ST-9"])
        store = stores("prod")
        receipts = store.receipts()
        self.assertEqual([r.kind for r in receipts], ["intent", "outcome"])
        self.assertEqual(receipts[0].body["doctype"], "Share Transfer")
        self.assertEqual(store.orphans(), [])

    def test_amend_refuses_an_uncancelled_source(self):
        broker, client, _ = make_broker()
        out = broker.dispatch("amend_share_transfer", {"name": "ST-4"})  # a draft
        self.assertFalse(out["ok"])
        self.assertIn("cancelled", out["reason"])

    def test_cascade_node_meta_projects_the_date_and_reads_company_for_an_st_node(self):
        broker, client, _ = make_broker()
        node_meta = broker._cascade_node_meta(client)
        meta = node_meta(SHARE_TRANSFER, "ST-4")
        self.assertEqual(meta["posting_date"], "2026-07-01")
        self.assertEqual(meta["company"], "Example Corp")


class TestShareTransferLedgerPreviewSkipped(unittest.TestCase):
    """The ledger-preview finding, verified from the MRO rather than assumed: a bare
    ShareTransfer(Document), no make_gl_entries anywhere, so the real RPC would raise
    AttributeError on a live bench. Share Transfer posts no GL/Stock Ledger row of any kind,
    sibling or otherwise — its real side effects are share_balance/folio_no writes on Shareholder
    documents, disclosed separately (see TestShareTransferSubmitCancelRiskFlags below)."""

    def test_plan_submit_never_calls_the_native_preview(self):
        broker, client, _ = make_broker()
        preview_calls = []
        real_preview = client.ledger_preview
        client.ledger_preview = lambda **kw: preview_calls.append(kw) or real_preview(**kw)
        out = broker.dispatch("plan_submit",
                              {"name": "ST-4", "pacioli_doctype": "Share Transfer"})
        self.assertTrue(out["ok"], out)
        self.assertEqual(preview_calls, [])

    def test_plan_submit_projected_gl_is_empty_by_construction_with_the_disclosure_flag(self):
        broker, client, _ = make_broker()
        out = broker.dispatch("plan_submit",
                              {"name": "ST-4", "pacioli_doctype": "Share Transfer"})
        self.assertTrue(out["ok"], out)
        self.assertEqual(out["projected_gl"], [])
        flag = next((f for f in out["risk_flags"]
                    if "PROJECTED GL IS EMPTY BECAUSE THE PREVIEW COULD NOT RUN" in f), None)
        self.assertIsNotNone(flag, out["risk_flags"])
        self.assertIn("make_gl_entries", flag)
        self.assertIn("Share Transfer", flag)
        self.assertFalse(any("WRONG DOCUMENT" in f for f in out["risk_flags"]))

    def test_plan_cancel_needs_no_new_preview_flag_the_real_read_is_already_honest(self):
        broker, client, _ = make_broker()
        client.gl_rows = []
        out = broker.dispatch("plan_cancel",
                              {"name": "ST-9", "pacioli_doctype": "Share Transfer"})
        self.assertTrue(out["ok"], out)
        self.assertEqual(out["projected_reversal"], [])
        self.assertTrue(any("no live GL rows found" in f for f in out["risk_flags"]))
        self.assertFalse(any("PROJECTED GL IS EMPTY BECAUSE THE PREVIEW COULD NOT RUN" in f
                             for f in out["risk_flags"]))

    def test_other_doctypes_plan_submit_is_unaffected_by_the_share_transfer_branch(self):
        broker, client, _ = make_broker()
        out = broker.dispatch("plan_submit", {"name": "SI-1"})
        self.assertTrue(out["ok"], out)
        self.assertTrue(out["projected_gl"])
        self.assertFalse(any("PREVIEW COULD NOT RUN" in f for f in out["risk_flags"]))


class TestShareTransferCascadeLeaf(unittest.TestCase):
    """THE cascade finding: a full-tree grep of the entire v16 checkout for '"options": "Share
    Transfer"' returns exactly ONE hit — Share Transfer's own self-referencing amended_from
    (share_transfer.json:180). No other doctype anywhere carries a Link to Share Transfer. UNLIKE
    Asset Movement/Asset Value Adjustment (leaves for their own incoming edges, yet each still a
    dependent NODE inside Asset's own cascade graph via its own outgoing "asset" Link), Share
    Transfer's own outgoing Links (from_shareholder/to_shareholder -> Shareholder, share_type ->
    Share Type, asset_account/equity_or_liability_account -> Account, company -> Company) all
    point at non-submittable or non-transactional doctypes this broker's cascade mechanism never
    treats as a graph target — Share Transfer can never appear as a node in ANY cascade graph,
    its own or anyone else's. Rather than fabricate an external blast-radius scenario that cannot
    occur on a real bench, this class pins the true default: a submitted Share Transfer's own
    cancel is never refused by any linked document, because none exists."""

    def test_plan_cancel_of_a_submitted_st_is_never_blocked_by_a_linked_document(self):
        broker, client, _ = make_broker()
        self.assertEqual(client.linked, [])  # the honest default — no fixture pretends otherwise
        out = broker.dispatch("plan_cancel",
                              {"name": "ST-9", "pacioli_doctype": "Share Transfer"})
        self.assertTrue(out["ok"], out)

    def test_on_cancel_carries_zero_frappe_throw_calls_never_calls_validate(self):
        # share_transfer.py's on_cancel (lines 97-149) carries no frappe.throw of any kind — all
        # 11 throws in the class live inside validate()'s own call graph (basic_validations() +
        # folio_no_validation()), never on_cancel. Confirmed by a full grep.
        broker, client, _ = make_broker()
        out = broker.dispatch("plan_cancel",
                              {"name": "ST-9", "pacioli_doctype": "Share Transfer"})
        self.assertTrue(out["ok"], out)
        self.assertFalse(any("REFUSE" in f for f in out["risk_flags"]))


class TestShareTransferSubmitCancelRiskFlags(unittest.TestCase):
    """THE genuine risk-flag findings of this landing. See _share_transfer_submit_risk_flags's/
    _share_transfer_cancel_risk_flags's own docstrings (tools.py) for the full source-cited
    finding, including the doomed-submit gate beyond the pre-verification addendum's own scope."""

    def test_submit_discloses_the_doomed_purchase_gate_when_from_folio_no_is_blank(self):
        # ST-2: Purchase-type, from_shareholder populated, from_folio_no blank — THE sharpest
        # finding. basic_validations() checks from_folio_no but calls
        # autoname_folio(self.to_shareholder), and to_shareholder was already blanked to "" one
        # line earlier in this SAME branch — the resulting frappe.get_doc("Shareholder", None)
        # throws frappe.DoesNotExistError before any share_balance mutation runs.
        broker, client, _ = make_broker()
        out = broker.dispatch("plan_submit",
                              {"name": "ST-2", "pacioli_doctype": "Share Transfer"})
        self.assertTrue(out["ok"], out)  # PLAN still records — the refusal is at execute time
        flag = next((f for f in out["risk_flags"] if "will be REFUSED" in f), None)
        self.assertIsNotNone(flag, out["risk_flags"])
        self.assertIn("DoesNotExistError", flag)
        self.assertIn("to_shareholder", flag)
        self.assertIn("from_folio_no", flag)

    def test_submit_discloses_no_doomed_gate_when_purchase_from_folio_no_is_populated(self):
        # ST-3: same Purchase-type shape as ST-2, but from_folio_no IS populated — the clean,
        # non-doomed case; basic_validations()'s own blank-check never fires the buggy call.
        broker, client, _ = make_broker()
        out = broker.dispatch("plan_submit",
                              {"name": "ST-3", "pacioli_doctype": "Share Transfer"})
        self.assertTrue(out["ok"], out)
        self.assertFalse(any("will be REFUSED" in f for f in out["risk_flags"]))
        self.assertFalse(any("DoesNotExistError" in f for f in out["risk_flags"]))

    def test_submit_discloses_the_folio_assignment_when_issue_to_folio_no_is_blank(self):
        # ST-1: Issue-type, to_folio_no blank — the clean, correctly-implemented autoname_folio
        # branch (checks to_folio_no, calls autoname_folio on the REAL to_shareholder).
        broker, client, _ = make_broker()
        out = broker.dispatch("plan_submit",
                              {"name": "ST-1", "pacioli_doctype": "Share Transfer"})
        self.assertTrue(out["ok"], out)
