class TestBomCreatorLedgerPreviewSkipped(unittest.TestCase):
    """The ledger-preview finding, verified from the MRO rather than assumed: a bare
    BOMCreator(Document), no make_gl_entries anywhere, so the real RPC would raise AttributeError
    on a live bench. BOM Creator posts no GL/Stock Ledger row of any kind — its only products are
    BOM documents, built later by a background worker (see TestBomCreatorTwoPhaseProve below)."""

    def test_plan_submit_never_calls_the_native_preview(self):
        broker, client, _ = make_broker()
        preview_calls = []
        real_preview = client.ledger_preview
        client.ledger_preview = lambda **kw: preview_calls.append(kw) or real_preview(**kw)
        out = broker.dispatch("plan_submit",
                              {"name": "BC-1", "pacioli_doctype": "BOM Creator"})
        self.assertTrue(out["ok"], out)
        self.assertEqual(preview_calls, [])

    def test_plan_submit_projected_gl_is_empty_by_construction_with_the_disclosure_flag(self):
        broker, client, _ = make_broker()
        out = broker.dispatch("plan_submit",
                              {"name": "BC-1", "pacioli_doctype": "BOM Creator"})
        self.assertTrue(out["ok"], out)
        self.assertEqual(out["projected_gl"], [])
        flag = next((f for f in out["risk_flags"]
                    if "PROJECTED GL IS EMPTY BECAUSE THE PREVIEW COULD NOT RUN" in f), None)
        self.assertIsNotNone(flag, out["risk_flags"])
        self.assertIn("make_gl_entries", flag)
        self.assertIn("BOM Creator", flag)

    def test_other_doctypes_plan_submit_is_unaffected_by_the_bom_creator_branch(self):
        broker, client, _ = make_broker()
        out = broker.dispatch("plan_submit", {"name": "SI-1"})
