class TestBomCreatorNotACascadeLeaf(unittest.TestCase):
    """Unlike Share Transfer, BOM Creator is NOT a cascade leaf: the two-checkout grep for
    '"options": "BOM Creator"' finds one real incoming edge (BOM's own bom_creator Link). This
    class pins the consequence directly: once client.linked reports a submitted BOM (the fake's
    stand-in for the real blast-radius read), the standing leaf-cancel gate refuses exactly like
    it would for any other doctype — BOM Creator is deliberately NOT registered
    SELF_UNLINKING_DOCTYPES, unlike Delivery Trip."""

    def test_plan_cancel_refuses_when_a_built_bom_still_links_back(self):
        broker, client, _ = make_broker()
        client.linked = [{"doctype": "BOM", "name": "BOM-FROM-BC11-1"}]
        out = broker.dispatch("plan_cancel",
                              {"name": "BC-11", "pacioli_doctype": "BOM Creator"})
        self.assertFalse(out["ok"])
        self.assertIn("BOM-FROM-BC11-1", out["reason"])
        self.assertIn("plan_cascade_cancel", out["reason"])

    def test_plan_cancel_of_a_leaf_with_nothing_linked_is_never_blocked(self):
        broker, client, _ = make_broker()
        self.assertEqual(client.linked, [])
        out = broker.dispatch("plan_cancel",
                              {"name": "BC-9", "pacioli_doctype": "BOM Creator"})
        self.assertTrue(out["ok"], out)


