class TestBomCreatorTwoPhaseProve(unittest.TestCase):
    """John's ruling 2 (2026-07-21, docs/plans/2026-07-21-cancel-truth-rulings.md) — the two-phase
    PROVE machinery itself. Phase 1 (this class's first group): the governed submit narrows its
    OWN ledger outcome to "committed_pending_async" rather than a plain "committed", carrying a
    queued_consequence marker. Phase 2 (the second group): prove_verify's own sweep
    (_sweep_queued_consequences) resolves a terminal Completed/Failed result, or reports a still-
    running job pending, and is idempotent against a repeat sweep."""

    def _submit_bc1(self, broker, client, stores, *, status_at_submit="Submitted"):
        """Runs the governed submit of BC-1 (a clean draft), simulating the bench's own inline
        before_submit status flip (this fake has no real hook engine — the real bench flips
        `status` synchronously before this broker's submit response is built; the fixture is
        mutated here to model exactly that, never a random/unrelated value)."""
        client.docs["BC-1"]["status"] = status_at_submit
        plan = broker.dispatch("plan_submit",
                               {"name": "BC-1", "pacioli_doctype": "BOM Creator"})
        self.assertTrue(plan["ok"], plan)
        token = "bc1-token"
        stores("prod").mint_marker(token, plan["plan_id"], expires_at=2_000.0)
        out = broker.dispatch("submit_bom_creator",
                              {"name": "BC-1", "plan_id": plan["plan_id"], "marker": token})
        return out

    # --- Phase 1: the submit's own outcome ------------------------------------------------

    def test_submit_still_reports_ok_true_docstatus_really_did_transition(self):
        broker, client, stores = make_broker()
        out = self._submit_bc1(broker, client, stores)
        self.assertTrue(out["ok"], out)
        self.assertEqual(out["result"]["docstatus"], 1)
        self.assertEqual(client.submitted, ["BC-1"])

    def test_submit_result_carries_the_queued_consequence_marker(self):
        broker, client, stores = make_broker()
        out = self._submit_bc1(broker, client, stores)
        self.assertTrue(out["ok"], out)
        qc = out["result"]["queued_consequence"]
        self.assertEqual(qc["channel"], "bom_creator.create_boms")
        self.assertEqual(qc["queue"], "short")
        self.assertEqual(qc["status_at_submit"], "Submitted")

    def test_the_ledger_outcome_is_committed_pending_async_never_a_plain_committed(self):
        broker, client, stores = make_broker()
        self._submit_bc1(broker, client, stores)
        receipts = stores("prod").receipts()
        self.assertEqual([r.kind for r in receipts], ["intent", "outcome"])
        self.assertEqual(receipts[1].body["status"], "committed_pending_async")
        self.assertIn("queued_consequence", receipts[1].body["result"])

    def test_the_pending_submit_stays_an_open_orphan_until_resolved(self):
        # prove.orphans() only clears an intent on a LITERAL "committed" outcome — this is the
        # existing, UNMODIFIED sweep already surfacing a queued consequence as open, for free.
        broker, client, stores = make_broker()
        self._submit_bc1(broker, client, stores)
        store = stores("prod")
        orphans = store.orphans()
        self.assertEqual(len(orphans), 1)
        self.assertEqual(orphans[0].body["doctype"], "BOM Creator")

    def test_other_doctypes_submit_outcome_is_unaffected_plain_committed_still_means_committed(self):
        broker, client, stores = make_broker()
        plan = broker.dispatch("plan_submit", {"name": "SI-1"})
        self.assertTrue(plan["ok"], plan)
        token = "si-token"
        stores("prod").mint_marker(token, plan["plan_id"], expires_at=2_000.0)
        out = broker.dispatch("submit_sales_invoice",
                              {"name": "SI-1", "plan_id": plan["plan_id"], "marker": token})
        self.assertTrue(out["ok"], out)
        self.assertNotIn("queued_consequence", out["result"])
        receipts = stores("prod").receipts()
        self.assertEqual(receipts[1].body["status"], "committed")
        self.assertEqual(stores("prod").orphans(), [])

    # --- Phase 2: prove_verify's own sweep -------------------------------------------------

    def test_prove_verify_reports_a_still_running_job_as_pending_no_new_outcome(self):
        broker, client, stores = make_broker()
        self._submit_bc1(broker, client, stores)
        client.docs["BC-1"]["status"] = "In Progress"  # the worker started, hasn't finished
        out = broker.dispatch("prove_verify", {})
        self.assertTrue(out["ok"], out)
        pending = out["queued_consequences"]["pending"]
        self.assertEqual(len(pending), 1)
        self.assertEqual(pending[0]["docname"], "BC-1")
        self.assertEqual(pending[0]["status"], "In Progress")
        self.assertEqual(out["queued_consequences"]["resolved"], [])
        self.assertEqual(len(stores("prod").receipts()), 2)  # no third receipt was written
        self.assertEqual(len(stores("prod").orphans()), 1)  # still open

    def test_prove_verify_resolves_a_completed_job_with_the_real_built_bom_names(self):
        broker, client, stores = make_broker()
        self._submit_bc1(broker, client, stores)
        client.docs["BC-1"]["status"] = "Completed"
        client.docs["BOM-FROM-BC1-1"] = {"name": "BOM-FROM-BC1-1", "docstatus": 1,
                                         "bom_creator": "BC-1", "item": "WIDGET-100"}
        out = broker.dispatch("prove_verify", {})
        self.assertTrue(out["ok"], out)
        resolved = out["queued_consequences"]["resolved"]
        self.assertEqual(len(resolved), 1)
        self.assertEqual(resolved[0]["docname"], "BC-1")
        self.assertEqual(resolved[0]["status"], "committed")
        res = resolved[0]["queued_consequence_resolution"]
        self.assertEqual(res["built_boms"], ["BOM-FROM-BC1-1"])
        self.assertEqual(res["count"], 1)
        # a THIRD receipt now exists — the resolution outcome — and the intent is finalized.
        receipts = stores("prod").receipts()
        self.assertEqual(len(receipts), 3)
        self.assertEqual(receipts[2].body["status"], "committed")
        self.assertEqual(receipts[2].body["finalizes"], receipts[0].seq)
        self.assertEqual(stores("prod").orphans(), [])

    def test_prove_verify_resolves_a_failed_job_with_error_log_stays_an_orphan(self):
        # A "failed" resolution does NOT finalize the intent — the SAME deny-biased rule
        # spine.py's own docstring states for a genuinely failed submit (only "committed"
        # finalizes); a Failed BOM tree stays visible to prove_orphans forever until a human
        # actually looks at it, never silently clearing.
        broker, client, stores = make_broker()
        self._submit_bc1(broker, client, stores)
        client.docs["BC-1"]["status"] = "Failed"
        client.docs["BC-1"]["error_log"] = "Traceback: could not resolve item rate"
        out = broker.dispatch("prove_verify", {})
        self.assertTrue(out["ok"], out)
        resolved = out["queued_consequences"]["resolved"]
        self.assertEqual(len(resolved), 1)
        self.assertEqual(resolved[0]["status"], "failed")
        res = resolved[0]["queued_consequence_resolution"]
        self.assertEqual(res["error_log"], "Traceback: could not resolve item rate")
        self.assertEqual(res["built_boms"], [])
        self.assertEqual(len(stores("prod").orphans()), 1)  # still open — "failed" never finalizes

    def test_prove_verify_sweep_is_idempotent_never_re_resolves(self):
        broker, client, stores = make_broker()
        self._submit_bc1(broker, client, stores)
        client.docs["BC-1"]["status"] = "Completed"
        client.docs["BOM-FROM-BC1-1"] = {"name": "BOM-FROM-BC1-1", "docstatus": 1,
                                         "bom_creator": "BC-1", "item": "WIDGET-100"}
        first = broker.dispatch("prove_verify", {})
        self.assertEqual(len(first["queued_consequences"]["resolved"]), 1)
        second = broker.dispatch("prove_verify", {})
        self.assertEqual(second["queued_consequences"]["resolved"], [])
        self.assertEqual(second["queued_consequences"]["pending"], [])
        self.assertEqual(len(stores("prod").receipts()), 3)  # no fourth receipt

    def test_prove_verify_sweep_is_a_noop_when_nothing_is_pending(self):
        broker, client, _ = make_broker()
        out = broker.dispatch("prove_verify", {})
        self.assertTrue(out["ok"], out)
        self.assertEqual(out["queued_consequences"], {"pending": [], "resolved": []})

    def test_enqueue_on_submit_doctypes_contains_exactly_bom_creator(self):
        self.assertEqual(ENQUEUE_ON_SUBMIT_DOCTYPES, (BOM_CREATOR,))


# ============================================================================================
# BREADTH (Budget) — a full-attention landing off the pre-verification addendum
# (docs/plans/dossiers/budget.verify.md, 2026-07-21), the forty-first supported doctype.
# party_field=None — cost_center/project is a dual conditional pair gated on budget_against,
# spliced WHOLE. status/grand_total CONFIRMED ABSENT, no substitute (budget_amount carries no
# in_list_view flag). company IS present and reqd — NOT companyless. date_field=
# "budget_start_date" — THE CAMPAIGN'S FIRST HIDDEN date_field: hidden:1, schema-optional, but
# validate()-FORCED non-blank via the reqd from_fiscal_year Link on every persisted document.
# submit_via="run_method" — Budget defines zero submit/cancel/on_submit/on_cancel hooks of any
# kind, the SIXTH member of the "hookless at submit/cancel" family, but by far its richest
# (validate() spans 8 sub-validations plus a separate before_save()/on_update() pair). Ledger
# preview UNCALLABLE (bare Document, skip tuple 25th member). Cascade: a genuine LEAF (one hit
# across both checkouts, its own self-referencing amended_from). THE CONTROL-PLANE FINDING:
# submitting a Budget ARMS a belt governing FUTURE submits of OTHER documents (PO/MR through
# either enforcement engine, per Accounts Settings.use_legacy_budget_controller); cancelling
# DISARMS it immediately (both engines filter on docstatus == 1).
# ============================================================================================

