class TestTimesheetGovernedRoundTrip(unittest.TestCase):
    """One full plan->submit, plan->cancel, and amend round trip — the mechanical-wiring proof
    for the forty-second doctype. The submit/cancel risk-flag semantics live in their own
    dedicated class below, not here."""

    def test_plan_submit_records_the_doctype_and_the_date(self):
        broker, client, stores = make_broker()
        out = broker.dispatch("plan_submit", {"name": "TS-1", "pacioli_doctype": "Timesheet"})
        self.assertTrue(out["ok"], out)
        self.assertEqual(out["doctype"], "Timesheet")
        self.assertEqual(out["posting_date"], "2026-01-01")
        self.assertEqual(client.lock_calls[-1], ("Example Corp", TIMESHEET, "2026-01-01"))
        stored = stores("prod").get_plan(out["plan_id"])
        self.assertEqual(stored.doctype, "Timesheet")
        self.assertEqual(stored.docname, "TS-1")

    def test_full_governed_submit_flow(self):
        broker, client, stores = make_broker()
        plan = broker.dispatch("plan_submit", {"name": "TS-1", "pacioli_doctype": "Timesheet"})
        self.assertTrue(plan["ok"], plan)
        token = "ts-submit-token"
        stores("prod").mint_marker(token, plan["plan_id"], expires_at=2_000.0)
        out = broker.dispatch("submit_timesheet",
                              {"name": "TS-1", "plan_id": plan["plan_id"], "marker": token})
        self.assertTrue(out["ok"], out)
        self.assertEqual(out["result"]["docstatus"], 1)
        self.assertEqual(out["result"]["doctype"], "Timesheet")
        self.assertEqual(client.submitted, ["TS-1"])
        store = stores("prod")
        self.assertEqual(store.marker_state(token), "consumed")
        self.assertEqual(store.orphans(), [])

    def test_plan_submit_refuses_non_draft(self):
        broker, client, _ = make_broker()
        client.docs["TS-1"]["docstatus"] = 1
        out = broker.dispatch("plan_submit", {"name": "TS-1", "pacioli_doctype": "Timesheet"})
        self.assertFalse(out["ok"])
        self.assertIn("draft", out["reason"].lower())

    def test_full_governed_cancel_flow_of_a_leaf(self):
        broker, client, stores = make_broker()
        self.assertEqual(client.linked, [])  # the honest default — no fixture pretends otherwise
        plan = broker.dispatch("plan_cancel", {"name": "TS-9", "pacioli_doctype": "Timesheet"})
        self.assertTrue(plan["ok"], plan)
        token = "ts-cancel-token"
        stores("prod").mint_marker(token, plan["plan_id"], expires_at=2_000.0)
        out = broker.dispatch("cancel_timesheet",
                              {"name": "TS-9", "plan_id": plan["plan_id"], "marker": token})
        self.assertTrue(out["ok"], out)
        self.assertEqual(out["result"]["docstatus"], 2)
        self.assertEqual(client.cancelled, ["TS-9"])
        self.assertEqual(stores("prod").marker_state(token), "consumed")

    def test_amend_creates_the_draft_with_receipts_and_no_marker(self):
        broker, client, stores = make_broker()
        client.docs["TS-9"]["docstatus"] = 2
        out = broker.dispatch("amend_timesheet", {"name": "TS-9"})
        self.assertTrue(out["ok"], out)
        self.assertEqual(out["result"]["name"], "TS-9-1")
        self.assertEqual(out["result"]["docstatus"], 0)
        self.assertEqual(out["result"]["doctype"], "Timesheet")
        self.assertEqual(client.amended, ["TS-9"])
        store = stores("prod")
        receipts = store.receipts()
        self.assertEqual([r.kind for r in receipts], ["intent", "outcome"])
        self.assertEqual(receipts[0].body["doctype"], "Timesheet")
        self.assertEqual(store.orphans(), [])

    def test_amend_refuses_an_uncancelled_source(self):
        broker, client, _ = make_broker()
        out = broker.dispatch("amend_timesheet", {"name": "TS-1"})  # a draft
        self.assertFalse(out["ok"])
        self.assertIn("cancelled", out["reason"])

    def test_cascade_node_meta_projects_the_start_date_and_reads_company(self):
        broker, client, _ = make_broker()
        node_meta = broker._cascade_node_meta(client)
        meta = node_meta(TIMESHEET, "TS-1")
        self.assertEqual(meta["posting_date"], "2026-01-01")
        self.assertEqual(meta["company"], "Example Corp")


