    def test_plan_submit_refuses_blank_company_under_a_pinned_target_wrong_books(self):
        # The mirror case: a pinned target refuses TS-6's blank company outright at the standing
        # "wrong books" gate, before any risk-flag logic is ever reached — the same 0fdf91d guard
        # every companyless-adjacent doctype in this campaign is tested under.
        broker, client, _ = make_broker()
        out = broker.dispatch("plan_submit", {"name": "TS-6", "pacioli_doctype": "Timesheet"})
        self.assertFalse(out["ok"])
        self.assertIn("wrong books", out["reason"])

    def test_submit_always_discloses_the_second_writer_and_status_precedence(self):
        broker, client, _ = make_broker()
        out = broker.dispatch("plan_submit", {"name": "TS-1", "pacioli_doctype": "Timesheet"})
        self.assertTrue(out["ok"], out)
        second_writer = next((f for f in out["risk_flags"] if "db_update_all" in f), None)
        self.assertIsNotNone(second_writer, out["risk_flags"])
        self.assertIn("Sales Invoice", second_writer)
        self.assertIn("DOES NOT VALIDATE AND CALL TRIGGERS", second_writer)
        precedence = next((f for f in out["risk_flags"]
                          if "THREE-SEQUENTIAL-IF" in f), None)
        self.assertIsNotNone(precedence, out["risk_flags"])
        self.assertIn("Completed", precedence)

