class TestContractGovernedRoundTrip(unittest.TestCase):
    """One full plan->submit, plan->cancel, and amend round trip, plus the cascade node_meta
    closure — all exercised under REG_UNPINNED (the ONLY registry shape a companyless doctype can
    ever govern through). CONTRACT-1's own signed_on carries a microsecond REST variant
    ("2026-01-01 09:00:00.000001") — the SAME Datetime->date projection Work Order's/Asset
    Movement's own landings built, reused unchanged."""

    def test_plan_submit_records_the_doctype_and_the_projected_signed_on_date(self):
        broker, client, stores = make_broker(reg=REG_UNPINNED)
        out = broker.dispatch("plan_submit",
                              {"name": "CONTRACT-1", "pacioli_doctype": "Contract"})
        self.assertTrue(out["ok"], out)
        self.assertEqual(out["doctype"], "Contract")
        self.assertEqual(out["posting_date"], "2026-01-01")  # the date part, never the raw value
        # Companyless: _locks_for short-circuits to {} before any network call — never a
        # (None, ...) read.
        self.assertEqual(client.lock_calls, [])
        self.assertTrue(any("closed-books: not applicable" in f for f in out["risk_flags"]),
                        out["risk_flags"])
        self.assertTrue(any("no company" in f for f in out["risk_flags"]), out["risk_flags"])
        stored = stores("prod").get_plan(out["plan_id"])
        self.assertEqual(stored.doctype, "Contract")
        self.assertEqual(stored.docname, "CONTRACT-1")

    def test_full_governed_submit_flow(self):
        broker, client, stores = make_broker(reg=REG_UNPINNED)
        plan = broker.dispatch("plan_submit",
                               {"name": "CONTRACT-1", "pacioli_doctype": "Contract"})
        self.assertTrue(plan["ok"], plan)
        token = "contract-raw-token"
        stores("prod").mint_marker(token, plan["plan_id"], expires_at=2_000.0)
        out = broker.dispatch("submit_contract",
                              {"name": "CONTRACT-1", "plan_id": plan["plan_id"], "marker": token})
        self.assertTrue(out["ok"], out)
        self.assertEqual(out["result"]["docstatus"], 1)
        self.assertEqual(out["result"]["doctype"], "Contract")
        self.assertEqual(client.submitted, ["CONTRACT-1"])
        store = stores("prod")
        self.assertEqual(store.marker_state(token), "consumed")
        self.assertEqual(store.orphans(), [])

    def test_plan_submit_refuses_non_draft(self):
        broker, client, _ = make_broker(reg=REG_UNPINNED)
        client.docs["CONTRACT-1"]["docstatus"] = 1
        out = broker.dispatch("plan_submit",
                              {"name": "CONTRACT-1", "pacioli_doctype": "Contract"})
        self.assertFalse(out["ok"])
        self.assertIn("draft", out["reason"].lower())

    def test_full_governed_cancel_flow_of_a_leaf(self):
        broker, client, stores = make_broker(reg=REG_UNPINNED)
        self.assertEqual(client.linked, [])  # a genuine cascade leaf — no fixture pretends
        plan = broker.dispatch("plan_cancel",
                               {"name": "CONTRACT-9", "pacioli_doctype": "Contract"})
        self.assertTrue(plan["ok"], plan)
        token = "contract-cancel-token"
        stores("prod").mint_marker(token, plan["plan_id"], expires_at=2_000.0)
        out = broker.dispatch("cancel_contract",
                              {"name": "CONTRACT-9", "plan_id": plan["plan_id"],
                               "marker": token})
        self.assertTrue(out["ok"], out)
        self.assertEqual(out["result"]["docstatus"], 2)
        self.assertEqual(client.cancelled, ["CONTRACT-9"])
        self.assertEqual(stores("prod").marker_state(token), "consumed")

    def test_amend_creates_the_draft_with_receipts_and_no_marker(self):
        broker, client, stores = make_broker(reg=REG_UNPINNED)
        client.docs["CONTRACT-9"]["docstatus"] = 2
        out = broker.dispatch("amend_contract", {"name": "CONTRACT-9"})
        self.assertTrue(out["ok"], out)
        self.assertEqual(out["result"]["name"], "CONTRACT-9-1")
        self.assertEqual(out["result"]["docstatus"], 0)
        self.assertEqual(out["result"]["doctype"], "Contract")
        self.assertEqual(client.amended, ["CONTRACT-9"])
        store = stores("prod")
        receipts = store.receipts()
        self.assertEqual([r.kind for r in receipts], ["intent", "outcome"])
        self.assertEqual(receipts[0].body["doctype"], "Contract")
        self.assertEqual(store.orphans(), [])

    def test_amend_refuses_an_uncancelled_source(self):
        broker, client, _ = make_broker(reg=REG_UNPINNED)
        out = broker.dispatch("amend_contract", {"name": "CONTRACT-1"})  # a draft
        self.assertFalse(out["ok"])
        self.assertIn("cancelled", out["reason"])

    def test_cascade_node_meta_reads_the_projected_date_and_no_company(self):
        broker, client, _ = make_broker(reg=REG_UNPINNED)
        node_meta = broker._cascade_node_meta(client)
        meta = node_meta(CONTRACT, "CONTRACT-1")
        self.assertEqual(meta["posting_date"], "2026-01-01")
        self.assertIsNone(meta["company"])  # confirmed absent from the real schema too


