class TestContractDatetimeProjectionAndBlankDate(unittest.TestCase):
    """signed_on is a Datetime — the SAME truncate-at-real-separator projection Work Order's/
    Asset Movement's own landings built (reused unchanged). It is ALSO genuinely, verifiably
    blank-capable on a submitted Contract (never forced non-blank by any code path) — the Project
    Update/Asset Maintenance Log precedent for "a real declared date field that can still be
    blank," proven here for the first date_field pin that is ALSO allow_on_submit."""

