class TestPickListGovernedRoundTrip(unittest.TestCase):
    """One full plan->submit, plan->cancel, and amend round trip — the mechanical-wiring proof
    for the forty-fourth doctype. The submit/cancel risk-flag semantics live in their own
    dedicated classes below, not here."""

    def test_plan_submit_records_the_doctype_and_the_dateless_sentinel(self):
        broker, client, stores = make_broker()
        out = broker.dispatch("plan_submit", {"name": "PL-1", "pacioli_doctype": "Pick List"})
        self.assertTrue(out["ok"], out)
        self.assertEqual(out["doctype"], "Pick List")
        self.assertEqual(out["posting_date"], NO_DATE_FIELD)
        self.assertEqual(client.lock_calls, [])  # dateless — no period-lock read at all
        stored = stores("prod").get_plan(out["plan_id"])
        self.assertEqual(stored.doctype, "Pick List")
        self.assertEqual(stored.docname, "PL-1")

    def test_full_governed_submit_flow(self):
        broker, client, stores = make_broker()
        plan = broker.dispatch("plan_submit", {"name": "PL-1", "pacioli_doctype": "Pick List"})
        self.assertTrue(plan["ok"], plan)
        token = "pl-submit-token"
        stores("prod").mint_marker(token, plan["plan_id"], expires_at=2_000.0)
        out = broker.dispatch("submit_pick_list",
                              {"name": "PL-1", "plan_id": plan["plan_id"], "marker": token})
        self.assertTrue(out["ok"], out)
        self.assertEqual(out["result"]["docstatus"], 1)
        self.assertEqual(out["result"]["doctype"], "Pick List")
        self.assertEqual(client.submitted, ["PL-1"])
        store = stores("prod")
        self.assertEqual(store.marker_state(token), "consumed")
        self.assertEqual(store.orphans(), [])

    def test_plan_submit_refuses_non_draft(self):
        broker, client, _ = make_broker()
        client.docs["PL-1"]["docstatus"] = 1
        out = broker.dispatch("plan_submit", {"name": "PL-1", "pacioli_doctype": "Pick List"})
        self.assertFalse(out["ok"])
        self.assertIn("draft", out["reason"].lower())

    def test_full_governed_cancel_flow_of_a_leaf(self):
        broker, client, stores = make_broker()
        self.assertEqual(client.linked, [])  # the honest default — no fixture pretends otherwise
        plan = broker.dispatch("plan_cancel", {"name": "PL-9", "pacioli_doctype": "Pick List"})
        self.assertTrue(plan["ok"], plan)
        token = "pl-cancel-token"
        stores("prod").mint_marker(token, plan["plan_id"], expires_at=2_000.0)
        out = broker.dispatch("cancel_pick_list",
                              {"name": "PL-9", "plan_id": plan["plan_id"], "marker": token})
        self.assertTrue(out["ok"], out)
        self.assertEqual(out["result"]["docstatus"], 2)
        self.assertEqual(client.cancelled, ["PL-9"])
        self.assertEqual(stores("prod").marker_state(token), "consumed")

    def test_amend_creates_the_draft_with_receipts_and_no_marker(self):
        broker, client, stores = make_broker()
        client.docs["PL-9"]["docstatus"] = 2
        out = broker.dispatch("amend_pick_list", {"name": "PL-9"})
        self.assertTrue(out["ok"], out)
        self.assertEqual(out["result"]["name"], "PL-9-1")
        self.assertEqual(out["result"]["docstatus"], 0)
        self.assertEqual(out["result"]["doctype"], "Pick List")
        self.assertEqual(client.amended, ["PL-9"])
        store = stores("prod")
        receipts = store.receipts()
        self.assertEqual([r.kind for r in receipts], ["intent", "outcome"])
        self.assertEqual(receipts[0].body["doctype"], "Pick List")
        self.assertEqual(store.orphans(), [])

    def test_amend_refuses_an_uncancelled_source(self):
        broker, client, _ = make_broker()
        out = broker.dispatch("amend_pick_list", {"name": "PL-1"})  # a draft
        self.assertFalse(out["ok"])
        self.assertIn("cancelled", out["reason"])

    def test_cascade_node_meta_projects_the_dateless_sentinel_and_reads_company(self):
        broker, client, _ = make_broker()
        node_meta = broker._cascade_node_meta(client)
        meta = node_meta(PICK_LIST, "PL-1")
        self.assertEqual(meta["posting_date"], NO_DATE_FIELD)
        self.assertEqual(meta["company"], "Example Corp")


