class TestPickListCascadeNotALeaf(unittest.TestCase):
    """THE CASCADE QUESTION — the row's decisive fact, settled here from source, not inherited
    from the dossier/addendum (both concluded LEAF and were wrong). A full two-checkout grep for
    '"options": "Pick List"' returns exactly 4 hits: Pick List's own self-referencing
    amended_from, Stock Entry.pick_list (a direct header-level Link on submittable Stock Entry),
    Delivery Note Item.against_pick_list, and Sales Invoice Item.against_pick_list (both real
    Links on child tables under submittable DN/SI). frappe's own linked_with.py resolves a
    child-table hit back to its submittable PARENT under get_parent_if_child_table_doc=True
    (confirmed live in ``linked_with.py:121``/``:356-364``) — the exact mechanism Timesheet's own
    landing already proved for Sales Invoice Timesheet.time_sheet. Pick List is NOT a cascade leaf
    on three independent counts."""

    def test_leaf_plan_cancel_is_blocked_by_a_submitted_stock_entry(self):
        broker, client, _ = make_broker()
        client.linked = [{"doctype": "Stock Entry", "name": "SE-9", "docstatus": 1}]
        out = broker.dispatch("plan_cancel", {"name": "PL-9", "pacioli_doctype": "Pick List"})
        self.assertFalse(out["ok"])
        self.assertIn("Stock Entry SE-9", out["reason"])
        self.assertIn("plan_cascade_cancel", out["reason"])

    def test_leaf_plan_cancel_is_blocked_by_a_submitted_delivery_note(self):
        broker, client, _ = make_broker()
        client.linked = [{"doctype": "Delivery Note", "name": "DN-9", "docstatus": 1}]
        out = broker.dispatch("plan_cancel", {"name": "PL-9", "pacioli_doctype": "Pick List"})
        self.assertFalse(out["ok"])
        self.assertIn("Delivery Note DN-9", out["reason"])

    def test_leaf_plan_cancel_is_blocked_by_a_submitted_sales_invoice(self):
        broker, client, _ = make_broker()
        client.linked = [{"doctype": "Sales Invoice", "name": "SI-9", "docstatus": 1}]
        out = broker.dispatch("plan_cancel", {"name": "PL-9", "pacioli_doctype": "Pick List"})
        self.assertFalse(out["ok"])
        self.assertIn("Sales Invoice SI-9", out["reason"])

    def test_plan_cascade_cancel_orders_the_stock_entry_before_the_pick_list(self):
        cc = CascadeClient({("Pick List", "PL-9"):
                                [{"doctype": "Stock Entry", "docname": "SE-9"}],
                            ("Stock Entry", "SE-9"): []})
        broker, client, store_provider = make_broker(client=cc)
        plan = broker.dispatch("plan_cascade_cancel",
                               {"name": "PL-9", "pacioli_doctype": "Pick List"})
        self.assertTrue(plan["ok"], plan)
        self.assertEqual([n["docname"] for n in plan["graph"]], ["SE-9", "PL-9"])
        self.assertEqual(plan["graph"][0]["coverage"], "modeled")  # Stock Entry IS modeled
        self.assertEqual(plan["graph"][1]["coverage"], "modeled")  # Pick List IS modeled
        self.assertTrue(any("PL-9: " in f and "on_cancel" in f for f in plan["risk_flags"]),
                        plan["risk_flags"])
        store_provider("prod").mint_marker("pl-casc-token", plan["plan_id"], expires_at=2_000.0)
        out = broker.dispatch("cascade_cancel",
                              {"name": "PL-9", "plan_id": plan["plan_id"],
                               "marker": "pl-casc-token"})
        self.assertTrue(out["ok"], out)
        self.assertEqual([n["docname"] for n in out["cancelled"]], ["SE-9", "PL-9"])
        self.assertEqual(len(client.cancelled), 2)


