class TestAssetRepairCompanyOptionalAndConsequential(unittest.TestCase):
    """company is present but NOT reqd (fetch_from asset.company) — the FIFTH such row (after
    PI/QI/AVA/Timesheet). Unlike Timesheet's own zero-consequence blank company, a blank company
    on Asset Repair IS genuinely consequential under two independent, data-driven conditions (the
    AVA honesty grade) — but also reachable in its zero-consequence Timesheet shape on this SAME
    doctype, depending on the draft's own fields. Blank company only reaches this broker's own
    risk-flag logic under REG_UNPINNED (a pinned target refuses "" as wrong-books first, exactly
    like every other present-but-blank company row in this campaign)."""

    def test_blank_company_refuses_wrong_books_under_a_pinned_target(self):
        broker, client, _ = make_broker()  # default REG: company = "Example Corp"
        out = broker.dispatch("plan_submit", {"name": "AR-6", "pacioli_doctype": "Asset Repair"})
        self.assertFalse(out["ok"])
        self.assertIn("wrong books", out["reason"].lower())

    def test_blank_company_with_the_gl_gate_armed_is_doomed_under_unpinned(self):
        broker, client, _ = make_broker(reg=REG_UNPINNED)
        out = broker.dispatch("plan_submit", {"name": "AR-6", "pacioli_doctype": "Asset Repair"})
        self.assertTrue(out["ok"], out)  # the plan still records; only submit itself is doomed
        flag = next((f for f in out["risk_flags"]
                    if "company is blank AND the GL gate above is armed" in f), None)
        self.assertIsNotNone(flag, out["risk_flags"])
        self.assertIn("get_asset_account", flag)

    def test_blank_company_with_stock_items_is_doomed_under_unpinned(self):
        broker, client, _ = make_broker(reg=REG_UNPINNED)
        out = broker.dispatch("plan_submit", {"name": "AR-7", "pacioli_doctype": "Asset Repair"})
        self.assertTrue(out["ok"], out)
        flag = next((f for f in out["risk_flags"]
                    if "company is blank AND stock_items is non-empty" in f), None)
        self.assertIsNotNone(flag, out["risk_flags"])
        self.assertIn("MandatoryError", flag)

    def test_blank_company_with_neither_gate_armed_has_no_consequence(self):
        broker, client, _ = make_broker(reg=REG_UNPINNED)
        out = broker.dispatch("plan_submit", {"name": "AR-8", "pacioli_doctype": "Asset Repair"})
        self.assertTrue(out["ok"], out)
        self.assertFalse(any("company is blank" in f for f in out["risk_flags"]))

    def test_a_present_company_is_unaffected_control(self):
        broker, client, _ = make_broker()
        out = broker.dispatch("plan_submit", {"name": "AR-1", "pacioli_doctype": "Asset Repair"})
        self.assertTrue(out["ok"], out)
        self.assertFalse(any("company is blank" in f for f in out["risk_flags"]))


