class TestAssetRepairDatetimeDateProjection(unittest.TestCase):
    """completion_date is a Datetime — the SAME truncate-at-real-separator projection Work
    Order's/Asset Movement's/Contract's own landings built (reused unchanged). THE addendum's own
    sharpest landing risk: completion_date can be genuinely EMPTY on a SUBMITTED document whose own
    repair_status is "Cancelled" (check_repair_status blocks submit only for "Pending") — a shape
    none of the prior three Datetime-dated doctypes could reach (all three chosen fields are
    unconditionally reqd=1)."""

    def test_microsecond_datetime_projects_to_its_date_part(self):
        broker, client, _ = make_broker()
        out = broker.dispatch("plan_submit", {"name": "AR-1", "pacioli_doctype": "Asset Repair"})
        self.assertTrue(out["ok"], out)
        self.assertEqual(out["posting_date"], "2026-07-01")

    def test_plain_space_separated_datetime_projects_too(self):
        broker, client, _ = make_broker()
        out = broker.dispatch("plan_cancel", {"name": "AR-10", "pacioli_doctype": "Asset Repair"})
        self.assertTrue(out["ok"], out)
        self.assertEqual(out["posting_date"], "2026-06-15")

    def test_malformed_datetime_stays_refused_projection_is_never_repair(self):
        # Live-true reshape (2026-07-22, see the Work Order class's own reshaped test): the raw
        # shape flows through untouched and the plan REFUSES at the period-lock read.
        broker, client, stores = make_broker()
        client.docs["AR-1"]["completion_date"] = "2026-7-1 10:00:00"
        plan = broker.dispatch("plan_submit", {"name": "AR-1", "pacioli_doctype": "Asset Repair"})
        self.assertFalse(plan["ok"])
        self.assertIn("not a valid ISO", plan["reason"])
        self.assertIn("2026-7-1 10:00:00", plan["reason"])  # raw shape, never a "repair"
        self.assertEqual(client.submitted, [])  # nothing went to the bench

    def test_empty_completion_date_on_a_submitted_cancelled_status_document_refuses_at_plan(
            self):
        # THE central finding (addendum's Landing Risk #1), live-true reshape 2026-07-22: ERPNext
        # itself has no code path that would ever refuse cancelling AR-9 over a blank
        # completion_date (check_repair_status only blocks a "Pending" SUBMIT, and validate()
        # doesn't even run on cancel) — this broker refuses it anyway, because its own governed
        # date_field pin requires a real date to verify against period locks. Broker STRICTER
        # than ERPNext here, by construction. The refusal fires at the PLAN's own lock read
        # (get_period_locks' ISO gate — company present, so no short-circuit applies), so no
        # plan exists to mint against and no cancel can ever reach the bench.
        broker, client, stores = make_broker()
        plan = broker.dispatch("plan_cancel", {"name": "AR-9", "pacioli_doctype": "Asset Repair"})
        self.assertFalse(plan["ok"], plan)
        self.assertIn("not a valid ISO", plan["reason"])
        self.assertEqual(client.cancelled, [])  # no cancel ever reached the bench


class TestAssetRepairCascadeNotALeaf(unittest.TestCase):
    """Genuinely NOT a leaf — the simplest non-leaf shape this campaign has found: a direct
    header-level Link, no child-table resolution at all. A full two-checkout grep for
    '"options": "Asset Repair"' returns exactly 2 hits: Asset Repair's own self-referencing
    amended_from, and Stock Entry's own asset_repair field (stock_entry.json:705, read_only,
    header-level, on submittable Stock Entry)."""

    def test_leaf_plan_cancel_is_blocked_by_a_submitted_stock_entry(self):
        broker, client, _ = make_broker()
        client.linked = [{"doctype": "Stock Entry", "name": "SE-9", "docstatus": 1}]
        out = broker.dispatch("plan_cancel", {"name": "AR-10", "pacioli_doctype": "Asset Repair"})
        self.assertFalse(out["ok"])
        self.assertIn("Stock Entry SE-9", out["reason"])
        self.assertIn("plan_cascade_cancel", out["reason"])

    def test_plan_cascade_cancel_orders_the_stock_entry_before_the_asset_repair(self):
        cc = CascadeClient({("Asset Repair", "AR-10"):
                                [{"doctype": "Stock Entry", "docname": "SE-9"}],
                            ("Stock Entry", "SE-9"): []})
        broker, client, store_provider = make_broker(client=cc)
        plan = broker.dispatch("plan_cascade_cancel",
                               {"name": "AR-10", "pacioli_doctype": "Asset Repair"})
        self.assertTrue(plan["ok"], plan)
        self.assertEqual([n["docname"] for n in plan["graph"]], ["SE-9", "AR-10"])
        self.assertEqual(plan["graph"][0]["coverage"], "modeled")  # Stock Entry IS modeled
        self.assertEqual(plan["graph"][1]["coverage"], "modeled")  # Asset Repair IS modeled
        store_provider("prod").mint_marker("ar-casc-token", plan["plan_id"], expires_at=2_000.0)
        out = broker.dispatch("cascade_cancel",
                              {"name": "AR-10", "plan_id": plan["plan_id"],
                               "marker": "ar-casc-token"})
        self.assertTrue(out["ok"], out)
        self.assertEqual([n["docname"] for n in out["cancelled"]], ["SE-9", "AR-10"])
        self.assertEqual(len(client.cancelled), 2)


