class TestAssetRepairCancelRiskFlags(unittest.TestCase):
    """The cancel-direction disclosure: THE ASSET-STATUS SIDE-WRITE does NOT fire here (cancel
    skips validate() entirely, a correction to the pre-verification addendum), the
    capitalize_repair_cost-gated reversal family, and the dangling-Stock-Entry disclosure."""

    def test_cancel_never_discloses_the_asset_status_side_write(self):
        broker, client, _ = make_broker()
        out = broker.dispatch("plan_cancel", {"name": "AR-10", "pacioli_doctype": "Asset Repair"})
        self.assertTrue(out["ok"], out)
