class TestInvoiceDiscountingGovernedRoundTrip(unittest.TestCase):
    """One full plan->submit, plan->cancel, and amend round trip — the mechanical-wiring proof for
    the forty-sixth doctype. The submit/cancel risk-flag semantics live in their own dedicated
    classes below, not here."""

    def test_plan_submit_records_the_doctype_and_the_posting_date(self):
        broker, client, stores = make_broker()
        out = broker.dispatch("plan_submit", {"name": "ID-1", "pacioli_doctype": "Invoice Discounting"})
        self.assertTrue(out["ok"], out)
        self.assertEqual(out["doctype"], "Invoice Discounting")
        self.assertEqual(out["posting_date"], "2026-07-01")
        self.assertEqual(client.lock_calls[-1], ("Example Corp", INVOICE_DISCOUNTING, "2026-07-01"))
        stored = stores("prod").get_plan(out["plan_id"])
        self.assertEqual(stored.doctype, "Invoice Discounting")
        self.assertEqual(stored.docname, "ID-1")

    def test_full_governed_submit_flow(self):
        broker, client, stores = make_broker()
        plan = broker.dispatch("plan_submit",
                               {"name": "ID-1", "pacioli_doctype": "Invoice Discounting"})
        self.assertTrue(plan["ok"], plan)
        token = "id-submit-token"
        stores("prod").mint_marker(token, plan["plan_id"], expires_at=2_000.0)
        out = broker.dispatch("submit_invoice_discounting",
                              {"name": "ID-1", "plan_id": plan["plan_id"], "marker": token})
        self.assertTrue(out["ok"], out)
        self.assertEqual(out["result"]["docstatus"], 1)
        self.assertEqual(out["result"]["doctype"], "Invoice Discounting")
        self.assertEqual(client.submitted, ["ID-1"])
        store = stores("prod")
        self.assertEqual(store.marker_state(token), "consumed")
        self.assertEqual(store.orphans(), [])

    def test_plan_submit_refuses_non_draft(self):
        broker, client, _ = make_broker()
        client.docs["ID-1"]["docstatus"] = 1
        out = broker.dispatch("plan_submit",
                              {"name": "ID-1", "pacioli_doctype": "Invoice Discounting"})
        self.assertFalse(out["ok"])
        self.assertIn("draft", out["reason"].lower())

    def test_full_governed_cancel_flow_of_a_leaf(self):
        broker, client, stores = make_broker()
        self.assertEqual(client.linked, [])  # the honest default — no fixture pretends otherwise
        plan = broker.dispatch("plan_cancel",
                               {"name": "ID-9", "pacioli_doctype": "Invoice Discounting"})
        self.assertTrue(plan["ok"], plan)
        token = "id-cancel-token"
        stores("prod").mint_marker(token, plan["plan_id"], expires_at=2_000.0)
        out = broker.dispatch("cancel_invoice_discounting",
                              {"name": "ID-9", "plan_id": plan["plan_id"], "marker": token})
        self.assertTrue(out["ok"], out)
        self.assertEqual(out["result"]["docstatus"], 2)
        self.assertEqual(client.cancelled, ["ID-9"])
        self.assertEqual(stores("prod").marker_state(token), "consumed")

    def test_amend_creates_the_draft_with_receipts_and_no_marker(self):
        broker, client, stores = make_broker()
        client.docs["ID-9"]["docstatus"] = 2
        out = broker.dispatch("amend_invoice_discounting", {"name": "ID-9"})
        self.assertTrue(out["ok"], out)
        self.assertEqual(out["result"]["name"], "ID-9-1")
        self.assertEqual(out["result"]["docstatus"], 0)
        self.assertEqual(out["result"]["doctype"], "Invoice Discounting")
        self.assertEqual(client.amended, ["ID-9"])
        store = stores("prod")
        receipts = store.receipts()
        self.assertEqual([r.kind for r in receipts], ["intent", "outcome"])
        self.assertEqual(receipts[0].body["doctype"], "Invoice Discounting")
        self.assertEqual(store.orphans(), [])

    def test_amend_refuses_an_uncancelled_source(self):
        broker, client, _ = make_broker()
        out = broker.dispatch("amend_invoice_discounting", {"name": "ID-1"})  # a draft
        self.assertFalse(out["ok"])
        self.assertIn("cancelled", out["reason"])

