class TestInvoiceDiscountingCascadeNotALeaf(unittest.TestCase):
    """THE CASCADE QUESTION — settled from source, not the campaign's own grep method (both the
    dossier and the addendum's own static-grep framing would have called this a leaf): Journal
    Entry Account's own reference_name is a Dynamic Link (options="reference_type"), and a Journal
    Entry Account row with reference_type="Invoice Discounting" IS discovered by this broker's own
    get_submitted_linked_docs — the SAME live-distinct-value Dynamic Link mechanism the Landed Cost
    Voucher/Dunning landings already proved — resolved up to its submitted Journal Entry parent."""

    def test_leaf_plan_cancel_is_blocked_by_a_submitted_journal_entry(self):
        broker, client, _ = make_broker()
        client.linked = [{"doctype": "Journal Entry", "name": "JE-9", "docstatus": 1}]
        out = broker.dispatch("plan_cancel",
                              {"name": "ID-9", "pacioli_doctype": "Invoice Discounting"})
        self.assertFalse(out["ok"])
        self.assertIn("Journal Entry JE-9", out["reason"])
        self.assertIn("plan_cascade_cancel", out["reason"])

    def test_plan_cascade_cancel_orders_the_journal_entry_before_the_invoice_discounting(self):
        cc = CascadeClient({("Invoice Discounting", "ID-9"):
                                [{"doctype": "Journal Entry", "docname": "JE-9"}],
                            ("Journal Entry", "JE-9"): []})
        broker, client, store_provider = make_broker(client=cc)
        plan = broker.dispatch("plan_cascade_cancel",
                               {"name": "ID-9", "pacioli_doctype": "Invoice Discounting"})
        self.assertTrue(plan["ok"], plan)
        self.assertEqual([n["docname"] for n in plan["graph"]], ["JE-9", "ID-9"])
        self.assertEqual(plan["graph"][0]["coverage"], "modeled")  # Journal Entry IS modeled
        self.assertEqual(plan["graph"][1]["coverage"], "modeled")  # Invoice Discounting IS modeled
        store_provider("prod").mint_marker("id-casc-token", plan["plan_id"], expires_at=2_000.0)
        out = broker.dispatch("cascade_cancel",
                              {"name": "ID-9", "plan_id": plan["plan_id"],
                               "marker": "id-casc-token"})
        self.assertTrue(out["ok"], out)
        self.assertEqual([n["docname"] for n in out["cancelled"]], ["JE-9", "ID-9"])
        self.assertEqual(len(client.cancelled), 2)


