class TestProductionPlanGovernedRoundTrip(unittest.TestCase):
    """One full plan->submit, plan->cancel, and amend round trip — the mechanical-wiring proof
    for the forty-eighth doctype. The semantic divergences (the uncallable preview, the two
    auto-submit channels, the not-a-leaf cascade shape) live in their own dedicated test classes
    below, not here. PP-1 is a clean Draft (reserve_stock=0, no doomed-submit branch fires); PP-9
    is the submitted, reserve_stock=0 fixture for the cancel-direction/amend tests."""

    def test_plan_submit_records_the_doctype_and_the_date(self):
        broker, client, stores = make_broker()
        out = broker.dispatch("plan_submit",
                              {"name": "PP-1", "pacioli_doctype": "Production Plan"})
        self.assertTrue(out["ok"], out)
        self.assertEqual(out["doctype"], "Production Plan")
        self.assertEqual(out["posting_date"], "2026-07-01")
        self.assertEqual(client.lock_calls[-1],
                         ("Example Corp", PRODUCTION_PLAN, "2026-07-01"))
        stored = stores("prod").get_plan(out["plan_id"])
        self.assertEqual(stored.doctype, "Production Plan")
        self.assertEqual(stored.docname, "PP-1")

    def test_full_governed_submit_flow(self):
        broker, client, stores = make_broker()
        plan = broker.dispatch("plan_submit",
                               {"name": "PP-1", "pacioli_doctype": "Production Plan"})
        self.assertTrue(plan["ok"], plan)
        token = "pp-raw-token"
        stores("prod").mint_marker(token, plan["plan_id"], expires_at=2_000.0)
        out = broker.dispatch("submit_production_plan",
                              {"name": "PP-1", "plan_id": plan["plan_id"], "marker": token})
        self.assertTrue(out["ok"], out)
        self.assertEqual(out["result"]["docstatus"], 1)
        self.assertEqual(out["result"]["doctype"], "Production Plan")
        self.assertEqual(client.submitted, ["PP-1"])
