class TestProductionPlanCascadeNotALeaf(unittest.TestCase):
    """THE CASCADE QUESTION — the row's decisive fact, settled here from source, not inherited
    from the dossier (which concluded LEAF and was wrong, self-contradicted by its own §8 text). A
    full two-checkout grep for '"options": "Production Plan"' returns exactly FOUR hits:
    Production Plan's own self-referencing amended_from, Work Order.production_plan (a direct
    header-level Link on submittable Work Order), Purchase Order Item.production_plan, and
    Material Request Item.production_plan (both real Links on child tables under submittable PO/
    MR). frappe's own linked_with.py resolves a child-table hit back to its submittable PARENT
    under get_parent_if_child_table_doc=True (the exact mechanism the Pick List/Timesheet
    landings already proved). Production Plan is NOT a cascade leaf on three independent
    counts."""

    def test_leaf_plan_cancel_is_blocked_by_a_submitted_work_order(self):
        broker, client, _ = make_broker()
        client.linked = [{"doctype": "Work Order", "name": "WO-9", "docstatus": 1}]
        out = broker.dispatch("plan_cancel",
                              {"name": "PP-9", "pacioli_doctype": "Production Plan"})
        self.assertFalse(out["ok"])
        self.assertIn("Work Order WO-9", out["reason"])
        self.assertIn("plan_cascade_cancel", out["reason"])

    def test_leaf_plan_cancel_is_blocked_by_a_submitted_purchase_order(self):
        broker, client, _ = make_broker()
        client.linked = [{"doctype": "Purchase Order", "name": "PO-9", "docstatus": 1}]
        out = broker.dispatch("plan_cancel",
                              {"name": "PP-9", "pacioli_doctype": "Production Plan"})
        self.assertFalse(out["ok"])
        self.assertIn("Purchase Order PO-9", out["reason"])

    def test_leaf_plan_cancel_is_blocked_by_a_submitted_material_request(self):
        broker, client, _ = make_broker()
        client.linked = [{"doctype": "Material Request", "name": "MR-9", "docstatus": 1}]
        out = broker.dispatch("plan_cancel",
                              {"name": "PP-9", "pacioli_doctype": "Production Plan"})
        self.assertFalse(out["ok"])
        self.assertIn("Material Request MR-9", out["reason"])

    def test_plan_cascade_cancel_orders_the_work_order_before_the_production_plan(self):
        cc = CascadeClient({("Production Plan", "PP-9"):
                                [{"doctype": "Work Order", "docname": "WO-PP-9"}],
                            ("Work Order", "WO-PP-9"): []})
        cc.docs["PP-9"] = dict(FakeClient().docs["PP-9"])
        cc.docs["WO-PP-9"] = {"name": "WO-PP-9", "docstatus": 1, "company": "Example Corp",
                              "production_plan": "PP-9", "status": "Not Started",
                              "planned_start_date": "2026-06-20 08:00:00",
                              "modified": "2026-06-20 08:00:00.000001"}
        broker, client, store_provider = make_broker(client=cc)
        plan = broker.dispatch("plan_cascade_cancel",
                               {"name": "PP-9", "pacioli_doctype": "Production Plan"})
        self.assertTrue(plan["ok"], plan)
        self.assertEqual([n["docname"] for n in plan["graph"]], ["WO-PP-9", "PP-9"])
        self.assertEqual(plan["graph"][0]["coverage"], "modeled")  # Work Order IS modeled
        self.assertEqual(plan["graph"][1]["coverage"], "modeled")  # Production Plan IS modeled
        self.assertTrue(any("PP-9: " in f and "NOT a cascade leaf" in f
                            for f in plan["risk_flags"]), plan["risk_flags"])
        store_provider("prod").mint_marker("pp-casc-token", plan["plan_id"], expires_at=2_000.0)
        out = broker.dispatch("cascade_cancel",
                              {"name": "PP-9", "plan_id": plan["plan_id"],
                               "marker": "pp-casc-token"})
        self.assertTrue(out["ok"], out)
        self.assertEqual([n["docname"] for n in out["cancelled"]], ["WO-PP-9", "PP-9"])
        self.assertEqual(len(client.cancelled), 2)


