class TestSubcontractingOrderGovernedRoundTrip(unittest.TestCase):
    """One full plan->submit, plan->cancel, and amend round trip — the mechanical-wiring proof
    for the forty-ninth doctype. The semantic divergences (THE SEVEN-PATH MUTATOR MAP, the
    not-a-leaf cascade correction, the doomed-submit gates) live in their own dedicated test
    classes below, not here. SCO-1 is a clean Draft (purchase_order set, no collision,
    reserve_stock=0); SCO-9 is the submitted, reserve_stock=0 fixture for the cancel-direction/
    amend tests."""

    def test_plan_submit_records_the_doctype_and_the_date(self):
        broker, client, stores = make_broker()
        out = broker.dispatch("plan_submit",
                              {"name": "SCO-1", "pacioli_doctype": "Subcontracting Order"})
        self.assertTrue(out["ok"], out)
        self.assertEqual(out["doctype"], "Subcontracting Order")
        self.assertEqual(out["posting_date"], "2026-07-01")
        self.assertEqual(client.lock_calls[-1],
                         ("Example Corp", SUBCONTRACTING_ORDER, "2026-07-01"))
        stored = stores("prod").get_plan(out["plan_id"])
        self.assertEqual(stored.doctype, "Subcontracting Order")
        self.assertEqual(stored.docname, "SCO-1")

    def test_full_governed_submit_flow(self):
        broker, client, stores = make_broker()
        plan = broker.dispatch("plan_submit",
                               {"name": "SCO-1", "pacioli_doctype": "Subcontracting Order"})
        self.assertTrue(plan["ok"], plan)
        token = "sco-raw-token"
        stores("prod").mint_marker(token, plan["plan_id"], expires_at=2_000.0)
        out = broker.dispatch("submit_subcontracting_order",
                              {"name": "SCO-1", "plan_id": plan["plan_id"], "marker": token})
        self.assertTrue(out["ok"], out)
        self.assertEqual(out["result"]["docstatus"], 1)
        self.assertEqual(out["result"]["doctype"], "Subcontracting Order")
        self.assertEqual(client.submitted, ["SCO-1"])
        store = stores("prod")
        self.assertEqual(store.marker_state(token), "consumed")
        self.assertEqual(store.orphans(), [])

    def test_plan_submit_refuses_non_draft(self):
        broker, client, _ = make_broker()
        client.docs["SCO-1"]["docstatus"] = 1
        out = broker.dispatch("plan_submit",
                              {"name": "SCO-1", "pacioli_doctype": "Subcontracting Order"})
        self.assertFalse(out["ok"])
        self.assertIn("draft", out["reason"].lower())

    def test_full_governed_cancel_flow(self):
        broker, client, stores = make_broker()
        plan = broker.dispatch("plan_cancel",
                               {"name": "SCO-9", "pacioli_doctype": "Subcontracting Order"})
        self.assertTrue(plan["ok"], plan)
        self.assertEqual(plan["doctype"], "Subcontracting Order")
        token = "sco-cancel-token"
        stores("prod").mint_marker(token, plan["plan_id"], expires_at=2_000.0)
        out = broker.dispatch("cancel_subcontracting_order",
                              {"name": "SCO-9", "plan_id": plan["plan_id"], "marker": token})
        self.assertTrue(out["ok"], out)
        self.assertEqual(out["result"]["docstatus"], 2)
        self.assertEqual(client.cancelled, ["SCO-9"])
        self.assertEqual(stores("prod").marker_state(token), "consumed")

    def test_amend_creates_the_draft_with_receipts_and_no_marker(self):
        broker, client, stores = make_broker()
        client.docs["SCO-9"]["docstatus"] = 2
        out = broker.dispatch("amend_subcontracting_order", {"name": "SCO-9"})
        self.assertTrue(out["ok"], out)
        self.assertEqual(out["result"]["name"], "SCO-9-1")
        self.assertEqual(out["result"]["docstatus"], 0)
        self.assertEqual(out["result"]["doctype"], "Subcontracting Order")
        self.assertEqual(client.amended, ["SCO-9"])
        store = stores("prod")
        receipts = store.receipts()
        self.assertEqual([r.kind for r in receipts], ["intent", "outcome"])
        self.assertEqual(receipts[0].body["doctype"], "Subcontracting Order")
        self.assertEqual(store.orphans(), [])

    def test_amend_refuses_an_uncancelled_source(self):
        broker, client, _ = make_broker()
        out = broker.dispatch("amend_subcontracting_order", {"name": "SCO-1"})  # a draft
        self.assertFalse(out["ok"])
        self.assertIn("cancelled", out["reason"])


