class TestSubcontractingOrderCascadeNotALeaf(unittest.TestCase):
    """THE CASCADE CORRECTION — this landing's own refinement, NOT inherited from the dossier or
    the addendum (both repeated, without correcting, the framing that Subcontracting Receipt
    Item/Supplied Item are 'non-submittable, never appear in blast-radius reads'). Both child
    doctypes (istable=1) live under the submittable Subcontracting Receipt, and frappe's own
    get_submitted_linked_docs resolves a child-table Link hit back to its submittable PARENT
    (get_parent_if_child_table_doc=True) — the same mechanism Production Plan/Pick List/
    Timesheet's own landings already proved. Subcontracting Order is NOT a leaf on TWO
    independent submittable-referencer families: Stock Entry's own direct header Link, and
    Subcontracting Receipt's own child-table Links."""

    def test_leaf_plan_cancel_is_blocked_by_a_submitted_stock_entry(self):
        broker, client, _ = make_broker()
        client.linked = [{"doctype": "Stock Entry", "name": "STE-9", "docstatus": 1}]
        out = broker.dispatch("plan_cancel",
                              {"name": "SCO-9", "pacioli_doctype": "Subcontracting Order"})
        self.assertFalse(out["ok"])
        self.assertIn("Stock Entry STE-9", out["reason"])
        self.assertIn("plan_cascade_cancel", out["reason"])

    def test_leaf_plan_cancel_is_blocked_by_a_submitted_subcontracting_receipt(self):
        # The correction itself, exercised: a submitted Subcontracting Receipt (resolved from its
        # own child-table Subcontracting Order Link via frappe's get_parent_if_child_table_doc)
        # blocks a leaf cancel exactly like Stock Entry's own direct Link does.
        broker, client, _ = make_broker()
        client.linked = [{"doctype": "Subcontracting Receipt", "name": "SCR-9", "docstatus": 1}]
        out = broker.dispatch("plan_cancel",
                              {"name": "SCO-9", "pacioli_doctype": "Subcontracting Order"})
        self.assertFalse(out["ok"])
        self.assertIn("Subcontracting Receipt SCR-9", out["reason"])

    def test_plan_cascade_cancel_orders_the_stock_entry_before_the_subcontracting_order(self):
        cc = CascadeClient({("Subcontracting Order", "SCO-9"):
                                [{"doctype": "Stock Entry", "docname": "STE-SCO-9"}],
                            ("Stock Entry", "STE-SCO-9"): []})
        cc.docs["SCO-9"] = dict(FakeClient().docs["SCO-9"])
        cc.docs["STE-SCO-9"] = {"name": "STE-SCO-9", "docstatus": 1, "company": "Example Corp",
                                "subcontracting_order": "SCO-9", "purpose": "Material Transfer",
                                "posting_date": "2026-06-20",
                                "modified": "2026-06-20 08:00:00.000001"}
        broker, client, store_provider = make_broker(client=cc)
        plan = broker.dispatch("plan_cascade_cancel",
                               {"name": "SCO-9", "pacioli_doctype": "Subcontracting Order"})
        self.assertTrue(plan["ok"], plan)
        self.assertEqual([n["docname"] for n in plan["graph"]], ["STE-SCO-9", "SCO-9"])
        self.assertEqual(plan["graph"][0]["coverage"], "modeled")
        self.assertEqual(plan["graph"][1]["coverage"], "modeled")
        self.assertTrue(any("SCO-9: " in f and "NOT a cascade leaf" in f
                            for f in plan["risk_flags"]), plan["risk_flags"])
        store_provider("prod").mint_marker("sco-casc-token", plan["plan_id"], expires_at=2_000.0)
