class TestSubcontractingInwardOrderGovernedRoundTrip(unittest.TestCase):
    """One full plan->submit, plan->cancel, and amend round trip — the mechanical-wiring proof
    for the fiftieth doctype. The semantic divergences (THE ELEVEN-ROW MUTATOR MAP, THE NEW
    BYPASS CLASS, the always-empty ledger preview, the cascade-not-a-leaf finding) live in their
    own dedicated test classes below, not here. SCIO-1 is a clean Draft; SCIO-9 is the submitted
    fixture for the cancel-direction/amend tests."""

    def test_plan_submit_records_the_doctype_and_the_date(self):
        broker, client, stores = make_broker()
        out = broker.dispatch("plan_submit",
                              {"name": "SCIO-1",
                               "pacioli_doctype": "Subcontracting Inward Order"})
        self.assertTrue(out["ok"], out)
        self.assertEqual(out["doctype"], "Subcontracting Inward Order")
        self.assertEqual(out["posting_date"], "2026-07-01")
        self.assertEqual(client.lock_calls[-1],
                         ("Example Corp", SUBCONTRACTING_INWARD_ORDER, "2026-07-01"))
        stored = stores("prod").get_plan(out["plan_id"])
        self.assertEqual(stored.doctype, "Subcontracting Inward Order")
        self.assertEqual(stored.docname, "SCIO-1")

    def test_full_governed_submit_flow(self):
        broker, client, stores = make_broker()
        plan = broker.dispatch("plan_submit",
                               {"name": "SCIO-1",
                                "pacioli_doctype": "Subcontracting Inward Order"})
        self.assertTrue(plan["ok"], plan)
        token = "scio-raw-token"
        stores("prod").mint_marker(token, plan["plan_id"], expires_at=2_000.0)
        out = broker.dispatch("submit_subcontracting_inward_order",
                              {"name": "SCIO-1", "plan_id": plan["plan_id"], "marker": token})
        self.assertTrue(out["ok"], out)
        self.assertEqual(out["result"]["docstatus"], 1)
        self.assertEqual(out["result"]["doctype"], "Subcontracting Inward Order")
        self.assertEqual(client.submitted, ["SCIO-1"])
        store = stores("prod")
        self.assertEqual(store.marker_state(token), "consumed")
        self.assertEqual(store.orphans(), [])

    def test_plan_submit_refuses_non_draft(self):
        broker, client, _ = make_broker()
        client.docs["SCIO-1"]["docstatus"] = 1
        out = broker.dispatch("plan_submit",
                              {"name": "SCIO-1",
                               "pacioli_doctype": "Subcontracting Inward Order"})
        self.assertFalse(out["ok"])
        self.assertIn("draft", out["reason"].lower())

    def test_full_governed_cancel_flow(self):
        broker, client, stores = make_broker()
        plan = broker.dispatch("plan_cancel",
                               {"name": "SCIO-9",
                                "pacioli_doctype": "Subcontracting Inward Order"})
        self.assertTrue(plan["ok"], plan)
        self.assertEqual(plan["doctype"], "Subcontracting Inward Order")
        token = "scio-cancel-token"
        stores("prod").mint_marker(token, plan["plan_id"], expires_at=2_000.0)
        out = broker.dispatch("cancel_subcontracting_inward_order",
                              {"name": "SCIO-9", "plan_id": plan["plan_id"], "marker": token})
        self.assertTrue(out["ok"], out)
        self.assertEqual(out["result"]["docstatus"], 2)
        self.assertEqual(client.cancelled, ["SCIO-9"])
        self.assertEqual(stores("prod").marker_state(token), "consumed")

    def test_amend_creates_the_draft_with_receipts_and_no_marker(self):
        broker, client, stores = make_broker()
        client.docs["SCIO-9"]["docstatus"] = 2
        out = broker.dispatch("amend_subcontracting_inward_order", {"name": "SCIO-9"})
        self.assertTrue(out["ok"], out)
        self.assertEqual(out["result"]["name"], "SCIO-9-1")
        self.assertEqual(out["result"]["docstatus"], 0)
        self.assertEqual(out["result"]["doctype"], "Subcontracting Inward Order")
        self.assertEqual(client.amended, ["SCIO-9"])
        store = stores("prod")
        receipts = store.receipts()
        self.assertEqual([r.kind for r in receipts], ["intent", "outcome"])
        self.assertEqual(receipts[0].body["doctype"], "Subcontracting Inward Order")
        self.assertEqual(store.orphans(), [])

    def test_amend_refuses_an_uncancelled_source(self):
        broker, client, _ = make_broker()
        out = broker.dispatch("amend_subcontracting_inward_order", {"name": "SCIO-1"})  # a draft
        self.assertFalse(out["ok"])
        self.assertIn("cancelled", out["reason"])


class TestSubcontractingInwardOrderLedgerPreviewAlwaysEmpty(unittest.TestCase):
    """The ledger-preview finding: make_gl_entries genuinely EXISTS in the MRO (7 nodes, ties
    Subcontracting Order for deepest in the CALLABLE category) — calling it raises no
    AttributeError, so this doctype does NOT join the skip tuple. But this voucher's own
    on_submit never writes a Stock Ledger Entry under its own voucher_type — the preview call
    succeeds and returns empty, UNCONDITIONALLY, every time — the POS Invoice false-positive
    shape mirrored (real accounting consequence deferred onto four spawned Stock Entry
    documents), NOT the Sales/Purchase Order honest-empty shape and NOT Asset's per-cause
    conditional emptiness."""

