class TestSubcontractingReceiptGovernedRoundTrip(unittest.TestCase):
    """One full plan->submit, plan->cancel, and amend round trip — the mechanical-wiring proof
    for the fifty-first and FINAL doctype, THE ROOF ROW. The semantic divergences (THE SIXTH
    LEDGER-PREVIEW SHAPE, THE CANCEL BACK-LINK GATE, THE SCO WRITEBACK) live in their own
    dedicated test classes below, not here. SCR-1 is a clean Draft; SCR-9 is the submitted
    fixture for the cancel-direction/amend tests."""

    def test_plan_submit_records_the_doctype_and_the_date(self):
        broker, client, stores = make_broker()
        out = broker.dispatch("plan_submit",
                              {"name": "SCR-1", "pacioli_doctype": "Subcontracting Receipt"})
        self.assertTrue(out["ok"], out)
        self.assertEqual(out["doctype"], "Subcontracting Receipt")
        self.assertEqual(out["posting_date"], "2026-07-01")
        self.assertEqual(client.lock_calls[-1],
                         ("Example Corp", SUBCONTRACTING_RECEIPT, "2026-07-01"))
        stored = stores("prod").get_plan(out["plan_id"])
        self.assertEqual(stored.doctype, "Subcontracting Receipt")
        self.assertEqual(stored.docname, "SCR-1")

    def test_full_governed_submit_flow(self):
        broker, client, stores = make_broker()
        plan = broker.dispatch("plan_submit",
                               {"name": "SCR-1", "pacioli_doctype": "Subcontracting Receipt"})
        self.assertTrue(plan["ok"], plan)
        token = "scr-raw-token"
        stores("prod").mint_marker(token, plan["plan_id"], expires_at=2_000.0)
        out = broker.dispatch("submit_subcontracting_receipt",
                              {"name": "SCR-1", "plan_id": plan["plan_id"], "marker": token})
        self.assertTrue(out["ok"], out)
        self.assertEqual(out["result"]["docstatus"], 1)
        self.assertEqual(out["result"]["doctype"], "Subcontracting Receipt")
        self.assertEqual(client.submitted, ["SCR-1"])
        store = stores("prod")
        self.assertEqual(store.marker_state(token), "consumed")
        self.assertEqual(store.orphans(), [])

    def test_plan_submit_refuses_non_draft(self):
        broker, client, _ = make_broker()
        client.docs["SCR-1"]["docstatus"] = 1
        out = broker.dispatch("plan_submit",
                              {"name": "SCR-1", "pacioli_doctype": "Subcontracting Receipt"})
        self.assertFalse(out["ok"])
        self.assertIn("draft", out["reason"].lower())

    def test_full_governed_cancel_flow(self):
        broker, client, stores = make_broker()
        plan = broker.dispatch("plan_cancel",
                               {"name": "SCR-9", "pacioli_doctype": "Subcontracting Receipt"})
        self.assertTrue(plan["ok"], plan)
        self.assertEqual(plan["doctype"], "Subcontracting Receipt")
        token = "scr-cancel-token"
        stores("prod").mint_marker(token, plan["plan_id"], expires_at=2_000.0)
        out = broker.dispatch("cancel_subcontracting_receipt",
                              {"name": "SCR-9", "plan_id": plan["plan_id"], "marker": token})
        self.assertTrue(out["ok"], out)
        self.assertEqual(out["result"]["docstatus"], 2)
        self.assertEqual(client.cancelled, ["SCR-9"])
        self.assertEqual(stores("prod").marker_state(token), "consumed")

    def test_amend_creates_the_draft_with_receipts_and_no_marker(self):
        broker, client, stores = make_broker()
        client.docs["SCR-9"]["docstatus"] = 2
        out = broker.dispatch("amend_subcontracting_receipt", {"name": "SCR-9"})
        self.assertTrue(out["ok"], out)
        self.assertEqual(out["result"]["name"], "SCR-9-1")
        self.assertEqual(out["result"]["docstatus"], 0)
        self.assertEqual(out["result"]["doctype"], "Subcontracting Receipt")
        self.assertEqual(client.amended, ["SCR-9"])
        store = stores("prod")
        receipts = store.receipts()
        self.assertEqual([r.kind for r in receipts], ["intent", "outcome"])
        self.assertEqual(receipts[0].body["doctype"], "Subcontracting Receipt")
        self.assertEqual(store.orphans(), [])

    def test_amend_refuses_an_uncancelled_source(self):
        broker, client, _ = make_broker()
        out = broker.dispatch("amend_subcontracting_receipt", {"name": "SCR-1"})  # a draft
        self.assertFalse(out["ok"])
        self.assertIn("cancelled", out["reason"])


class TestSubcontractingReceiptLedgerPreviewCallable(unittest.TestCase):
    """THE SIXTH LEDGER-PREVIEW SHAPE — make_gl_entries genuinely EXISTS in the MRO (7 nodes,
    ties Subcontracting Order/Subcontracting Inward Order for deepest in the CALLABLE category),
    but SCR is ABSENT from ERPNext's own native-preview SLE-seeding whitelist and its :847
    None-arithmetic makes the native preview itself a live TypeError on draft previews under
    perpetual inventory. THE SUPERVISOR'S RULING (2026-07-22): the broker never calls a preview
    upstream broke — SCR is the skip tuple's THIRTIETH member, for its own sixth-shape cause
    (CALLABLE-but-structurally-broken, distinct from the AttributeError class), and the gap flag
    discloses the deliberate skip."""

    def test_plan_submit_never_calls_the_native_preview_by_the_supervisors_ruling(self):
        broker, client, _ = make_broker()
        preview_calls = []
        real_preview = client.ledger_preview
        client.ledger_preview = lambda **kw: preview_calls.append(kw) or real_preview(**kw)
        out = broker.dispatch("plan_submit",
                              {"name": "SCR-1", "pacioli_doctype": "Subcontracting Receipt"})
        self.assertTrue(out["ok"], out)
        self.assertEqual(preview_calls, [])
        self.assertEqual(out["projected_gl"], [])

    def test_plan_submit_discloses_the_sle_seeding_whitelist_gap(self):
        broker, client, _ = make_broker()
        out = broker.dispatch("plan_submit",
                              {"name": "SCR-1", "pacioli_doctype": "Subcontracting Receipt"})
        self.assertTrue(out["ok"], out)
        flag = next((f for f in out["risk_flags"]
                    if "DELIBERATELY DID NOT CALL THE NATIVE PREVIEW" in f), None)
        self.assertIsNotNone(flag, out["risk_flags"])
        self.assertIn("SLE-seeding whitelist", flag)
        self.assertIn("Delivery Note/Purchase Receipt/Stock Entry", flag)

    def test_the_gap_flag_is_a_no_op_for_every_other_doctype(self):
        broker, client, _ = make_broker()
        out = broker.dispatch("plan_submit",
                              {"name": "SCIO-1",
                               "pacioli_doctype": "Subcontracting Inward Order"})
        self.assertTrue(out["ok"], out)
        self.assertFalse(any("SLE-SEEDING WHITELIST" in f for f in out["risk_flags"]))

    def test_plan_cancel_needs_no_equivalent_flag(self):
        # plan_cancel's own projected_reversal is a REAL bench read of actually-posted GL Entry
        # rows (get_gl_entries), never routed through the crash-prone in-memory preview path.
        broker, client, _ = make_broker()
        out = broker.dispatch("plan_cancel",
                              {"name": "SCR-9", "pacioli_doctype": "Subcontracting Receipt"})
        self.assertTrue(out["ok"], out)
        self.assertFalse(any("SLE-SEEDING WHITELIST" in f for f in out["risk_flags"]))


