class TestSubcontractingReceiptCascadeNotALeaf(unittest.TestCase):
    """Genuinely NOT a cascade leaf — a full two-checkout grep for '"options": "Subcontracting
    Receipt"' finds exactly 3 hits: Purchase Receipt.subcontracting_receipt (a real, direct,
    external submittable-referencer Link), Subcontracting Receipt.amended_from (self,
    hardcoded-exempt from the framework's own cancel back-link check), and Subcontracting
    Receipt.return_against (self, NOT exempt — see THE CANCEL BACK-LINK GATE's own test class
    below for the return_against angle)."""

    def test_leaf_plan_cancel_is_blocked_by_a_submitted_purchase_receipt(self):
        broker, client, _ = make_broker()
        client.linked = [{"doctype": "Purchase Receipt", "name": "PR-9", "docstatus": 1}]
        out = broker.dispatch("plan_cancel",
                              {"name": "SCR-9", "pacioli_doctype": "Subcontracting Receipt"})
        self.assertFalse(out["ok"])
        self.assertIn("Purchase Receipt PR-9", out["reason"])
        self.assertIn("plan_cascade_cancel", out["reason"])

    def test_plan_cascade_cancel_orders_the_purchase_receipt_before_the_scr(self):
        cc = CascadeClient({("Subcontracting Receipt", "SCR-9"):
                                [{"doctype": "Purchase Receipt", "docname": "PR-SCR-9"}],
                            ("Purchase Receipt", "PR-SCR-9"): []})
        cc.docs["SCR-9"] = dict(FakeClient().docs["SCR-9"])
        cc.docs["PR-SCR-9"] = {"name": "PR-SCR-9", "docstatus": 1,
                               "company": "Example Corp",
                               "subcontracting_receipt": "SCR-9",
                               "posting_date": "2026-06-20",
                               "modified": "2026-06-20 08:00:00.000001"}
        broker, client, store_provider = make_broker(client=cc)
        plan = broker.dispatch("plan_cascade_cancel",
                               {"name": "SCR-9", "pacioli_doctype": "Subcontracting Receipt"})
        self.assertTrue(plan["ok"], plan)
        self.assertEqual([n["docname"] for n in plan["graph"]], ["PR-SCR-9", "SCR-9"])
        self.assertEqual(plan["graph"][0]["coverage"], "modeled")
        self.assertEqual(plan["graph"][1]["coverage"], "modeled")
        self.assertTrue(any("SCR-9: " in f and "cascade leaf" in f
                            for f in plan["risk_flags"]), plan["risk_flags"])
        store_provider("prod").mint_marker("scr-casc-token", plan["plan_id"],
                                           expires_at=2_000.0)
        out = broker.dispatch("cascade_cancel",
                              {"name": "SCR-9", "plan_id": plan["plan_id"],
                               "marker": "scr-casc-token"})
        self.assertTrue(out["ok"], out)
        self.assertEqual([n["docname"] for n in out["cancelled"]], ["PR-SCR-9", "SCR-9"])
        self.assertEqual(len(client.cancelled), 2)


